        function scheduleRefPrefetch() {
            // 0) Define setRefStatus de forma compatível:
            // - Se você já tem setStatus, usa ela (com title/hover)
            // - Se não tiver, cria uma básica
            if (typeof window.setRefStatus !== "function") {
                window.setRefStatus = (typeof window.setStatus === "function")
                    ? window.setStatus
                    : function (txt) {
                        const el = _doc().getElementById("syncStatus");
                        if (!el) return;
                        const t = (txt || "").toString();
                        el.textContent = t;
                        el.title = t;
                    };
            }

            // 1) Preenche o que der do cache (instantâneo)
            try { hydrateSiteDatalistFromCache(); } catch (_) { }
            try { hydrateChoiceDatalistsFromCache(); } catch (_) { }

            // 2) Atualiza em background (rede), sem travar
            const run = () => {
                try {
                    if (typeof ensureDatalistsLoaded !== "function") return;

                    const el = _doc().getElementById("syncStatus");
                    const prev = el ? (el.textContent || "") : "";

                    // Só mostra "Preparando listas…" se não estiver no meio de um sync “de verdade”
                    // (evita sobrescrever "Baixando alterações..." etc.)
                    const isBusySync =
                        prev.startsWith("Baixando") ||
                        prev.startsWith("Atualizando") ||
                        prev.startsWith("Detectadas") ||
                        prev.startsWith("Verificando");

                    if (!isBusySync) {
                        window.setRefStatus("Preparando listas…");
                    }

                    ensureDatalistsLoaded()
                        .catch(console.warn)
                        .finally(() => {
                            // restaura o texto anterior, mas só se a gente foi quem escreveu "Preparando..."
                            const cur = el ? (el.textContent || "") : "";
                            if (!isBusySync && cur === "Preparando listas…") {
                                window.setRefStatus(prev); // volta para o que estava antes
                            }
                        });

                } catch (e) {
                    console.warn(e);
                    try { window.setRefStatus(""); } catch (_) { }
                }
            };

            // requestIdleCallback é o melhor (quando disponível)
            if ("requestIdleCallback" in window) {
                requestIdleCallback(run, { timeout: 3000 });
            } else {
                setTimeout(run, 1200);
            }
        }
