        function scHasActiveFacetFilters() {
            // Heurística: chips ativos OU badge de filtro > 0 OU selects/inputs de faceta preenchidos
            try {
                const chips = _doc().getElementById("scFpChips");
                if (chips && chips.children && chips.children.length > 0) return true;

                const b = _doc().getElementById("filterBadge");
                if (b && !b.classList.contains("d-none")) {
                    const n = parseInt((b.textContent || "0").trim(), 10) || 0;
                    if (n > 0) return true;
                }

                // Extra: se você usa algum estado global de filtros, tente detectar rapidamente
                if (window.scFilterStateV2 && typeof window.scFilterStateV2.countActive === "function") {
                    return (window.scFilterStateV2.countActive() || 0) > 0;
                }
            } catch (e) { }
            return false;
        }

        function scSetMasterItems(items, reason) {
            items = Array.isArray(items) ? items.slice() : [];

            const prev = Array.isArray(window.allItemsGlobal) ? window.allItemsGlobal : [];
            const prevLen = prev.length;
            const nextLen = items.length;

            // ✅ Guard robusto por proporção (base grande + filtros ativos)
            try {
                const hasFilters = scHasActiveFacetFilters();
                const bigPrev = prevLen >= 2000;
                if (bigPrev && hasFilters && nextLen > 0 && nextLen < (prevLen * 0.70)) {
                    console.warn(`[scSetMasterItems] BLOQUEADO overwrite do MASTER (${prevLen} -> ${nextLen}) por '${reason}'. Mantendo MASTER atual.`);
                    return prev.slice();
                }
                if (bigPrev && hasFilters && nextLen === 0) {
                    console.warn(`[scSetMasterItems] BLOQUEADO overwrite do MASTER (${prevLen} -> 0) por '${reason}'. Mantendo MASTER atual.`);
                    return prev.slice();
                }
            } catch (e) { }

            // ✅ Guard: base > 1000 itens encolhendo para < 500 com filtros
            try {
                if (prevLen > 1000 && nextLen > 0 && nextLen < 500 && scHasActiveFacetFilters()) {
                    console.warn(`[scSetMasterItems] Bloqueado overwrite do MASTER (${prevLen} -> ${nextLen}) por '${reason}'. Mantendo MASTER atual.`);
                    return prev.slice();
                }
            } catch (e) { }

            try { normalizeItemsArray(items); } catch (eN) { }

            window.allItemsGlobal = items.slice();
            try { allItemsGlobal = window.allItemsGlobal; } catch (e) { }
            return window.allItemsGlobal.slice();
        }

