        // Função para formatar o nome do usuário (primeiro nome + último sobrenome)
        function formatUserName(fullName) {
            if (!fullName) return "";
            const parts = fullName.trim().split(/\s+/);
            if (parts.length === 0) return "";
            if (parts.length === 1) return parts[0];
            return parts[0] + " " + parts[parts.length - 1];
        }

        // Função para obter o usuário logado
        async function getUsuarioLogado() {
            try {
                const response = await fetch("/_api/web/currentuser", {
                    method: "GET",
                    headers: { "Accept": "application/json;odata=verbose" }
                });
                if (!response.ok) throw new Error("Erro ao buscar usuário logado: " + response.statusText);
                const data = await response.json();
                // Retorna um objeto com os dados relevantes
                return {
                    title: data.d.Title,
                    email: data.d.Email
                };
            } catch (error) {
                console.error("Erro no getUsuarioLogado:", error);
                return null;
            }
        }


