        function setWelcomeAvatar(email, displayName) {
            var slots = ensureWelcomeAvatarSlots();
            var img = slots.img, ini = slots.ini;
            if (!img || !ini) return;

            // 1) Mostrar iniciais imediatamente (placebo visual)
            ini.textContent = computeInitials(displayName);
            ini.classList.remove('d-none');
            img.classList.add('d-none');

            // 2) Candidatos de URL (email e login claims)
            var ts = Date.now();
            var candidates = [];
            if (email) candidates.push(getUserPhotoUrl(email, 'M') + '&ts=' + ts);
            if (window._spPageContextInfo?.userLoginName) {
                candidates.push(getUserPhotoUrl(_spPageContextInfo.userLoginName, 'M') + '&ts=' + ts);
            }

            // 3) Pré-carrega fora do DOM para driblar lazy/defer
            var i = 0;
            (function tryNext() {
                if (i >= candidates.length) return; // fica com iniciais
                var url = candidates[i++];
                var probe = new Image();
                probe.decoding = 'async';
                // probe.referrerPolicy = 'no-referrer'; // use se seu tenant exigir
                probe.onload = function () {
                    img.src = url;              // troca a real
                    img.classList.remove('d-none');
                    ini.classList.add('d-none');
                };
                probe.onerror = tryNext;      // tenta próxima
                probe.src = url;
            })();
        }


