            // aplica permissão do botão
            window.applyBulkV2Perm?.();


            // ✅ Se já tem cache: NÃO faz carga pesada agora
            if (cache && cache.hasCache) {
                // garante que variáveis globais apontem para os dados do cache
                if (Array.isArray(cache.items) && cache.items.length) {
                    scSetMasterItems(cache.items || [], "initializeDashboard/cache");

                    // (opcional mas recomendado p/ consistência do delta sync)
                    window.currentItemsList = cache.items;
                }

                // reprocessa os derivados usando cache (rápido)
                window.scDashScope = loadScope();
                updateScopeCardUI();
                refreshCardsWithScope();

                // ✅ Fecha loader
                try { hideLoadingOverlay(); } catch (e) { }

                // ✅ NOVO: Prefetch dos datalists em background (para Novo Registro não demorar)
                try { scheduleRefPrefetch(); } catch (e) { }
                // Suprimentos (Ricoh)
                try { scSupplies.init(); } catch (e) { }

                return;
            }

            // ---------------------------------------------------------
            // ⛔ Sem cache: primeira vez precisa carregar tudo (normal)
