        /** SharePoint OData verbose: "\/Date(1234567890123)\/" — new Date() falha no Chrome; aceita também pt-BR */
        function parseSharePointDate(val) {
            if (val == null || val === "") return null;
            if (typeof val === "number" && isFinite(val)) {
                var dn = new Date(val);
                return isNaN(dn.getTime()) ? null : dn;
            }
            if (val instanceof Date) return isNaN(val.getTime()) ? null : val;
            var s = String(val).trim();
            if (!s || s === "undefined") return null;
            var m = s.match(/\/Date\((-?\d+)\)\//);
            if (m) {
                var d = new Date(parseInt(m[1], 10));
                return isNaN(d.getTime()) ? null : d;
            }
            // dd/mm/aaaa, hh:mm:ss ou dd/mm/aaaa hh:mm:ss (regional BR no SharePoint)
            var br = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})(?:\s*,\s*|\s+)(\d{1,2}):(\d{1,2}):(\d{1,2})$/);
            if (br) {
                var day = parseInt(br[1], 10), month = parseInt(br[2], 10) - 1, year = parseInt(br[3], 10);
                var hh = parseInt(br[4], 10), mi = parseInt(br[5], 10), se = parseInt(br[6], 10);
                var dbr = new Date(year, month, day, hh, mi, se);
                return isNaN(dbr.getTime()) ? null : dbr;
            }
            var d2 = new Date(s);
            return isNaN(d2.getTime()) ? null : d2;
        }
