        // Heurística: só faz fallback quando parece serial/asset (evita ruído/performance)
        function scIsLikelyIdentifierQuery(q) {
            q = String(q || "").trim();
            if (!q) return false;
            if (q.length >= 4 && /\d/.test(q)) return true;
            if (/^[A-Za-z0-9-_.]{6,}$/.test(q)) return true;
            if (/^\d{4,}$/.test(q)) return true;
            return false;
        }

