        function escapeHtml(str) {
            return String(str || "").replace(/[&<>"']/g, m => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[m]));
        }

        // Fim Helpers de busca/fallback

        /***** Busca Global (acento-insensível + todas colunas, incluindo AssignedTo) + UI melhorada *****/
        (function () {
            var input = _doc().getElementById("globalSearchInput");
            if (!input) return;

            var debounceTimer, DEBOUNCE = 400;

            // UI extras
            var chipsBar = _doc().getElementById("activeFiltersBar");
            var badge = _doc().getElementById("filterBadge");
            var btnClearSearch = _doc().getElementById("btnClearSearch");

            // normaliza: minúsculas e sem acentos
            function norm(s) {
                if (s == null) return "";
                return String(s)
                    .toLowerCase()
                    .normalize("NFD").replace(/[\u0300-\u036f]/g, ""); // remove acentos
            }

            // converte qualquer valor em texto pesquisável
            function toText(v) {
                if (v == null) return "";
                if (Array.isArray(v)) return v.map(toText).join(" ");
                if (typeof v === "object") {
                    var parts = [];
                    if ("Title" in v) parts.push(v.Title);
                    if ("Name" in v) parts.push(v.Name);
                    if ("EMail" in v) parts.push(v.EMail);
                    if ("Email" in v) parts.push(v.Email);
                    try {
                        Object.values(v).forEach(function (x) {
                            if (x == null) return;
                            var t = typeof x;
                            if (t === "string" || t === "number" || t === "boolean") parts.push(String(x));
                        });
                    } catch (_) { }
                    return parts.join(" ");
                }
                return String(v);
            }

            // monta o "haystack" (todas as colunas relevantes + extras)
            function haystack(item) {
                var parts = [];

                // principais
                parts.push(
                    item.Id, item.Title, item.Company, item.Category,
                    item.Fabricante, item.Vendor, item.Modelo, item.Model,
                    item.ITAssetBunge, item.Status, item.Prateleira, item.Hostname, item.Comments
                );

                // Site (objeto ou string)
                if (item.Site) parts.push(toText(item.Site));

                // ✅ País derivado: Site.Id -> allSites[Id].siteCountry
                // try {
                //   var country = (typeof getCountryForItem === "function") ? countryLabel(getCountryForItem(item)) : "";
                //   if (country) parts.push(country);
                // } catch (_) { }

                try {
                    var ck = (typeof getCountryForItem === "function") ? getCountryForItem(item) : "";
                    if (ck) {
                        parts.push(ck);                 // canônico (brazil)
                        parts.push(countryLabel(ck));   // label (Brasil/Brazil)
                    }
                } catch (_) { }
                // Pessoas
                function pushPeople(p) {
                    if (!p) return;
                    if (Array.isArray(p)) { p.forEach(pushPeople); return; }
                    if (p.results && Array.isArray(p.results)) { p.results.forEach(pushPeople); return; }
                    parts.push(p.Title, p.Name, p.EMail || p.Email);
                }
                pushPeople(item.AssignedTo);
                pushPeople(item.Author);
                pushPeople(item.Editor);

                // Datas (Created)
                if (item.Created) {
                    try {
                        var d = new Date(item.Created);
                        var dd = ("0" + d.getDate()).slice(-2);
                        var mm = ("0" + (d.getMonth() + 1)).slice(-2);
                        var yyyy = d.getFullYear();
                        parts.push(dd + "/" + mm + "/" + yyyy, yyyy + "-" + mm + "-" + dd);
                    } catch (_) { }
                }

                // Extras: agrega outros campos primitivos
                try {
                    Object.keys(item).forEach(function (k) {
                        var v = item[k];
                        if (v == null) return;
                        var t = typeof v;
                        if (t === "string" || t === "number" || t === "boolean") parts.push(v);
                    });
                } catch (_) { }

                return norm(parts.map(toText).join(" | "));
            }

            // Base SEMPRE da fonte completa (evita “embolar” buscas sucessivas)
            // ⚠️ NOVO: se estiver em modo global temporário, IGNORA ESCOPO
            function getBase() {
                var base = Array.isArray(window.allItemsGlobal) ? window.allItemsGlobal.slice() :
                    (Array.isArray(window.currentItemsList) ? window.currentItemsList.slice() : []);

                // ✅ Se "modo global temporário" estiver ativo, NÃO aplica escopo
                try {
                    if (window.__scGlobalSearchMode && window.__scGlobalSearchMode.active === true) {
                        return base;
                    }
                } catch (e) { }

                // normal: aplica escopo do dashboard/cards
                try { if (typeof applyDashScope === 'function') base = applyDashScope(base); } catch (e) { }
                return base;
            }

            // ====== NOVO: estado de filtros (para UI) ======
            function getExactFiltersStateRaw() {
                var st = {
                    q: (_doc().getElementById("globalSearchInput").value || "").trim(),
                    company: (_doc().getElementById("filterCompanyValue") || {}).value || "",
                    category: (_doc().getElementById("filterCategoryValue") || {}).value || "",
                    vendor: (_doc().getElementById("filterVendorValue") || {}).value || "",
                    status: (_doc().getElementById("filterStatusValue") || {}).value || "",
                    site: (_doc().getElementById("filterSiteValue") || {}).value || ""
                };
                return st;
            }
            function countActive(st) {
                var n = 0;
                if (st.q) n++;
                if (st.company) n++;
                if (st.category) n++;
                if (st.vendor) n++;
                if (st.status) n++;
                if (st.site) n++;
                return n;
            }
            function triggerRecalc() {
                input.dispatchEvent(new Event("input"));
            }

            // Renderiza chips + badge
            function renderFiltersUI() {
                if (!chipsBar) return;
                var st = getExactFiltersStateRaw();
                chipsBar.innerHTML = "";

                function addChip(label, val, onX) {
                    var span = _doc().createElement("span");
                    span.className = "chip";
                    span.innerHTML = "<strong>" + label + "</strong>: " + val + ' <i class="bi bi-x"></i>';
                    span.querySelector("i").onclick = function () { onX(); triggerRecalc(); };
                    chipsBar.appendChild(span);
                }

                if (st.q) addChip((typeof t === "function" ? t("chipSearch") : "Busca"), st.q, function () {
                    var el = _doc().getElementById("globalSearchInput"); if (el) el.value = "";
                });
                if (st.company) addChip((typeof t === "function" ? t("chipCompany") : "Empresa"), st.company, function () {
                    var el = _doc().getElementById("filterCompanyValue"); if (el) el.value = "";
                    localStorage.removeItem("searchPreferences");
                });
                if (st.category) addChip((typeof t === "function" ? t("chipCategory") : "Categoria"), st.category, function () {
                    var el = _doc().getElementById("filterCategoryValue"); if (el) el.value = "";
                    localStorage.removeItem("searchPreferences");
                });
                if (st.vendor) addChip((typeof t === "function" ? t("chipVendor") : "Fabricante"), st.vendor, function () {
                    var el = _doc().getElementById("filterVendorValue"); if (el) el.value = "";
                    localStorage.removeItem("searchPreferences");
                });
                if (st.status) addChip((typeof t === "function" ? t("chipStatus") : "Status"), st.status, function () {
                    var el = _doc().getElementById("filterStatusValue"); if (el) el.value = "";
                    localStorage.removeItem("searchPreferences");
                });
                if (st.site) addChip((typeof t === "function" ? t("chipSite") : "Site"), st.site, function () {
                    var el = _doc().getElementById("filterSiteValue"); if (el) el.value = "";
                    localStorage.removeItem("searchPreferences");
                });

                var n = countActive(st);
                if (n) {
                    var clearAll = _doc().createElement("button");
                    clearAll.className = "btn btn-sm btn-link ms-1";
                    clearAll.textContent = (typeof t === "function" ? t("clearAll") : "Limpar tudo");
                    clearAll.onclick = function () {
                        var ids = ["globalSearchInput", "filterCompanyValue", "filterCategoryValue", "filterVendorValue", "filterStatusValue", "filterSiteValue"];
                        ids.forEach(function (id) { var el = _doc().getElementById(id); if (el) el.value = ""; });
                        localStorage.removeItem("searchPreferences");
                        triggerRecalc();
                    };
                    chipsBar.appendChild(clearAll);
                }


                // Badge no funil (agora controlado pelo estado único)
                try { if (window.scUpdateFilterBadge) window.scUpdateFilterBadge(); } catch (_) { }
            }

            function runGlobalSearchPipeline(q) {
                var gm = window.__scGlobalSearchMode || { active: false, queryNorm: "", results: [] };
                var isGlobalTemp = !!(gm.active && gm.queryNorm && gm.queryNorm === q);
                var base = getBase();
                var results;

                if (!q) {
                    results = base;
                } else {
                    var tokens = q.split(/\s+/).filter(Boolean);
                    results = base.filter(function (it) {
                        var h = haystack(it);
                        for (var i = 0; i < tokens.length; i++) {
                            if (h.indexOf(tokens[i]) === -1) return false;
                        }
                        return true;
                    });
                }

                if (!isGlobalTemp && typeof applyFiltersFromState === "function") {
                    results = applyFiltersFromState(results) || results;
                }

                try {
                    scHideGlobalSearchBanner();
                    var queryNorm = String(q || "").trim();
                    if (!isGlobalTemp && queryNorm && Array.isArray(results) && results.length === 0 && scIsLikelyIdentifierQuery(queryNorm)) {
                        var master = Array.isArray(window.allItemsGlobal) ? window.allItemsGlobal.slice() : [];
                        var tokens2 = queryNorm.split(/\s+/).filter(Boolean);
                        var globalPure = master.filter(function (it) {
                            var h = haystack(it);
                            for (var i = 0; i < tokens2.length; i++) {
                                if (h.indexOf(tokens2[i]) === -1) return false;
                            }
                            return true;
                        });
                        if (Array.isArray(globalPure) && globalPure.length > 0) {
                            window.__scGlobalSearchMode = window.__scGlobalSearchMode || { active: false, queryNorm: "", results: [] };
                            window.__scGlobalSearchMode.results = globalPure;
                            scShowGlobalSearchBanner({
                                queryNorm: queryNorm,
                                globalCount: globalPure.length,
                                globalResults: globalPure
                            });
                        }
                    }
                } catch (e) { console.warn("fallback:", e); }

                if (typeof updateLatestItems === "function") {
                    updateLatestItems(results);
                }

                var title =
                    q
                        ? (typeof t === "function"
                            ? t("searchResult", { count: results.length })
                            : ("Resultado da Pesquisa (" + results.length + ")"))
                        : (typeof t === "function"
                            ? t("latestAdded")
                            : "Últimos Ativos Adicionados");

                scSetLatestHeaderTitle(
                    isGlobalTemp ? ("Resultado da Pesquisa (base toda) (" + results.length + ")") : title,
                    "", ""
                );

                if (isGlobalTemp) {
                    scShowGlobalModePill();
                } else {
                    scHideGlobalModePill();
                }

                if (q && typeof scrollToResults === "function") {
                    setTimeout(scrollToResults, 200);
                }

                try { if (window.scQuickFiltersRefresh) window.scQuickFiltersRefresh(); } catch (e) { }
            }

            // Handler da busca
            input.addEventListener("input", function () {
                clearTimeout(debounceTimer);
                var q = norm(this.value.trim());
                debounceTimer = setTimeout(function () {
                    runGlobalSearchPipeline(q);
                }, DEBOUNCE);
            });


            // Botão × e tecla Esc limpam a busca
            if (btnClearSearch) btnClearSearch.onclick = function () {
                input.value = "";
                clearTimeout(debounceTimer);
                runGlobalSearchPipeline(norm(""));
            };

            _doc().addEventListener("keydown", function (e) {
                if (e.key !== "Escape") return;

                // se o painel estiver aberto, ESC fecha o painel primeiro
                if (typeof window.scFilterPanelIsOpen === "function" && window.scFilterPanelIsOpen()) {
                    e.preventDefault();
                    if (typeof window.scFilterPanelClose === "function") window.scFilterPanelClose();
                    return;
                }

                try { if (typeof scExitGlobalTempMode === "function") scExitGlobalTempMode(false); } catch (_) { }

                e.preventDefault();
                input.value = "";
                clearTimeout(debounceTimer);
                runGlobalSearchPipeline(norm(""));
            });



            // Primeira render (painel)
            try { if (window.scFpRefresh) window.scFpRefresh(); } catch (e) { }

        })();




        /***** Filtro Avançado (Modal) *****/
