        // === Regra: AssignedTo só quando In Use + categorias específicas ===
        var NEEDS_ASSIGNEE_KEYS_RAW = {
            "notebook": 1,
            "desktop": 1,
            "mobile": 1,
            "monitor": 1,
            "tablet": 1,
            "telephony (ramal)": 1
        };

        // Normaliza as chaves para bater com normKey(category)
        var NEEDS_ASSIGNEE_KEYS = (function () {
            var out = {};
            for (var k in NEEDS_ASSIGNEE_KEYS_RAW) {
                if (Object.prototype.hasOwnProperty.call(NEEDS_ASSIGNEE_KEYS_RAW, k)) {
                    out[normKey(k)] = 1;
                }
            }
            return out;
        })();
        function normKey(s) {
            try { if (typeof window.canonicalChoice === 'function') s = window.canonicalChoice('Category', s); } catch (_) { }
            return String(s || '')
                .toLowerCase()
                .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
                .replace(/[()\-_]/g, '')
                .replace(/\s+/g, '')
                .trim();
        }
        function needsAssignee(status, category) {
            if (!isInUseLocal(status)) return false;
            return !!NEEDS_ASSIGNEE_KEYS[normKey(category)];
        }

        /***** Abertura do Modal de Item (novo/editar) *****/
        async function openItemModal(itemId = null) {

            // ==============================
            // Config: quais datalists travar
            // ==============================
            const STRICT_LISTS = new Set([
                "company-list",
                "category-list",
                "vendor-list",
                "status-list",
                "site-list",
                "prateleira-list"
            ]);

            const LIST_LABEL = {
                "company-list": "Empresa",
                "category-list": "Categoria",
                "vendor-list": "Fornecedor",
                "status-list": "Status",
                "site-list": "Site",
                "prateleira-list": "Prateleira"
            };

            // ==============================
            // Helpers locais: normalização
            // ==============================
            function _norm(v) {
                return (v || "")
                    .toString()
                    .trim()
                    .toLowerCase()
                    .normalize("NFD")
                    .replace(/[\u0300-\u036f]/g, "");
            }

            function _getAllowedSet(datalistId) {
                const dl = _doc().getElementById(datalistId);
                if (!dl) return null;
                const opts = Array.from(dl.querySelectorAll("option"));
                if (!opts.length) return null;
                const set = new Set();
                for (const o of opts) {
                    if (o.value) set.add(_norm(o.value));
                    if (o.dataset && o.dataset.canonical) set.add(_norm(o.dataset.canonical));
                }
                return set;
            }

            function _ensureOptionExists(datalistId, value) {
                const dl = _doc().getElementById(datalistId);
                if (!dl) return;

                const v = (value || "").trim();
                if (!v) return;

                const exists = Array.from(dl.querySelectorAll("option"))
                    .some(o => _norm(o.value) === _norm(v) || _norm(o.dataset?.canonical) === _norm(v));

                if (!exists) {
                    const opt = _doc().createElement("option");
                    opt.value = v;
                    opt.dataset.temp = "1";
                    dl.appendChild(opt);
                }
            }

            // ==============================
            // STRICT: trava digitação fora do datalist
            // - Soft enquanto digita (só feedback visual)
            // - Hard no blur/change/submit
            // - EDIT: inválido/vazio => RESTAURA último válido
            // - NEW: inválido => LIMPA
            // - Definitivo: handlers não "grudam" no modo errado (mode vem do dataset.strictMode)
            // ==============================
            function _wireStrictDatalists(mode) {
                const form = _doc().getElementById("itemForm");
                if (!form) return;

                // Backup para achar o datalist real (caso list="sc-none-list" e originalList falhe)
                const ID_TO_LIST = {
                    selectCompany: "company-list",
                    selectCategory: "category-list",
                    selectVendor: "vendor-list",
                    selectStatus: "status-list",
                    inputSite: "site-list",
                    selectPrateleira: "prateleira-list"
                };

                function resolveListId(input) {
                    // 1) preferencial: lista real guardada quando desativa o nativo
                    let dlId = input.dataset.originalList;
                    if (dlId) return dlId;

                    // 2) fallback: atributo list se não for sc-none-list
                    dlId = input.getAttribute("list");
                    if (dlId && dlId !== "sc-none-list") return dlId;

                    // 3) fallback final: mapa por id do input
                    return ID_TO_LIST[input.id] || null;
                }

                // Cache normalizado para soft-check rápido (listas grandes)
                function getNormOptionsCache(datalistId) {
                    const dl = _doc().getElementById(datalistId);
                    if (!dl) return null;

                    const opts = Array.from(dl.querySelectorAll("option"));
                    const stamp = String(opts.length);

                    if (dl.dataset.scNormStamp === stamp && dl._scNormCache) return dl._scNormCache;

                    const arr = opts
                        .map(o => (o.dataset && o.dataset.canonical) ? o.dataset.canonical : o.value)
                        .filter(Boolean)
                        .map(v => _norm(v));

                    dl._scNormCache = arr;
                    dl.dataset.scNormStamp = stamp;
                    return arr;
                }

                function toastOnce(input, msg, level) {
                    const now = Date.now();
                    const last = Number(input.dataset.strictToastAt || "0");
                    if (now - last > 1500) {
                        input.dataset.strictToastAt = String(now);
                        try { typeof showToast === "function" && showToast(msg, level || "warning"); } catch (_) { }
                    }
                }

                const inputs = Array.from(form.querySelectorAll("input[list]"));

                inputs.forEach(input => {
                    const dlId = resolveListId(input);
                    if (!dlId) return;
                    if (!STRICT_LISTS.has(dlId)) return;

                    const label =
                        input.getAttribute("data-label") ||
                        LIST_LABEL[dlId] ||
                        input.getAttribute("aria-label") ||
                        input.placeholder ||
                        input.id ||
                        "Campo";

                    // ✅ CRÍTICO: modo sempre atualizado (não fica preso no primeiro bind)
                    input.dataset.strictMode = mode;

                    // ✅ Atualiza o último válido sempre que abrir o modal (principalmente no EDIT)
                    const cur = (input.value || "").trim();
                    input.dataset.strictLastGood = cur;
                    if (cur) input.dataset.strictLastGoodNonEmpty = cur;

                    // Função HARD que lê o modo atual via dataset (não via closure)
                    const validateHard = () => {
                        const modeNow = input.dataset.strictMode || "new";
                        const realList = resolveListId(input) || dlId;

                        input.classList.remove("sc-soft-invalid");

                        const raw = (input.value || "").trim();

                        // ✅ EDIT: vazio não pode -> restaura o último não vazio
                        // Campos que podem ficar vazios no EDIT (mesmo com STRICT)
                        const ALLOW_EMPTY_IN_EDIT = new Set(["selectPrateleira"]);

                        // ✅ EDIT: vazio não pode -> restaura, EXCETO campos permitidos
                        if (modeNow === "edit" && !raw && !ALLOW_EMPTY_IN_EDIT.has(input.id)) {
                            const back = (input.dataset.strictLastGoodNonEmpty || "").trim();
                            input.value = back;
                            try { input.dispatchEvent(new Event("input", { bubbles: true })); } catch (_) { }
                            try { input.dispatchEvent(new Event("change", { bubbles: true })); } catch (_) { }
                            return false;
                        }

                        // NEW: vazio pode passar (required do HTML e submit cuidam)
                        if (!raw) return true;

                        const allowed = _getAllowedSet(realList);

                        // Se lista não carregou:
                        // EDIT -> não permite troca (restaura), NEW -> não bloqueia agora, submit pega depois
                        if (!allowed) {
                            if (modeNow === "edit") {
                                toastOnce(input, `Listas ainda carregando em "${label}". Aguarde.`, "info");
                                const back = (input.dataset.strictLastGoodNonEmpty || "").trim();
                                input.value = back;
                                try { input.dispatchEvent(new Event("input", { bubbles: true })); } catch (_) { }
                                try { input.dispatchEvent(new Event("change", { bubbles: true })); } catch (_) { }
                                return false;
                            }
                            input.classList.add("sc-soft-invalid");
                            return true;
                        }

                        const ok = allowed.has(_norm(raw));
                        if (ok) {
                            // atualiza último válido
                            input.dataset.strictLastGood = raw;
                            input.dataset.strictLastGoodNonEmpty = raw;
                            return true;
                        }

                        toastOnce(input, `Valor inválido em "${label}". Selecione um item da lista.`, "warning");

                        if (modeNow === "edit") {
                            // ✅ EDIT: restaura último válido NÃO vazio
                            const back = (input.dataset.strictLastGoodNonEmpty || "").trim();
                            input.value = back;
                            try { input.dispatchEvent(new Event("input", { bubbles: true })); } catch (_) { }
                            try { input.dispatchEvent(new Event("change", { bubbles: true })); } catch (_) { }
                            return false;
                        } else {
                            // ✅ NEW: limpa
                            input.value = "";
                            try { input.dispatchEvent(new Event("input", { bubbles: true })); } catch (_) { }
                            return false;
                        }
                    };

                    // Soft enquanto digita (só feedback visual)
                    const validateSoft = () => {
                        const realList = resolveListId(input) || dlId;
                        const raw = (input.value || "").trim();

                        if (!raw) {
                            input.classList.remove("sc-soft-invalid");
                            return true;
                        }

                        const allowed = _getAllowedSet(realList);
                        if (!allowed) return true;

                        const n = _norm(raw);
                        if (allowed.has(n)) {
                            input.classList.remove("sc-soft-invalid");
                            return true;
                        }

                        const arr = getNormOptionsCache(realList) || [];
                        const hasPossible = arr.some(v => v.includes(n));
                        input.classList.toggle("sc-soft-invalid", !hasPossible);
                        return hasPossible;
                    };

                    // ✅ CRÍTICO: sempre atualiza o _strictValidate (mesmo se já wired)
                    input._strictValidate = validateHard;

                    // Se já wired, não reanexa listeners (mas já atualizamos modo + _strictValidate)
                    if (input.dataset.strictWired === "1") return;
                    input.dataset.strictWired = "1";

                    input.addEventListener("input", validateSoft, { passive: true });
                    input.addEventListener("paste", () => setTimeout(validateSoft, 0));
                    input.addEventListener("blur", validateHard);
                    input.addEventListener("change", validateHard);
                });

                // Submit hard
                if (!form.dataset.strictSubmitWired) {
                    form.dataset.strictSubmitWired = "1";
                    form.addEventListener("submit", function (e) {
                        const strictInputs = Array.from(form.querySelectorAll("input[list]"))
                            .filter(inp => {
                                const real = resolveListId(inp) || "";
                                return STRICT_LISTS.has(real);
                            });

                        let ok = true;
                        let firstBad = null;

                        for (const inp of strictInputs) {
                            if (typeof inp._strictValidate === "function") {
                                const r = inp._strictValidate();
                                if (!r) { ok = false; if (!firstBad) firstBad = inp; }
                            }
                        }

                        if (!ok) {
                            e.preventDefault();
                            e.stopPropagation();
                            try { firstBad && firstBad.focus(); } catch (_) { }
                            try { typeof showToast === "function" && showToast("Corrija os campos inválidos antes de salvar.", "danger"); } catch (_) { }
                        }
                    });
                }
            }

            // ==============================
            // EDIT: desativar dropdown nativo do datalist
            // ==============================
            function _ensureEmptyDatalistOnce() {
                if (_doc().getElementById("sc-none-list")) return;
                const dl = _doc().createElement("datalist");
                dl.id = "sc-none-list";
                _doc().body.appendChild(dl);
            }

            function _disableNativeDatalistDropdown(formEl) {
                if (!formEl) return;
                _ensureEmptyDatalistOnce();

                const inputs = Array.from(formEl.querySelectorAll("input[list]"));
                inputs.forEach(inp => {
                    const currentList = inp.getAttribute("list");
                    const realList = inp.dataset.originalList || currentList;
                    if (!realList) return;
                    if (!STRICT_LISTS.has(realList)) return;

                    if (!inp.dataset.originalList && currentList && currentList !== "sc-none-list") {
                        inp.dataset.originalList = currentList;
                    }
                    if (currentList !== "sc-none-list") {
                        inp.setAttribute("list", "sc-none-list");
                    }
                    inp.setAttribute("autocomplete", "off");
                });
            }

            function _restoreNativeDatalistDropdown(formEl) {
                if (!formEl) return;
                const inputs = Array.from(formEl.querySelectorAll("input[list]"));
                inputs.forEach(inp => {
                    const orig = inp.dataset.originalList;
                    if (!orig) return;
                    if (!STRICT_LISTS.has(orig)) return;
                    inp.setAttribute("list", orig);
                    delete inp.dataset.originalList;
                });
            }

            // ==============================
            // EDIT: dropdown custom único
            // ==============================
            function _ensureEditDlCssOnce() {
                if (_doc().getElementById("scEditDlCss")) return;
                const st = _doc().createElement("style");
                st.id = "scEditDlCss";
                st.textContent = `
      .sc-dl-pop{position:absolute;z-index:20000;background:var(--bs-body-bg,#111);border:1px solid rgba(255,255,255,.12);border-radius:10px;box-shadow:0 10px 30px rgba(0,0,0,.45);max-height:260px;overflow:auto;min-width:220px;padding:6px}
      .sc-dl-item{padding:8px 10px;border-radius:8px;cursor:pointer;user-select:none;color:var(--bs-body-color,#fff)}
      .sc-dl-item:hover{background:rgba(13,110,253,.18);outline:1px solid rgba(13,110,253,.35)}
      .sc-dl-empty{padding:8px 10px;opacity:.7;font-size:.9rem}
      `;
                _doc().head.appendChild(st);
            }

            function _getListOptions(listId) {
                const dl = _doc().getElementById(listId);
                if (!dl) return [];

                const LIST_TO_FIELD = {
                    'status-list': 'Status',
                    'category-list': 'Category',
                    'vendor-list': 'Vendor',
                    'company-list': 'Company',
                    'prateleira-list': 'Prateleira'
                };
                const field = LIST_TO_FIELD[String(listId || '').toLowerCase()] || null;

                return Array.from(dl.querySelectorAll('option'))
                    .map(o => {
                        const canonical = (o.dataset && o.dataset.canonical) ? o.dataset.canonical : o.value;
                        if (field && typeof window.displayChoice === 'function') {
                            try { return window.displayChoice(field, canonical); } catch (_) { return canonical; }
                        }
                        return canonical;
                    })
                    .filter(Boolean);
            }


            // Singleton do popup
            window.__scEditDl = window.__scEditDl || {
                pop: null,
                currentInput: null,
                currentListId: null,
                onDocDown: null,
                onScroll: null,
                onResize: null
            };

            function _scEditDlDetachGlobals() {
                const st = window.__scEditDl;
                try {
                    if (st.onDocDown) _doc().removeEventListener("mousedown", st.onDocDown, true);
                    if (st.onScroll) window.removeEventListener("scroll", st.onScroll, true);
                    if (st.onResize) window.removeEventListener("resize", st.onResize, true);
                } catch (_) { }
                st.onDocDown = st.onScroll = st.onResize = null;
            }

            function _scEditDlClose() {
                const st = window.__scEditDl;
                _scEditDlDetachGlobals();
                if (st.pop) { st.pop.remove(); st.pop = null; }
                st.currentInput = null;
                st.currentListId = null;
            }

            function _scEditDlPlace(inp) {
                const st = window.__scEditDl;
                if (!st.pop) return;
                const r = inp.getBoundingClientRect();
                st.pop.style.top = (r.bottom + window.scrollY + 4) + "px";
                st.pop.style.left = (r.left + window.scrollX) + "px";
                st.pop.style.minWidth = Math.max(220, r.width) + "px";
            }

            function _wireEditDropdown(formEl, STRICT_LISTS, _norm, _getListOptions) {
                if (!formEl) return;

                if (formEl.dataset.editDlWired === "1") return;
                formEl.dataset.editDlWired = "1";

                function render(items, filterText) {
                    const st = window.__scEditDl;
                    st.pop.innerHTML = "";

                    if (!items.length) {
                        const empty = _doc().createElement("div");
                        empty.className = "sc-dl-empty";
                        empty.textContent = filterText ? "Nenhum resultado" : "Sem opções";
                        st.pop.appendChild(empty);
                        return;
                    }

                    items.slice(0, 120).forEach(val => {
                        const div = _doc().createElement("div");
                        div.className = "sc-dl-item";
                        div.textContent = val;

                        div.addEventListener("mousedown", (e) => {
                            e.preventDefault();
                            const st = window.__scEditDl;
                            if (!st.currentInput) return;

                            st.currentInput.value = val;
                            try { st.currentInput.dispatchEvent(new Event("input", { bubbles: true })); } catch (_) { }
                            try { st.currentInput.dispatchEvent(new Event("change", { bubbles: true })); } catch (_) { }
                            _scEditDlClose();
                        });

                        st.pop.appendChild(div);
                    });
                }

                function openPop(inp, listId) {
                    const st = window.__scEditDl;

                    if (st.pop && st.currentInput === inp && st.currentListId === listId) {
                        _scEditDlPlace(inp);
                        return;
                    }

                    _scEditDlClose();
                    st.currentInput = inp;
                    st.currentListId = listId;

                    st.pop = _doc().createElement("div");
                    st.pop.className = "sc-dl-pop";
                    _doc().body.appendChild(st.pop);

                    _scEditDlPlace(inp);
                    render(_getListOptions(listId), "");

                    if (inp._scEditDlOnInput) inp.removeEventListener("input", inp._scEditDlOnInput);
                    const onInput = () => {
                        const all = _getListOptions(listId);
                        const f = _norm(inp.value);
                        const filtered = f ? all.filter(x => _norm(x).includes(f)) : all;
                        render(filtered, inp.value);
                        _scEditDlPlace(inp);
                    };
                    inp._scEditDlOnInput = onInput;
                    inp.addEventListener("input", onInput, { passive: true });

                    st.onDocDown = (ev) => {
                        if (!st.pop) return;
                        if (ev.target === inp) return;
                        if (st.pop.contains(ev.target)) return;
                        _scEditDlClose();
                    };

                    st.onScroll = () => { if (st.pop && st.currentInput) _scEditDlPlace(st.currentInput); };
                    st.onResize = st.onScroll;

                    _doc().addEventListener("mousedown", st.onDocDown, true);
                    window.addEventListener("scroll", st.onScroll, true);
                    window.addEventListener("resize", st.onResize, true);
                }

                const inputs = Array.from(formEl.querySelectorAll("input[list]"));
                inputs.forEach(inp => {
                    const realListId = inp.dataset.originalList || inp.getAttribute("list");
                    if (!realListId) return;
                    if (!STRICT_LISTS.has(realListId)) return;

                    if (inp.dataset.editDlInputWired === "1") return;
                    inp.dataset.editDlInputWired = "1";

                    const selectAll = () => { try { inp.select(); } catch (_) { } };
                    inp.addEventListener("focus", selectAll);
                    inp.addEventListener("click", selectAll);

                    // ✅ GUARDA DEFINITIVA: só abre popup custom se estiver EDIT (hiddenItemId preenchido)
                    inp.addEventListener("mousedown", () => {
                        // ✅ só abre popup custom se estiver em modo EDIT
                        const isEdit = !!_doc().getElementById("hiddenItemId")?.value;
                        if (!isEdit) return;
                        setTimeout(() => openPop(inp, realListId), 0);
                    });
                });

                const modalEl = _doc().getElementById("itemModal");
                if (modalEl && !modalEl.dataset.editDlHideWired) {
                    modalEl.dataset.editDlHideWired = "1";
                    modalEl.addEventListener("hidden.bs.modal", () => {
                        try { _scEditDlClose(); } catch (_) { }
                    });
                }
            }

            // ==========================================================
            // 1) garante datalists antes do modal
            // ==========================================================
            try {
                if (typeof ensureDatalistsLoaded === "function") {
                    await Promise.race([
                        ensureDatalistsLoaded(),
                        new Promise((_, rej) => setTimeout(() => rej(new Error("timeout datalists")), 1800))
                    ]);
                }
            } catch (e) {
                console.warn("ensureDatalistsLoaded:", e);
                try { if (typeof setRefStatus === "function") setRefStatus("Carregando listas…"); } catch (_) { }
                try {
                    if (typeof ensureDatalistsLoaded === "function") {
                        ensureDatalistsLoaded().finally(() => { try { setRefStatus(""); } catch (_) { } });
                    }
                } catch (_) { }
            }

            // ==========================================================
            // 2) reset do formulário / estado
            // ==========================================================
            const form = _doc().getElementById("itemForm");
            form.reset();

            // ✅ controla modo
            const hiddenId = _doc().getElementById("hiddenItemId");
            if (hiddenId) hiddenId.value = itemId ? String(itemId) : "";

            // fecha popup custom se estava aberto
            try { _scEditDlClose(); } catch (_) { }

            const keepFieldsContainer = _doc().getElementById("keepFieldsContainer");
            if (keepFieldsContainer) keepFieldsContainer.style.display = itemId ? "none" : "";

            const formEl = _doc().getElementById("itemForm");

            // ============================
            // NEW: apenas datalist nativo + strict new
            // ============================
            if (!itemId) {
                try { _restoreNativeDatalistDropdown(formEl); } catch (_) { }
                try { _wireStrictDatalists("new"); } catch (_) { }
            }

            let item = null;

            // ============================
            // EDIT: carrega item, preenche, custom + strict edit
            // ============================
            if (itemId) {
                item = (Array.isArray(allItemsGlobal) ? allItemsGlobal.find(it => String(it.Id) === String(itemId)) : null) || null;

                if (!item || !item.AssignedTo) {
                    try {
                        const resp = await fetch(
                            `${apiUrl}(${itemId})` +
                            `?$select=Id,Title,Company,Category,Fabricante,Modelo,ITAssetBunge,Prateleira,Status,Hostname,Comments,Created,` +
                            `Site/Id,Site/Title,Author/Title,Editor/Title,AssignedTo/Id,AssignedTo/Title,AssignedTo/EMail` +
                            `&$expand=Site,Author,AssignedTo,Editor`,
                            { headers: { "Accept": "application/json;odata=verbose" } }
                        );
                        if (!resp.ok) throw new Error("Erro ao buscar item");
                        item = (await resp.json()).d;
                    } catch (e) {
                        console.error("openItemModal(fetch):", e);
                        try { showToast("Não foi possível carregar o item.", "danger"); } catch (_) { }
                        return;
                    }
                }

                _doc().getElementById("itemModalLabel").textContent = `Editar Item (Serial: ${item.Title || ""})`;
                try { populateItemForm(item); } catch (_) { }

                // ✅ EDIT: somente custom (desliga nativo e liga o popup)
                try {
                    _ensureEditDlCssOnce();
                    _disableNativeDatalistDropdown(formEl);
                    _wireEditDropdown(formEl, STRICT_LISTS, _norm, _getListOptions);
                } catch (e) {
                    console.warn("Edit dropdown:", e);
                }



                // ✅ EDIT: strict DEPOIS do custom (agora originalList existe e o modo é edit)
                try { _wireStrictDatalists("edit"); } catch (e) {
                    console.warn("Strict edit:", e);
                }



                const mustShow = needsAssignee(item.Status, item.Category);
                if (mustShow && item.AssignedTo && item.AssignedTo.Id) {
                    const setIf = (id, val) => { const el = _doc().getElementById(id); if (el) el.value = val; };
                    setIf("assignedToId", item.AssignedTo.Id);
                    setIf("assignedToName", item.AssignedTo.Title || "");
                    const sel = _doc().getElementById("ppAssignedToSelected");
                    if (sel) sel.textContent =
                        (item.AssignedTo.Title || "") + (item.AssignedTo.EMail ? " (" + item.AssignedTo.EMail + ")" : "");
                } else if (typeof clearAssignedTo === "function") {
                    clearAssignedTo();
                }

            } else {
                _doc().getElementById("itemModalLabel").textContent =
                    (typeof t === "function" ? t("newItemTitle") : "Novo Item");
                if (typeof clearAssignedTo === "function") clearAssignedTo();
            }

            // ==============================
            // 🇦🇷 A (Novo Registro): mostra/oculta e limpa campos AR
            // - AR: mostra bloco e (se for novo) limpa inputs
            // - Não-AR: esconde e limpa inputs (evita “vazar” valor antigo)
            // ==============================
            try {
                var arOk = (typeof isArgentinaTeam === "function") ? isArgentinaTeam() : false;
                var grp = _doc().getElementById("groupArDocs");
                if (grp) grp.style.display = arOk ? "" : "none";

                // Se for NOVO registro, sempre limpa os campos AR (para não reaproveitar sem querer)
                if (!itemId) {
                    ["inputNotaFiscal", "inputDataNota", "inputNrRemessa", "inputDataRemessa", "inputOCPO"]
                        .forEach(function (id) {
                            var el = _doc().getElementById(id);
                            if (el) el.value = "";
                        });
                }

                // Se NÃO for Argentina, limpa também (segurança contra valores “presos” no DOM)
                if (!arOk) {
                    ["inputNotaFiscal", "inputDataNota", "inputNrRemessa", "inputDataRemessa", "inputOCPO"]
                        .forEach(function (id) {
                            var el = _doc().getElementById(id);
                            if (el) el.value = "";
                        });
                }
            } catch (e) { }

            bindStatusWatcher();
            togglePrateleiraVisibility();
            initAssignedToPeoplePickerIfNeeded();
            toggleAssignedToVisibility();
            setupAttachmentsUI(itemId);

            if (itemId) initEditAuditGuards(item);
            else disableAuditForNewItem();

            bootstrap.Modal.getOrCreateInstance(_doc().getElementById("itemModal")).show();
        }

        function populateItemForm(item) {
            _doc().getElementById("itemModalLabel").textContent = `Editar Item (Serial: ${item.Title})`;
            _doc().getElementById("hiddenItemId").value = item.Id;
            _doc().getElementById("inputSerial").value = item.Title || "";
            _doc().getElementById("selectCompany").value = item.Company || "";
            _doc().getElementById("selectCategory").value = (typeof window.displayChoice === "function" ? window.displayChoice("Category", item.Category || "") : (item.Category || ""));
            _doc().getElementById("selectVendor").value = (typeof window.displayChoice === "function" ? window.displayChoice("Vendor", item.Fabricante || "") : (item.Fabricante || ""));
            _doc().getElementById("inputModel").value = item.Modelo || "";
            _doc().getElementById("inputITAssetBunge").value = item.ITAssetBunge || "";
            try {
                var _elSr = _doc().getElementById("inputSerial");
                var _elIt = _doc().getElementById("inputITAssetBunge");
                if (typeof window.scUppercaseFieldApply === "function") {
                    if (_elSr) window.scUppercaseFieldApply(_elSr);
                    if (_elIt) window.scUppercaseFieldApply(_elIt);
                }
            } catch (_eUp) { }
            _doc().getElementById("inputSite").value = item.Site ? item.Site.Title : "";

            const countryEl = _doc().getElementById("inputCountry");
            if (countryEl) countryEl.value = countryLabel(getCountryForItem(item));

            _doc().getElementById("selectPrateleira").value = (typeof window.displayChoice === "function" ? window.displayChoice("Prateleira", item.Prateleira || "") : (item.Prateleira || ""));
            _doc().getElementById("selectStatus").value = (typeof window.displayChoice === "function" ? window.displayChoice("Status", item.Status || "") : (item.Status || ""));
            _doc().getElementById("inputHostname").value = item.Hostname || "";
            _doc().getElementById("inputComments").value = item.Comments || "";

            // --- Assigned To (People Picker) ---
            const group = _doc().getElementById("groupAssignedTo");
            const selEl = _doc().getElementById("ppAssignedToSelected");
            const hidId = _doc().getElementById("assignedToId");
            const hidName = _doc().getElementById("assignedToName");
            const pp = _doc().getElementById("ppAssignedTo");
            const res = _doc().getElementById("ppAssignedToResults");

            const mustShow = requiresAssignee(item.Status, item.Category);

            if (group) group.classList.toggle("d-none", !mustShow);

            if (mustShow && item.AssignedTo && item.AssignedTo.Id) {
                if (hidId) hidId.value = item.AssignedTo.Id;
                if (hidName) hidName.value = item.AssignedTo.Title || "";
                if (selEl) selEl.textContent = (item.AssignedTo.Title || "") + (item.AssignedTo.EMail ? " (" + item.AssignedTo.EMail + ")" : "");
            } else {
                if (hidId) hidId.value = "";
                if (hidName) hidName.value = "";
                if (selEl) selEl.textContent = "";
            }
            if (pp) pp.value = "";
            if (res) res.innerHTML = "";

            // ===== 🇦🇷 Preencher campos AR (somente Argentina) =====
            try {
                var grpAr = _doc().getElementById("groupArDocs");
                if (grpAr) grpAr.style.display = (typeof isArgentinaTeam === "function" && isArgentinaTeam()) ? "" : "none";

                if (typeof isArgentinaTeam === "function" && isArgentinaTeam()) {
                    var nf = _doc().getElementById("inputNotaFiscal");
                    var dn = _doc().getElementById("inputDataNota");
                    var nr = _doc().getElementById("inputNrRemessa");
                    var dr = _doc().getElementById("inputDataRemessa");
                    var oc = _doc().getElementById("inputOCPO");

                    if (nf) nf.value = item.NotaFiscal || "";
                    if (nr) nr.value = item.NrRemessa || "";
                    if (oc) oc.value = item.OCPO || "";
                    if (dn) dn.value = (typeof toDTLocal === "function" ? toDTLocal(item.DataNota) : "");
                    if (dr) dr.value = (typeof toDTLocal === "function" ? toDTLocal(item.DataRemessa) : "");
                }
            } catch (e) { }
            try { window.translateChoiceDatalists && window.translateChoiceDatalists(); } catch (e) { }
        }

        function updateAssignedUIForForm() {
            const status = _doc().getElementById("selectStatus")?.value || "";
            const category = _doc().getElementById("selectCategory")?.value || "";
            const group = _doc().getElementById("groupAssignedTo");
            const selEl = _doc().getElementById("ppAssignedToSelected");
            const hidId = _doc().getElementById("assignedToId");
            const hidName = _doc().getElementById("assignedToName");
            const pp = _doc().getElementById("ppAssignedTo");
            const res = _doc().getElementById("ppAssignedToResults");

            if (!group) return;

            const mustShow = requiresAssignee(status, category);
            group.classList.toggle("d-none", !mustShow);

            if (!mustShow) {
                if (hidId) hidId.value = "";
                if (hidName) hidName.value = "";
                if (selEl) selEl.textContent = "";
                if (pp) pp.value = "";
                if (res) res.innerHTML = "";
            } else {
                // se quiser, re-inicialize o picker quando passar a exigir
                if (typeof initAssignedToPeoplePickerIfNeeded === "function") {
                    initAssignedToPeoplePickerIfNeeded();
                }
            }
        }

        _doc().addEventListener("DOMContentLoaded", () => {
            _doc().getElementById("selectStatus")?.addEventListener("change", updateAssignedUIForForm);
            _doc().getElementById("selectCategory")?.addEventListener("change", updateAssignedUIForForm);
        });



        _doc().getElementById("itemForm").addEventListener("submit", saveItem);

        async function saveItem(event) {
            event.preventDefault();

            // ===== Captura dos campos =====
            const itemIdRaw = _doc().getElementById("hiddenItemId").value;
            const itemIdNum = itemIdRaw ? parseInt(itemIdRaw, 10) : null; // <- normaliza
            const isEdit = itemIdNum !== null;

            const title = _doc().getElementById("inputSerial").value.trim();
            const company = _doc().getElementById("selectCompany").value.trim();

            const categoryDisplay = _doc().getElementById("selectCategory").value.trim();
            const category = (typeof window.canonicalChoice === 'function'
                ? window.canonicalChoice('Category', categoryDisplay)
                : categoryDisplay).trim();

            const model = _doc().getElementById("inputModel").value.trim();

            const vendorDisplay = _doc().getElementById("selectVendor").value.trim();
            const vendor = (typeof window.canonicalChoice === 'function'
                ? window.canonicalChoice('Vendor', vendorDisplay)
                : vendorDisplay).trim();

            const itAsset = _doc().getElementById("inputITAssetBunge").value.trim();

            const siteInputValue = _doc().getElementById("inputSite").value.trim();
            const datalist = _doc().getElementById("site-list");
            const selectedOption = Array.from(datalist.options).find(option => option.value === siteInputValue);
            const siteId = selectedOption ? parseInt(selectedOption.dataset.id, 10) : null;

            const prateleiraDisplay = _doc().getElementById("selectPrateleira").value.trim();
            const prateleira = (typeof window.canonicalChoice === 'function'
                ? window.canonicalChoice('Prateleira', prateleiraDisplay)
                : prateleiraDisplay).trim();

            const statusDisplay = _doc().getElementById("selectStatus").value.trim();
            const status = (typeof window.canonicalChoice === 'function'
                ? window.canonicalChoice('Status', statusDisplay)
                : statusDisplay).trim();

            const hostname = _doc().getElementById("inputHostname").value.trim(); // Preenchido automaticamente
            const comments = _doc().getElementById("inputComments").value.trim();

            // ===== Regras de Assigned To: só exigir para In Use + categorias definidas =====
            const isInUseLocal = s => String(s || "").trim().toLowerCase() === "in use";

            const CATS_REQUIRE_ASSIGNEE = [
                "Notebook",
                "Desktop",
                "Mobile",
                "Monitor",
                "Tablet",
                "Telephony (Ramal)"
            ];
            const norm = s => String(s || "")
                .trim()
                .toLowerCase()
                .normalize('NFD')
                .replace(/[\u0300-\u036f]/g, '')
                .replace(/[()\-_]/g, '')
                .replace(/\s+/g, '')
                .trim();
            const requiresAssignee = (st, cat) =>
                isInUseLocal(st) && CATS_REQUIRE_ASSIGNEE.some(c => norm(c) === norm(cat));

            // Pega AssignedToId do form
            const assignedToIdEl = _doc().getElementById("assignedToId");
            const assignedToId = parseInt(((assignedToIdEl && assignedToIdEl.value) ? assignedToIdEl.value : "").trim(), 10) || null;

            // Validação específica de AssignedTo
            if (requiresAssignee(status, category) && !assignedToId) {
                showToast("Selecione o usuário em 'Assigned To'.", "danger");
                return;
            }

            // ===== Validação obrigatórios (com toast dizendo qual falta) =====
            const getLabelText = (forId) => {
                const lbl = _doc().querySelector('#itemModal label[for="' + forId + '"]') || _doc().querySelector('label[for="' + forId + '"]');
                const txt = (lbl && lbl.textContent) ? lbl.textContent.replace(/\*/g, '').trim() : '';
                return txt || forId;
            };
            const missing = [];
            if (!title) missing.push(getLabelText("inputSerial"));
            if (!company) missing.push(getLabelText("selectCompany"));
            if (!category) missing.push(getLabelText("selectCategory"));
            if (!model) missing.push(getLabelText("inputModel"));
            if (!vendor) missing.push(getLabelText("selectVendor"));
            if (!itAsset) missing.push(getLabelText("inputITAssetBunge"));
            if (!status) missing.push(getLabelText("selectStatus"));
            if (!siteInputValue) missing.push(getLabelText("inputSite"));
            if (!comments) missing.push(getLabelText("inputComments"));
            if (missing.length) {
                showToast("Preencha o(s) campo(s) obrigatório(s): " + missing.join(", "), "danger");
                return;
            }

            // ===== Duplicidade (ignora o próprio item se for edição) =====
            try {
                const duplicates = await checkDuplicatesSingle({ title, itAsset, hostname, itemId: itemIdNum });
                let conflictMsg = "";
                if (duplicates.title) conflictMsg += "Serial Number já existe. ";
                if (duplicates.itAsset) conflictMsg += "IT Asset Bunge já existe. ";
                if (duplicates.hostname) conflictMsg += "Hostname já existe. ";
                if (conflictMsg) { showToast("Conflito: " + conflictMsg, "danger"); return; }
            } catch (error) {
                showToast("Erro na verificação de duplicidade.", "danger");
                return;
            }

            // ===== Status In Use: anexo obrigatório (Termo de entrega/Empréstimo) =====
            // AR TEMP: ignoreAttachmentsAR permite passar por enquanto (remover após reunião AR)
            var ignoreAttachmentsAREl = _doc().getElementById("ignoreAttachmentsAR");
            var ignoreAttachmentsAR = !!(ignoreAttachmentsAREl && ignoreAttachmentsAREl.checked);

            if (isEdit && requiresAssignee(status, category) && !ignoreAttachmentsAR) {
                try {
                    var attUrl = (typeof apiUrl !== "undefined" ? apiUrl : "") + "(" + itemIdNum + ")/AttachmentFiles?$select=Id&$top=1";
                    var attResp = await fetch(attUrl, { headers: { "Accept": "application/json;odata=verbose" } });
                    if (!attResp.ok) throw new Error(attResp.statusText);
                    var attData = await attResp.json();
                    var attResults = (attData.d && attData.d.results) ? attData.d.results : [];
                    if (attResults.length === 0) {
                        showToast("Anexos (Termo de entrega/Empréstimo) são obrigatórios para a Categoria selecionada quando Status = Em uso (In Use).", "danger");
                        return;
                    }
                } catch (err) {
                    showToast("Não foi possível verificar anexos. Tente novamente.", "danger");
                    return;
                }
            }

            // ===== 🇦🇷 Captura campos Argentina (somente AR) =====
            const arOk = (typeof isArgentinaTeam === "function") ? isArgentinaTeam() : false;

            let NotaFiscal = "";
            let NrRemessa = "";
            let OCPO = "";
            let DataNotaIso = null;
            let DataRemessaIso = null;

            if (arOk) {
                NotaFiscal = (_doc().getElementById("inputNotaFiscal")?.value || "").trim();
                NrRemessa = (_doc().getElementById("inputNrRemessa")?.value || "").trim();
                OCPO = (_doc().getElementById("inputOCPO")?.value || "").trim();

                const dnRaw = (_doc().getElementById("inputDataNota")?.value || "").trim();
                const drRaw = (_doc().getElementById("inputDataRemessa")?.value || "").trim();

                // fromDTLocal deve existir (vou te orientar no PASSO 2)
                DataNotaIso = (typeof fromDTLocal === "function") ? fromDTLocal(dnRaw) : (dnRaw ? new Date(dnRaw).toISOString() : null);
                DataRemessaIso = (typeof fromDTLocal === "function") ? fromDTLocal(drRaw) : (drRaw ? new Date(drRaw).toISOString() : null);
            }

            // ✅ Blindagem: se estiver editando e algum campo AR veio vazio, preserva o original
            if (arOk && isEdit && window.__scEditingItem) {
                const original = window.__scEditingItem;

                if (!NotaFiscal && original.NotaFiscal) NotaFiscal = original.NotaFiscal;
                if (!NrRemessa && original.NrRemessa) NrRemessa = original.NrRemessa;
                if (!OCPO && original.OCPO) OCPO = original.OCPO;

                if (!DataNotaIso && original.DataNota) DataNotaIso = original.DataNota;
                if (!DataRemessaIso && original.DataRemessa) DataRemessaIso = original.DataRemessa;
            }

            // ===== Payload =====
            const bodyData = {
                __metadata: { type: "SP.Data.Controle_x0020_de_x0020_EstoqueListItem" },
                Title: title,
                Company: company,
                Category: category,
                Fabricante: vendor,
                Modelo: model,
                ITAssetBunge: itAsset,

                // ✅ Regra: In Use não tem prateleira (limpa)
                Prateleira: isInUseLocal(status) ? "" : prateleira,

                SiteId: siteId,
                Status: status,
                Hostname: hostname,
                Comments: comments,

                // ✅ AssignedToId só quando a regra exigir; senão limpa (mantém seu padrão)
                AssignedToId: requiresAssignee(status, category) ? assignedToId : null
            };

            // ✅ Só adiciona campos AR no payload se for Argentina
            // (isso evita sobrescrever/apagar sem querer quando não for AR)
            if (arOk) {
                bodyData.NotaFiscal = NotaFiscal;           // texto (pode ser "")
                bodyData.NrRemessa = NrRemessa;            // texto (pode ser "")
                bodyData.OCPO = OCPO;                 // texto (pode ser "")
                bodyData.DataNota = DataNotaIso;          // ISO string ou null
                bodyData.DataRemessa = DataRemessaIso;      // ISO string ou null
            }

            // ===== Endpoint / headers =====
            let endpoint = apiUrl;
            let additionalHeaders = {};
            if (isEdit) {
                endpoint = `${apiUrl}(${itemIdNum})`;
                additionalHeaders = { "X-HTTP-Method": "MERGE", "IF-MATCH": "*" };
            }

            // ===== Envio =====
            try {
                const digest = await getRequestDigest();
                const response = await fetch(endpoint, {
                    method: "POST",
                    headers: {
                        "Accept": "application/json;odata=verbose",
                        "Content-Type": "application/json;odata=verbose",
                        "X-RequestDigest": digest,
                        ...additionalHeaders
                    },
                    body: JSON.stringify(bodyData)
                });

                if (!response.ok) {
                    throw new Error(`Erro ao ${isEdit ? "atualizar" : "criar"} item. Status: ${response.status}`);
                }

                showToast("Item salvo com sucesso!", "success");

                // ===== Pós-salvar =====
                if (!isEdit) {
                    const keepFieldsCheckbox = _doc().getElementById("keepFields");
                    if (keepFieldsCheckbox && keepFieldsCheckbox.checked) {
                        _doc().getElementById("inputSerial").value = "";
                        _doc().getElementById("inputITAssetBunge").value = "";
                        _doc().getElementById("inputHostname").value = "";

                        // ✅ também limpa campos AR no modo "Salvar campos" (se for AR)
                        if (arOk) {
                            ["inputNotaFiscal", "inputDataNota", "inputNrRemessa", "inputDataRemessa", "inputOCPO"]
                                .forEach(id => { const el = _doc().getElementById(id); if (el) el.value = ""; });
                        }
                        // mantém modal aberto
                    } else {
                        _doc().getElementById("itemForm").reset();
                        const itemModalEl = _doc().getElementById("itemModal");
                        const itemModal = bootstrap.Modal.getInstance(itemModalEl);
                        if (itemModal) itemModal.hide();
                    }
                } else {
                    // Edição: sempre reseta e fecha
                    _doc().getElementById("itemForm").reset();
                    const itemModalEl = _doc().getElementById("itemModal");
                    const itemModal = bootstrap.Modal.getInstance(itemModalEl);
                    if (itemModal) itemModal.hide();
                }

                _doc().getElementById("resultsSection")?.classList.add("opacity-50");
                // Atualiza a lista (aguarda terminar) e reaplica filtros atuais
                await fetchItems();

                // ✅ Reaplica o pipeline de filtros/busca atual (não "volta tudo")
                if (typeof window.triggerRecalc === "function") {
                    window.triggerRecalc();
                } else if (typeof window.applyFiltersFromState === "function" && typeof window.updateLatestItems === "function") {
                    // fallback seguro: aplica filtros do estado e atualiza tabela
                    const base = (window.allItemsGlobal || []);
                    window.updateLatestItems(window.applyFiltersFromState(base));
                }
                _doc().getElementById("resultsSection")?.classList.remove("opacity-50");
            } catch (error) {
                console.error("saveItem:", error);
                showToast("Falha ao salvar o item. Por favor, tente novamente.", "danger");
            }
        }

        async function deleteItem(itemId) {
            const endpoint = apiUrl + `(${itemId})`;
            try {
                const digest = await getRequestDigest();
                const response = await fetch(endpoint, {
                    method: "POST",
                    headers: {
                        "Accept": "application/json;odata=verbose",
                        "X-HTTP-Method": "DELETE",
                        "IF-MATCH": "*",
                        "X-RequestDigest": digest
                    }
                });

                // trate 200/204 como ok; 404 (já excluído) também não precisa travar
                if (!response.ok && response.status !== 404) {
                    throw new Error("Erro ao excluir item. Status: " + response.status);
                }

                // 1) Tombstone para não reaparecer no próximo sync imediato
                try { if (typeof Deleted_add === "function") Deleted_add(itemId); } catch (e) { }

                // 2) Remove local (lista corrente e filtrada)
                function keep(it) { var v = it && (it.Id != null ? it.Id : it.ID); return String(v) !== String(itemId); }
                if (Array.isArray(window.currentItemsList)) window.currentItemsList = window.currentItemsList.filter(keep);
                if (Array.isArray(window.filteredItems)) window.filteredItems = window.filteredItems.filter(keep);

                // 2.1) **MASTER**: remova do allItemsGlobal (fonte dos cards/dashboards)
                if (Array.isArray(window.allItemsGlobal)) window.allItemsGlobal = window.allItemsGlobal.filter(keep);

                // ✅ Remove do IndexedDB para não voltar ao reabrir
                try {
                    const idNum = Number(itemId); // keyPath é Id (Number)
                    if (Number.isFinite(idNum)) {
                        await scIdb.del(SC_STORES.items, idNum);
                    }
                } catch (e) {
                    console.warn("Falha ao remover do cache (IndexedDB):", e);
                }

                // ✅ Persistir cache final (boa prática)
                try {
                    await scPersistCache();
                } catch (e) {
                    console.warn("Falha ao persistir cache após delete:", e);
                }

                // ✅ 2.3) Persiste o estado final (agora com deleção refletida)
                try {
                    if (typeof scPersistCache === "function") await scPersistCache();
                } catch (e) {
                    console.warn("Falha ao persistir cache após delete:", e);
                }
                // 3) Re-render pela MESMA rota do app (usa o master e o modo atual)
                if (typeof refreshFromMaster === "function") {
                    refreshFromMaster(); // isto chama afterSyncRefresh internamente
                } else if (typeof afterSyncRefresh === "function") {
                    afterSyncRefresh(window.currentItemsList || []);
                } else {
                    try { renderLatestItems(); } catch (e) { }
                    try { if (typeof renderCardsNow === "function") renderCardsNow(window.currentItemsList || []); } catch (e) { }
                }

                // 3.1) (re)calcula dashboards/indicadores com base no MASTER atualizado
                try { updateDashboard(allItemsGlobal); } catch (e) { }
                try { updateTrendIndicators(); } catch (e) { }
                // 4) Reconciliação leve por IDs (garante consistência; limpa tombstones confirmados)
                try {
                    if (typeof reconcileDeletionsAfterSync === "function") {
                        reconcileDeletionsAfterSync(function (idDict) {
                            try { if (typeof Deleted_reconcileWithServerIdDict === "function") Deleted_reconcileWithServerIdDict(idDict || {}); } catch (e) { }
                        });
                    }
                } catch (e) { }

                try { if (typeof showToast === "function") showToast("Item excluído com sucesso!", "success"); } catch (e) { }
            } catch (error) {
                console.error("deleteItem:", error);
                try { if (typeof showToast === "function") showToast("Falha ao excluir o item. Por favor, tente novamente.", "danger"); } catch (e) { }
                // Em erro: não altera arrays locais nem tombstone
            }
        }


        /***** === REGISTRO EM MASSA — ABSOLUTE URL + AUTOSCROLL + RESULT COL (ES5) === *****
         * Site: https://bungeltd.sharepoint.com/sites/fieldservices
         * Lista: 'Stock Control'
         * - Resultados ✓/X na coluna "Result" (Comments intocado)
         * - Duplicidade: CSV + SharePoint (CAML GetItems, chunking)
         * - Corrida: trata 409/unique como duplicado
         * - Hostname só p/ Desktop/Notebook
         * - Auto-scroll acompanhando a linha sendo salva
         *****************************************************************************/

        // ====== CONFIG ABSOLUTA ======
        var BASE_SITE = "https://bungeltd.sharepoint.com/sites/fieldservices";
        var LIST_TITLE = "Stock Control";

        var LIST_ITEMS_URL = BASE_SITE + "/_api/web/lists/getbytitle('" + encodeURIComponent(LIST_TITLE) + "')/items";
        var GETITEMS_URL = BASE_SITE + "/_api/web/lists/getbytitle('" + encodeURIComponent(LIST_TITLE) + "')/GetItems";
        var CONTEXTINFO_URL = BASE_SITE + "/_api/contextinfo";
        var LIST_META_URL = BASE_SITE + "/_api/web/lists/getbytitle('" + encodeURIComponent(LIST_TITLE) + "')?$select=ListItemEntityTypeFullName";

        // ====== ESTADO GLOBAL ======
        var bulkHot = null;
        var __processingRow = null;
        var AUTO_SCROLL_ON_SAVE = true;

        // ====== FALLBACKS ======
        function toast(msg, type) { if (typeof showToast === "function") showToast(msg, type || "info"); else console.log(msg); }
        /** Mensagens de registro em massa / bulk (DICT: chaves bulk*). */
        function bulkT(key, vars) {
            if (typeof window.t === "function") return window.t(key, vars);
            return key;
        }
        var siteMapping = window.siteMapping || {}; // defina: { "sede (atrium)": {id:123, code:"ATR"}, ... }

        // ====== UTILS ======
        function norm(s) { return String(s || "").replace(/\s+/g, " ").trim().toLowerCase(); }
        function odataEscape(s) { return String(s || "").replace(/'/g, "''").trim(); }
        function xmlEscape(s) { return String(s || "").replace(/[<&>"]/g, function (c) { return ({ '<': '&lt;', '>': '&gt;', '&': '&amp;' })[c]; }); }
        function unique(arr) { var m = {}, out = [], i; for (i = 0; i < arr.length; i++) { var v = arr[i]; if (v != null && m[v] !== 1) { m[v] = 1; out.push(v); } } return out; }
        function chunk(arr, size) { var out = [], i; for (i = 0; i < arr.length; i += size) out.push(arr.slice(i, i + size)); return out; }
        function safeTrim(cell) { return cell == null ? "" : String(cell).trim(); }
        function getResultCol() { return bulkHot ? (bulkHot.countCols() - 1) : 10; } // última coluna

        // Cache do RequestDigest (~25 min)
        var __digest = { value: null, exp: 0 };
        function getRequestDigest() {
            return new Promise(function (res, rej) {
                var now = Date.now();
                if (__digest.value && now < __digest.exp) return res(__digest.value);
                fetch(CONTEXTINFO_URL, { method: "POST", headers: { "Accept": "application/json;odata=verbose" } })
                    .then(function (r) { if (!r.ok) throw new Error("contextinfo"); return r.json(); })
                    .then(function (j) {
                        __digest.value = j.d.GetContextWebInformation.FormDigestValue;
                        __digest.exp = Date.now() + 25 * 60 * 1000;
                        res(__digest.value);
                    })
                    .catch(rej);
            });
        }

        // Cache do ListItemEntityTypeFullName
        var __listType = { value: null, exp: 0 };
        function getListItemEntityType() {
            return new Promise(function (res, rej) {
                var now = Date.now();
                if (__listType.value && now < __listType.exp) return res(__listType.value);
                fetch(LIST_META_URL, { headers: { "Accept": "application/json;odata=verbose" } })
                    .then(function (r) { if (!r.ok) return r.text().then(function (t) { throw new Error("List meta: " + t); }); return r.json(); })
                    .then(function (j) {
                        var t = j && j.d && j.d.ListItemEntityTypeFullName;
                        if (!t) throw new Error("ListItemEntityTypeFullName não encontrado");
                        __listType.value = t;
                        __listType.exp = Date.now() + 24 * 60 * 60 * 1000;
                        res(t);
                    })
                    .catch(rej);
            });
        }

        function looksLikeUniqueViolation(txt, status) {
            var t = String(txt || "").toLowerCase();
            return status === 409 ||
                t.indexOf("requires a unique value") > -1 ||
                t.indexOf("duplicate value") > -1 ||
                t.indexOf("violation") > -1 ||
                t.indexOf("duplic") > -1 ||
                t.indexOf("já existe") > -1;
        }

        // CAML GetItems (sem URL gigante)
        // CAML GetItems robusto (timeout, retry, chunk configurável)
        // onBatch(batchIndex, totalBatches, fieldInternalName)
        // opts: { chunkSize=120, timeoutMs=30000, maxRetries=3, valueType="Text", skipNA=false }
        function fetchDuplicatesByFieldCaml(fieldInternalName, values, onBatch, opts) {
            opts = opts || {};
            var CHUNK = opts.chunkSize || 120;
            var TIMEOUT_MS = opts.timeoutMs || 30000;
            var RETRIES = opts.maxRetries || 3;
            var VAL_TYPE = opts.valueType || "Text";
            var SKIP_NA = !!opts.skipNA;

            function isNA(v) {
                var s = String(v || "").trim().toLowerCase();
                return s === "n/a" || s === "na" || s === "n.a" || s === "n.a." || s === "s/n" || s === "-";
            }
            function norm(s) { return String(s || "").replace(/\s+/g, " ").trim().toLowerCase(); }
            function xmlEscape(s) { return String(s || "").replace(/[<&>"]/g, function (c) { return ({ '<': '&lt;', '>': '&gt;', '&': '&amp;' })[c]; }); }

            // Limpa e deduplica
            var clean = [];
            var seen = Object.create(null);
            for (var i = 0; i < (values || []).length; i++) {
                var v = values[i];
                if (v == null) continue;
                if (SKIP_NA && isNA(v)) continue;
                v = String(v);
                if (!v) continue;
                if (!seen[v]) { seen[v] = 1; clean.push(v); }
            }
            if (!clean.length) return Promise.resolve(new Set());

            // Quebra em lotes
            var groups = [];
            for (var j = 0; j < clean.length; j += CHUNK) groups.push(clean.slice(j, j + CHUNK));
            var totalBatches = groups.length;

            function doFetchWithRetry(url, options, attempt) {
                attempt = attempt || 0;

                var controller = (typeof AbortController !== "undefined") ? new AbortController() : null;
                if (controller) options.signal = controller.signal;
                var to = setTimeout(function () { try { controller && controller.abort(); } catch (e) { } }, TIMEOUT_MS);

                return fetch(url, options).then(function (resp) {
                    clearTimeout(to);
                    // Retry para 429 / 503
                    if (!resp.ok && (resp.status === 429 || resp.status === 503) && attempt < RETRIES) {
                        var delay = Math.min(2000 * Math.pow(2, attempt), 10000) + Math.floor(Math.random() * 300);
                        return new Promise(function (res) { setTimeout(res, delay); })
                            .then(function () { return doFetchWithRetry(url, options, attempt + 1); });
                    }
                    return resp;
                }).catch(function (err) {
                    clearTimeout(to);
                    if (attempt < RETRIES) {
                        var delay2 = Math.min(1500 * Math.pow(2, attempt), 8000) + Math.floor(Math.random() * 300);
                        return new Promise(function (res) { setTimeout(res, delay2); })
                            .then(function () { return doFetchWithRetry(url, options, attempt + 1); });
                    }
                    throw err;
                });
            }

            return getRequestDigest().then(function (digest) {
                var found = new Set();
                var idx = 0;

                function next() {
                    if (idx >= totalBatches) return Promise.resolve(found);
                    var group = groups[idx++];
                    var valuesXml = group.map(function (v) { return "<Value Type='" + VAL_TYPE + "'>" + xmlEscape(v) + "</Value>"; }).join("");
                    var viewXml =
                        "<View>" +
                        "<Query><Where><In><FieldRef Name='" + fieldInternalName + "'/><Values>" + valuesXml + "</Values></In></Where></Query>" +
                        "<ViewFields><FieldRef Name='" + fieldInternalName + "'/></ViewFields>" +
                        "<RowLimit>5000</RowLimit>" +
                        "</View>";

                    var body = JSON.stringify({ query: { __metadata: { type: "SP.CamlQuery" }, ViewXml: viewXml } });
                    var options = {
                        method: "POST",
                        headers: {
                            "Accept": "application/json;odata=verbose",
                            "Content-Type": "application/json;odata=verbose",
                            "X-RequestDigest": digest
                        },
                        body: body
                    };

                    return doFetchWithRetry(GETITEMS_URL, options).then(function (resp) {
                        if (!resp.ok) return resp.text().then(function (t) { throw new Error("GetItems " + fieldInternalName + " (" + resp.status + "): " + t); });
                        return resp.json();
                    }).then(function (data) {
                        var arr = (data && data.d && data.d.results) ? data.d.results : [];
                        for (var k = 0; k < arr.length; k++) {
                            var val = arr[k][fieldInternalName];
                            if (val != null && val !== "") found.add(norm(val));
                        }
                        if (typeof onBatch === "function") onBatch(idx, totalBatches, fieldInternalName);
                        return next();
                    });
                }

                return next();
            });
        }



        // UMA searchOnce (uso pontual; sem "??")
        function searchOnce(field, value, itemId) {
            return new Promise(function (resolve, reject) {
                if (!value) return resolve(false);
                var filter = "(" + field + " eq '" + odataEscape(value) + "'" + (itemId ? (" and Id ne " + itemId) : "") + ")";
                var url = LIST_ITEMS_URL + "?$select=Id&$top=1&$filter=" + encodeURIComponent(filter);
                fetch(url, { headers: { "Accept": "application/json;odata=verbose" } })
                    .then(function (r) { if (!r.ok) return r.text().then(function (t) { throw new Error(t); }); return r.json(); })
                    .then(function (j) { resolve((j && j.d && j.d.results && j.d.results.length) ? true : false); })
                    .catch(reject);
            });
        }

        // Checagem single
        function checkDuplicatesSingle(opts) {
            var title = opts.title, itAsset = opts.itAsset, hostname = opts.hostname, itemId = opts.itemId || null;
            var out = { title: false, itAsset: false, hostname: false };

            var tOk = title && title.trim() !== "" && !isNA(title);    // Serial: ignora "n/a"
            var aOk = itAsset && itAsset.trim() !== "" && !isNA(itAsset);  // IT Asset: ignora "n/a"
            var hOk = hostname && hostname.trim() !== "";                    // Hostname: mantém regra atual

            return (tOk ? searchOnce("Title", title, itemId) : Promise.resolve(false))
                .then(function (v) { out.title = !!v; return aOk ? searchOnce("ITAssetBunge", itAsset, itemId) : false; })
                .then(function (v) { out.itAsset = !!v; return hOk && !isNA(hostname) ? searchOnce("Hostname", hostname, itemId) : false; })
                .then(function (v) { out.hostname = !!v; return out; });
        }


        // ====== HOSTNAME ======
        function shouldAutoHostname(category) {
            // Usa o valor canônico quando possível para não quebrar com idioma traduzido
            try { if (typeof window.canonicalChoice === "function") category = window.canonicalChoice("Category", category); } catch (_) { }
            var c = norm(category);
            return (c === "desktop" || c === "notebook");
        }
        function maybeFillHostnameForRow(hot, rIdx) {
            var row = hot.getDataAtRow(rIdx); if (!row) return;
            var serial = safeTrim(row[0]);
            var category = safeTrim(row[2]);
            var siteText = safeTrim(row[6]);
            var current = safeTrim(row[9]); // Hostname

            // Sem dados suficientes para gerar hostname → limpa célula (evita hostname “órfão” após apagar Serial/Site/Categoria)
            if (!serial || !siteText || !shouldAutoHostname(category)) {
                if (current !== "") hot.setDataAtCell(rIdx, 9, "", "autofill");
                return;
            }
            var sObj = siteMapping[String(siteText).toLowerCase()];
            if (!sObj || !sObj.code) {
                if (current !== "") hot.setDataAtCell(rIdx, 9, "", "autofill");
                return;
            }

            var generated = sObj.code + "-" + serial;
            // Hostname é somente leitura no grid: sempre sobrescreve com o valor gerado pela regra
            hot.setDataAtCell(rIdx, 9, generated, "autofill");
        }

        // ====== AUTOSCROLL / HIGHLIGHT ======
        function addClassAt(row, col, className) {
            var meta = bulkHot.getCellMeta(row, col);
            var cls = (meta && meta.className) ? meta.className : "";
            if (cls.indexOf(className) === -1) bulkHot.setCellMeta(row, col, "className", (cls + " " + className).replace(/\s+/g, " ").trim());
        }
        function removeClassAt(row, col, className) {
            var meta = bulkHot.getCellMeta(row, col);
            var cls = (meta && meta.className) ? meta.className : "";
            if (!cls) return;
            cls = cls.replace(new RegExp("\\b" + className + "\\b", "g"), "").replace(/\s{2,}/g, " ").trim();
            bulkHot.setCellMeta(row, col, "className", cls);
        }
        function highlightProcessingRow(idx) {
            if (!bulkHot) return;
            var cols = bulkHot.countCols();
            if (__processingRow !== null) { for (var c = 0; c < cols; c++) removeClassAt(__processingRow, c, "row-processing"); }
            for (var c2 = 0; c2 < cols; c2++) addClassAt(idx, c2, "row-processing");
            __processingRow = idx; bulkHot.render();
        }
        function scrollRowIntoView(hot, rowIndex) {
            if (!AUTO_SCROLL_ON_SAVE || !hot) return;
            try {
                if (typeof hot.scrollViewportTo === "function") hot.scrollViewportTo(rowIndex, 0);
                else {
                    var holder = hot.rootElement && hot.rootElement.querySelector ? hot.rootElement.querySelector(".wtHolder") : null;
                    var approx = (typeof hot.getRowHeight === "function" && hot.getRowHeight(0)) || 24;
                    var target = Math.max(0, (rowIndex * approx) - approx * 2);
                    if (holder && typeof holder.scrollTo === "function") holder.scrollTo({ top: target, behavior: "smooth" });
                    else if (holder) holder.scrollTop = target;
                }
            } catch (e) { }
        }

        // ====== MODAL / HANDSONTABLE ======
