            Model: ["model", "modelo"],
            ITAssetBunge: ["it asset bunge", "it asset b", "asset tag", "it asset", "tag", "patrimônio", "patrimonio"],
            Site: ["site", "local", "sede", "ubicación", "ubicacion", "bsa site"],
            Prateleira: ["prateleira", "estante", "estanteria", "shelf", "rack"],
            Status: ["status", "estado", "situação", "situacion"],
