        /**
         * Converte valor de input/textarea para MAIÚSCULO preservando seleção do cursor.
         * Uso: scUppercaseFieldApply(el) ou scBindUppercaseInputs(['#meuCampo']) para anexar listeners.
         */
        (function scUppercaseInputModule() {
            var d = _doc;

            function applyUppercasePreserve(el) {
                if (!el || el.nodeType !== 1) return;
                var tag = el.tagName;
                if (tag !== "INPUT" && tag !== "TEXTAREA") return;
                if (tag === "INPUT") {
                    var typ = String(el.getAttribute("type") || "text").toLowerCase();
                    if (typ !== "text" && typ !== "search" && typ !== "tel" && typ !== "url" && typ !== "") return;
                }
                if (el.readOnly || el.disabled) return;
                var raw = el.value;
                var next = String(raw).toUpperCase();
                if (raw === next) return;
                var start = el.selectionStart;
                var end = el.selectionEnd;
                var dir = el.selectionDirection;
                el.value = next;
                var len = next.length;
                if (typeof el.setSelectionRange !== "function") return;
                if (typeof start !== "number" || typeof end !== "number" || isNaN(start) || isNaN(end)) return;
                start = Math.max(0, Math.min(start, len));
                end = Math.max(0, Math.min(end, len));
                try {
                    el.setSelectionRange(start, end, dir === "backward" ? "backward" : "forward");
                } catch (e1) {
                    try { el.setSelectionRange(start, end); } catch (e2) { /* mobile antigo */ }
                }
            }

            function bindElement(el) {
                if (!el || el.nodeType !== 1) return;
                if (el._scUppercaseBound) return;
                el._scUppercaseBound = true;
                var composing = false;
                var run = function () {
                    if (composing) return;
                    applyUppercasePreserve(el);
                };
                el.addEventListener("compositionstart", function () { composing = true; });
                el.addEventListener("compositionend", function () {
                    composing = false;
                    applyUppercasePreserve(el);
                });
                el.addEventListener("input", run);
                el.addEventListener("change", run);
                el.addEventListener("paste", function () {
                    if (typeof requestAnimationFrame === "function") {
                        requestAnimationFrame(function () { applyUppercasePreserve(el); });
                    } else {
                        setTimeout(function () { applyUppercasePreserve(el); }, 0);
                    }
                });
            }

            function queryAllUnique(selectors) {
                var list = [];
                var useWeak = typeof WeakSet !== "undefined";
                var seen = useWeak ? new WeakSet() : [];
                (selectors || []).forEach(function (sel) {
                    if (!sel || typeof sel !== "string") return;
                    try {
                        d().querySelectorAll(sel).forEach(function (el) {
                            if (!el) return;
                            if (useWeak) {
                                if (seen.has(el)) return;
                                seen.add(el);
                            } else {
                                if (seen.indexOf(el) !== -1) return;
                                seen.push(el);
                            }
                            list.push(el);
                        });
                    } catch (eQ) { /* seletor inválido */ }
                });
                return list;
            }

            var DEFAULT_UPPERCASE_SELECTORS = [
                "#inputSerial",
                "#inpSerial",
                "input[name=\"Serial\"]",
                "#inputITAssetBunge",
                "#inpITBunge",
                "input[name=\"ITAssetBunge\"]"
            ];

            function bindSelectors(selectors) {
                queryAllUnique(selectors).forEach(bindElement);
            }

            window.scUppercaseFieldApply = applyUppercasePreserve;
            window.scBindUppercaseInputs = function (extra) {
                if (!extra) return;
                if (typeof extra === "string") bindSelectors([extra]);
                else if (Array.isArray(extra)) bindSelectors(extra);
            };

            function initDefault() {
                bindSelectors(DEFAULT_UPPERCASE_SELECTORS);
                var m = d().getElementById("itemModal");
                if (m && !m._scUppercaseModalHook) {
                    m._scUppercaseModalHook = true;
                    m.addEventListener("shown.bs.modal", function () {
                        bindSelectors(DEFAULT_UPPERCASE_SELECTORS);
                        queryAllUnique(DEFAULT_UPPERCASE_SELECTORS).forEach(applyUppercasePreserve);
                    });
                }
            }

            if (d().readyState === "loading") {
                d().addEventListener("DOMContentLoaded", initDefault);
            } else {
                initDefault();
            }
        })();

        /***** Funções de Tendência Geral (cache + escopo = mesmos dados dos cards) *****/
        async function fetchTrendData() {
            try {
                var base = [];
                if (typeof getDashboardBaseItems === "function") {
                    base = getDashboardBaseItems();
                } else if (typeof applyDashScope === "function" && Array.isArray(window.allItemsGlobal)) {
                    base = applyDashScope(window.allItemsGlobal.slice());
                } else if (Array.isArray(window.allItemsGlobal)) {
                    base = window.allItemsGlobal.slice();
                }
                return computeCreatedWindowTrends(base);
            } catch (e) {
                console.error("fetchTrendData:", e);
                return computeCreatedWindowTrends([]);
            }
        }

        // Atualiza o indicador da Trend Geral
        async function updateTrendIndicators() {
            try {
                const trendData = await fetchTrendData();

                function formatTrend(current, previous) {
                    const diff = current - previous;
                    if (diff > 0) return `<span class="text-success"><i class="bi bi-arrow-up"></i> +${diff}</span>`;
                    else if (diff < 0) return `<span class="text-danger"><i class="bi bi-arrow-down"></i> ${diff}</span>`;
                    else return `<span class="text-muted"><i class="bi bi-dash"></i> 0</span>`;
                }

                // ✅ NOVO: fallback seguro (se a chave não existir, assume 0/0)
                function getTrend(key) {
                    return trendData[key] || { current: 0, previous: 0 };
                }

                _doc().getElementById("trendTotal").innerHTML = formatTrend(getTrend("total").current, getTrend("total").previous);
                _doc().getElementById("trendDisposed").innerHTML = formatTrend(getTrend("Disposed").current, getTrend("Disposed").previous);
                _doc().getElementById("trendAvailable").innerHTML = formatTrend(getTrend("Available").current, getTrend("Available").previous);
                _doc().getElementById("trendDisposal").innerHTML = formatTrend(getTrend("Retired").current, getTrend("Retired").previous);
                _doc().getElementById("trendInTransport").innerHTML = formatTrend(getTrend("In Transport").current, getTrend("In Transport").previous);
                _doc().getElementById("trendReserved").innerHTML = formatTrend(getTrend("Reserved").current, getTrend("Reserved").previous);
                _doc().getElementById("trendOtherCountry").innerHTML = formatTrend(getTrend("In Use").current, getTrend("In Use").previous);

            } catch (error) {
                console.error("Erro ao atualizar indicadores de tendência:", error);
            }
        }





