        // Carrega as configurações de colunas do localStorage (mescla com defaults) 
        // Default column
        function loadColumnSettings() {
            const defaults = {
                Title: true,
                Company: true,
                Category: true,
                Vendor: true,
                Model: true,
                ITAssetBunge: true,
                Site: true,
                Country: true,
                Status: true,
                Prateleira: true,
                Hostname: false,
                Comments: false,
                Created: false,
                Modified: false,
                Responsible: true,
                AssignedTo: true,
                Editor: false,

                // 🇦🇷 Colunas Argentina (default ON)
                NotaFiscal: true,
                DataNota: true,
                NrRemessa: true,
                DataRemessa: true,
                OCPO: true,
                DocumentoAR: true
            };

            let merged = defaults;
            try {
                const saved = localStorage.getItem("columnSettings");
                merged = saved ? { ...defaults, ...JSON.parse(saved) } : defaults;
            } catch (e) {
                merged = defaults;
            }

            // Chaves alternativas (JSON antigo / typo)
            var aliasColumnFix = false;
            try {
                if (merged && typeof merged === "object") {
                    if (merged.Modified === undefined && merged.modified !== undefined) {
                        merged.Modified = merged.modified;
                        aliasColumnFix = true;
                    }
                    if (merged.Modified === undefined && merged.Merged !== undefined) {
                        merged.Modified = merged.Merged;
                        aliasColumnFix = true;
                    }
                }
            } catch (e2) { }

            // Garante booleanos (JSON antigo; string "true" não pode virar false por engano)
            function coerceColBool(v, defVal) {
                if (v === true || v === false) return v;
                if (v === 1 || v === "1") return true;
                if (v === 0 || v === "0") return false;
                if (typeof v === "string") {
                    const s = v.trim().toLowerCase();
                    if (s === "true" || s === "yes" || s === "on") return true;
                    if (s === "false" || s === "no" || s === "off") return false;
                }
                return defVal;
            }
            Object.keys(defaults).forEach((k) => {
                merged[k] = coerceColBool(merged[k], defaults[k]);
            });

            // 🔒 Força colunas AR desligadas para quem não é do time AR
            if (!isArgentinaTeam()) {
                merged.NotaFiscal = false;
                merged.DataNota = false;
                merged.NrRemessa = false;
                merged.DataRemessa = false;
                merged.OCPO = false;
                merged.DocumentoAR = false;
            }

            if (aliasColumnFix) {
                try {
                    const out = {};
                    Object.keys(defaults).forEach((k) => { out[k] = merged[k]; });
                    localStorage.setItem("columnSettings", JSON.stringify(out));
                } catch (e3) { }
            }

            return merged;
        }
        /****************************
         * Configurar Colunas (visibilidade + ordem)
         ****************************/
        const COL_ORDER_KEY = "columnOrder";

        function defaultColumnOrder() {
            return [
                "Title", "Company", "Category", "Fabricante", "Modelo", "ITAssetBunge",
                "Site", "Country", "Prateleira",

                // 🇦🇷 novas colunas (AR)
                "NotaFiscal", "DataNota", "NrRemessa", "DataRemessa", "OCPO", "DocumentoAR",

                "Status", "Hostname", "Comments", "Created", "Responsible", "AssignedTo", "Editor", "Modified"
            ];
        }

        function loadColumnOrder() {
            try {
                const raw = localStorage.getItem(COL_ORDER_KEY);
                const arr = raw ? JSON.parse(raw) : null;
                if (!Array.isArray(arr) || !arr.length) return defaultColumnOrder();
                const def = defaultColumnOrder();
                let cleaned = arr.filter(k => def.includes(k));
                def.forEach(k => { if (!cleaned.includes(k)) cleaned.push(k); });
                // Migração: Modified sempre logo após Editor (evita "Modified" isolado no topo do modal)
                const ie = cleaned.indexOf("Editor");
                const im = cleaned.indexOf("Modified");
                if (ie !== -1 && im !== -1 && im !== ie + 1) {
                    cleaned.splice(im, 1);
                    const ie2 = cleaned.indexOf("Editor");
                    cleaned.splice(ie2 + 1, 0, "Modified");
                }
                if (JSON.stringify(cleaned) !== JSON.stringify(arr)) {
                    try { localStorage.setItem(COL_ORDER_KEY, JSON.stringify(cleaned)); } catch (e) { }
                }
                return cleaned;
            } catch (e) {
                return defaultColumnOrder();
            }
        }

        function saveColumnOrder(order) {
            try { localStorage.setItem(COL_ORDER_KEY, JSON.stringify(order)); } catch (e) { }
        }

        function applyColumnOrder(columns) {
            const order = loadColumnOrder();
            const pos = new Map(order.map((k, i) => [k, i]));
            return columns.slice().sort((a, b) => {
                const ia = pos.has(a.key) ? pos.get(a.key) : 999;
                const ib = pos.has(b.key) ? pos.get(b.key) : 999;
                return ia - ib;
            });
        }

        function resetColumnSettings() {
            try { localStorage.removeItem("columnSettings"); } catch (e) { }
            try { localStorage.removeItem("columnOrder"); } catch (e) { }

            // reaplica na tela
            try { renderTableHeader(); } catch (e) { }
            try { renderLatestItems(); } catch (e) { }

            // opcional: se o modal estiver aberto, recarrega os checks imediatamente
            try {
                const modalEl = _doc().getElementById("columnSettingsModal");
                if (modalEl && modalEl.classList.contains("show")) {
                    openColumnSettingsModal();
                }
            } catch (e) { }

            try { if (typeof showToast === "function") showToast("Colunas resetadas.", "success"); } catch (e) { }
        }


