            async function adminCadUsersMergeEmailEnviado(records) {
                if (!Array.isArray(records) || records.length === 0) return;

                // Inicializa por padrão como "Não"
                records.forEach(r => { r.EmailEnviado = false; });

                // Busca todos itens do CadUsuarios (assumimos que é pequeno; se for grande, fazemos filter depois)
                const listTitleEsc = escapeODataString(CAD_USERS_LIST_TITLE);
                let nextUrl = siteBaseUrl +
                    "/_api/web/lists/getbytitle('" + listTitleEsc + "')/items" +
                    "?$select=Id,EmailEnviado,Usuario/Id&$expand=Usuario&$top=5000";

                const map = new Map(); // userId -> boolean

                while (nextUrl) {
                    const resp = await scFetch(nextUrl, {
                        method: "GET",
                        headers: { "Accept": "application/json;odata=verbose" },
                        timeoutMs: 20000,
                        retries: 1
                    });
                    const data = await resp.json();
                    const results = data?.d?.results || [];

                    results.forEach(it => {
                        const uid = it?.Usuario?.Id;
                        if (uid != null) map.set(String(uid), !!it?.EmailEnviado);
                    });

                    nextUrl = data?.d?.__next || null;
                    // SharePoint sometimes returns absolute __next already; keep as-is
                }

                records.forEach(r => {
                    if (r && r.UserId != null) {
                        const v = map.get(String(r.UserId));
                        r.EmailEnviado = !!v;
                    }
                });
            }

            async function adminCadUsersUpsertEmailEnviadoForRecord(record) {
                if (!record) throw new Error("Record inválido");
                if (record.Cargo === "None" || !record.Cargo) {
                    throw new Error("Cargo não definido");
                }
                const cargoChoice = record.Cargo; // Field / Visitante / Admin
                if (!["Field", "Visitante", "Admin"].includes(cargoChoice)) {
                    throw new Error("Cargo inválido: " + cargoChoice);
                }

                // Garante UserId
                let userId = record.UserId;
                if (userId == null) {
                    const ensured = await ensureUserByKeyOrEmail(record.LoginName || record.Email || "");
                    userId = ensured?.Id;
                }
                if (userId == null) throw new Error("UserId não encontrado");

                const digest = await adminGetDigest();
                if (!digest) throw new Error("Falha ao obter FormDigestValue");

                const listTitleEsc = escapeODataString(CAD_USERS_LIST_TITLE);
                const base = siteBaseUrl + "/_api/web/lists/getbytitle('" + listTitleEsc + "')/items";
                const entityTypeName = await adminCadUsersGetEntityTypeFullName();

                // Verifica se existe item para UsuarioId
                const filterUrl = base + "?$top=1&$select=Id&$filter=UsuarioId eq " + Number(userId);
                const resp = await scFetch(filterUrl, {
                    method: "GET",
                    headers: { "Accept": "application/json;odata=verbose" },
                    timeoutMs: 20000,
                    retries: 1
                });
                const data = await resp.json();
                const existing = data?.d?.results?.[0] || null;

                const payload = {
                    "__metadata": { "type": entityTypeName },
                    Cargo: cargoChoice,
                    EmailEnviado: false,
                    UsuarioId: Number(userId)
                };

                if (existing?.Id != null) {
                    const itemUrl = base + "(" + existing.Id + ")";
                    const patch = {
                        "__metadata": { "type": entityTypeName },
                        Cargo: cargoChoice,
                        EmailEnviado: false
                    };
                    const res = await fetch(itemUrl, {
                        method: "POST",
                        headers: {
                            "Accept": "application/json;odata=verbose",
                            "Content-Type": "application/json;odata=verbose",
                            "X-RequestDigest": digest,
                            "IF-MATCH": "*",
                            "X-HTTP-Method": "MERGE"
                        },
                        body: JSON.stringify(patch)
                    });
                    if (!res.ok) throw new Error("Falha ao atualizar CadUsuarios: HTTP " + res.status);
                } else {
                    const res = await fetch(base, {
                        method: "POST",
                        headers: {
                            "Accept": "application/json;odata=verbose",
                            "Content-Type": "application/json;odata=verbose",
                            "X-RequestDigest": digest
                        },
                        body: JSON.stringify(payload)
                    });
                    if (!res.ok) {
                        const txt = await res.text().catch(() => "");
                        throw new Error("Falha ao criar CadUsuarios: HTTP " + res.status + (txt ? " - " + txt.slice(0, 200) : ""));
                    }
                }
            }

            async function adminUsersSendAccessSelected() {
                const state = window.__adminUsersState || { records: [] };
                const tbody = _doc().getElementById("adminUsersTbody");
                if (!tbody) return;

                const selectedCbs = Array.from(tbody.querySelectorAll('input.admin-user-select:checked'));
                if (!selectedCbs.length) {
                    toast((typeof window.t === "function" ? window.t("admSelectAtLeastOneUser") : "Selecione ao menos 1 usuário."), "warning");
                    return;
                }

                const selectedLogins = selectedCbs.map(cb => String(cb.dataset.login || ""));
                const selectedRecords = selectedLogins
                    .map(login => state.records.find(r => String(r.LoginName).toLowerCase() === login.toLowerCase()))
                    .filter(Boolean);

                if (!selectedRecords.length) {
                    toast((typeof window.t === "function" ? window.t("admCouldNotResolveUsers") : "Não foi possível resolver os usuários selecionados."), "danger");
                    return;
                }

                let ok = 0, fail = 0;
                toast((typeof window.t === "function" ? window.t("admUpdatingCadEmailNo") : "Atualizando CadUsuarios (marcando EmailEnviado = Não)..."), "info");
                for (const rec of selectedRecords) {
                    try {
                        await adminCadUsersUpsertEmailEnviadoForRecord(rec);
                        ok++;
                    } catch (e) {
                        console.error(e);
                        fail++;
                    }
                }

                if (ok && !fail) toast((typeof window.t === "function" ? window.t("admAccessSentOk", { ok: ok }) : ("Acesso enviado com sucesso para " + ok + " usuário(s).")), "success");
                else if (ok && fail) toast((typeof window.t === "function" ? window.t("admAccessSentPartial", { ok: ok, fail: fail }) : ("Acesso enviado: OK=" + ok + " | Falhas=" + fail)), "warning");
                else toast((typeof window.t === "function" ? window.t("admAccessSentFail") : "Falha ao enviar acesso para os usuários."), "danger");

                // Atualiza lista/tabela e limpa seleção
                try { adminUsersDeselectAllVisible(); } catch (_) { }
                try {
                    await adminUsersFetchAndCacheFromSharePoint({ silentToast: true });
                } catch (e) { console.warn(e); }

                adminUsersRenderTable();
                adminUsersUpdateSelectionUI();
            }

