        // Variável global para armazenar o evento antesinstallprompt
        let deferredPrompt;

        // Captura o evento beforeinstallprompt
        window.addEventListener('beforeinstallprompt', (e) => {
            e.preventDefault(); // Impede que o prompt apareça automaticamente
            deferredPrompt = e;
            console.log('Evento beforeinstallprompt capturado.');

            // Exibe automaticamente o modal de instalação
            const installModalEl = _doc().getElementById('installModal');
            const installModal = new bootstrap.Modal(installModalEl);
            installModal.show();
        });

        // Ação do botão "Instalar Agora" no modal
        _doc().getElementById("btnInstall").addEventListener("click", async () => {
            if (deferredPrompt) {
                // Fecha o modal
                const installModalEl = _doc().getElementById('installModal');
                const installModal = bootstrap.Modal.getInstance(installModalEl);
                installModal.hide();

                // Exibe o prompt de instalação do PWA
                deferredPrompt.prompt();

                // Aguarda a resposta do usuário
                const { outcome } = await deferredPrompt.userChoice;
                console.log(`Resposta do usuário: ${outcome}`);

                // Limpa a variável para evitar reutilização
                deferredPrompt = null;
            }
        });



        /* ===========================================================
          Relatórios (Excel) - Stock Control  (ATUALIZADO)
          Depende de:
            - window.allItemsGlobal  (toda a base carregada)
            - window.filteredItems   (visão filtrada da tela, se existir)
            - Biblioteca XLSX já carregada na página
          Elementos no modal:
            - #relAllBase (checkbox)
            - #relIni, #relFim (input date) + #relPeriodByCreated | #relPeriodByModified (intervalo por Created ou Modified)
            - #relSortBy, #relSortDir (ordenação do ficheiro exportado; ativo mesmo com "toda base")
            - #relStatus dentro de #relAdvanced (Mais filtros)
            - #relStatus (input com datalist)
            - [Avançados] #relCompany, #relCategory, #relFabricante, #relModelo, #relSite,
                          #relHostname, #relITAsset, #relAuthor, #relOnlyStock
            - #relFileName (input text)
            - .rel-col (checkbox de colunas)
            - #btnGerarExcel (botão exportar)
            - #btnRelatorioEstoque (botão estoque)
            - #btnRelatorioModificadosDia (relatório Modificados: período De e/ou Até obrigatório; só data Modified)
          =========================================================== */

        // Cabeçalhos amigáveis para o Excel
        var HEADER_LABELS = {
            Company: "Empresa",
            Category: "Categoria",
            Fabricante: "Fabricante",
            Modelo: "Modelo",
            Title: "Serial Number",
            ITAssetBunge: "IT Asset Bunge",
            Site: "Site",
            Country: "País",
            Status: "Status",
            Hostname: "Hostname",
            Comments: "Comentários",
            Created: "Criado em",
            Modified: (typeof t === "function" && t("colModified") && t("colModified") !== "colModified")
                ? t("colModified")
                : "Modificado em",
            // "Author" no SharePoint = "Created By" (quem criou). No seu UI isso aparece como "Responsável".
            // Usa a mesma tradução do UI (colResponsible) para refletir PT/ES/EN no cabeçalho do Excel.
            Author: (typeof t === "function" && t("colResponsible") && t("colResponsible") !== "colResponsible")
                ? t("colResponsible")
                : "Criado por",
            Editor: (typeof t === "function" && t("colEditor") && t("colEditor") !== "colEditor")
                ? t("colEditor")
                : "Editado por",
        };

        // Status que contam como estoque
        var STOCK_STATUSES = ["Available", "Reserved", "Retired"];

        // ===== Utilidades =====
        function parseDateOnly(s) {
            try {
                if (!s) return null;
                if (s.indexOf('T') > -1) return new Date(s);
                var parts = s.split('-'); // yyyy-mm-dd
                return new Date(parseInt(parts[0], 10), parseInt(parts[1], 10) - 1, parseInt(parts[2], 10));
            } catch (e) { return null; }
        }

        function formatDateTime(val) {
            if (!val && val !== 0) return '';
            var d = (typeof parseSharePointDate === "function") ? parseSharePointDate(val) : new Date(val);
            if (!d || isNaN(d.getTime())) return '';
            var yyyy = d.getFullYear();
            var mm = ('0' + (d.getMonth() + 1)).slice(-2);
            var dd = ('0' + d.getDate()).slice(-2);
            var hh = ('0' + d.getHours()).slice(-2);
            var mi = ('0' + d.getMinutes()).slice(-2);
            return yyyy + '-' + mm + '-' + dd + ' ' + hh + ':' + mi;
        }

        /** DD/MM/AAAA HH:MM:SS para colunas Criado em / Modificado em no Excel */
        function formatExportDateTimeBr(val) {
            if (!val && val !== 0) return '';
            var d = (typeof parseSharePointDate === "function") ? parseSharePointDate(val) : new Date(val);
            if (!d || isNaN(d.getTime())) return '';
            var pad = function (n) { return String(n).padStart(2, "0"); };
            return pad(d.getDate()) + "/" + pad(d.getMonth() + 1) + "/" + d.getFullYear() + " "
                + pad(d.getHours()) + ":" + pad(d.getMinutes()) + ":" + pad(d.getSeconds());
        }

        function norm(s) { return String(s || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, ""); }
        function contains(hay, needle) { if (!needle) return true; return norm(hay).includes(norm(needle)); }

        /**
         * Ordem final ideal no Excel (colunas selecionadas):
         * Metadados → Ativo → Localização → Estado
         */
        function applyExcelMetadataColumnOrder(cols) {
            var IDEAL = [
                "Comments", "Author", "Created", "Editor", "Modified",
                "Company", "Category", "Fabricante", "Modelo", "Title", "ITAssetBunge",
                "Site", "Country", "Prateleira",
                "Status", "Hostname"
            ];
            var pick = [];
            for (var o = 0; o < IDEAL.length; o++) {
                if (cols.indexOf(IDEAL[o]) >= 0) pick.push(IDEAL[o]);
            }
            var rest = cols.filter(function (c) { return IDEAL.indexOf(c) < 0; });
            return pick.concat(rest);
        }

        function collectSelectedColumns() {
            var inputs = _doc().querySelectorAll('.rel-col:checked');
            var cols = [];
            for (var i = 0; i < inputs.length; i++) cols.push(inputs[i].value);
            // UX: "País" vem ao lado de "Site". Se Site não estiver selecionado,
            // remove Country (mesmo que esteja marcado/oculto).
            var hasSite = cols.indexOf('Site') >= 0;
            var hasCountry = cols.indexOf('Country') >= 0;
            if (!hasSite && hasCountry) {
                cols = cols.filter(function (c) { return c !== 'Country'; });
            }
            if (hasSite && !hasCountry) {
                // insere logo após Site para ficar "ao lado"
                var idx = cols.indexOf('Site');
                if (idx >= 0) cols.splice(idx + 1, 0, 'Country');
            }
            return applyExcelMetadataColumnOrder(cols);
        }

        // ===== Fonte de dados =====
        // Considera checkbox "toda base". Se marcada, sempre usa allItemsGlobal.
        // Se desmarcada, usa filteredItems (se houver) ou allItemsGlobal.
        function getExportBase() {
            var chk = _doc().getElementById('relAllBase');
            var useAll = chk && chk.checked;

            if (useAll && window.allItemsGlobal && window.allItemsGlobal.length) {
                return window.allItemsGlobal.slice();
            }
            if (window.filteredItems && window.filteredItems.length) {
                return window.filteredItems.slice();
            }
            if (window.allItemsGlobal && window.allItemsGlobal.length) {
                return window.allItemsGlobal.slice();
            }
            return [];
        }

        // ===== Filtros rápidos do modal (aplicados só se "toda base" NÃO estiver marcado) =====
        /** Enriquece Modified a partir de allItemsGlobal antes de filtrar/exportar (lista filtrada pode vir sem o campo). */
        function enrichExportRowsForDateFilter(data) {
            if (!data || !data.length) return data;
            var en = window.enrichModifiedFromGlobal;
            if (typeof en !== "function") return data;
            return data.map(function (row) { return en(row); });
        }

        function applyQuickFilters(data) {
            var ini = _doc().getElementById('relIni') ? _doc().getElementById('relIni').value : '';
            var fim = _doc().getElementById('relFim') ? _doc().getElementById('relFim').value : '';
            var status = _doc().getElementById('relStatus') ? _doc().getElementById('relStatus').value : '';

            var dtIni = ini ? parseDateOnly(ini) : null;
            var dtFim = fim ? new Date(parseDateOnly(fim).getTime() + 86399999) : null; // até 23:59:59

            var out = [];
            for (var i = 0; i < data.length; i++) {
                var item = data[i];
                var ok = true;

                // Status contém (case-insensitive)
                if (status) {
                    var itStatus = item.Status ? ('' + item.Status) : '';
                    if (itStatus.toLowerCase().indexOf(('' + status).toLowerCase()) === -1) ok = false;
                }

                // Período: conforme escolha do utilizador (Criado em = comportamento original; Modificado em = edições no intervalo).
                if (ok && (dtIni || dtFim)) {
                    function parseItemInstant(val) {
                        if (typeof parseSharePointDate === "function") {
                            var p = parseSharePointDate(val);
                            if (p && !isNaN(p.getTime())) return p;
                        }
                        if (!val) return null;
                        var d0 = new Date(val);
                        return (d0 && !isNaN(d0.getTime())) ? d0 : null;
                    }
                    var useModified = _doc().getElementById("relPeriodByModified") && _doc().getElementById("relPeriodByModified").checked;
                    var d = useModified ? parseItemInstant(item.Modified) : null;
                    if (useModified && !d) d = parseItemInstant(item.Created);
                    if (!useModified) d = parseItemInstant(item.Created);
                    if (!d) ok = false;
                    if (ok && dtIni && d < dtIni) ok = false;
                    if (ok && dtFim && d > dtFim) ok = false;
                }

                if (ok) out.push(item);
            }
            return out;
        }

        /** Ordenação do Excel: respeita #relSortBy e #relSortDir (datas com parseSharePointDate). */
        function applyExcelSort(data) {
            if (!data || !data.length) return data;
            var sel = _doc().getElementById("relSortBy");
            var dirEl = _doc().getElementById("relSortDir");
            var field = sel && sel.value ? String(sel.value) : "";
            var desc = dirEl && String(dirEl.value) === "desc";
            if (!field) return data.slice();

            function parseItemInstant(val) {
                if (typeof parseSharePointDate === "function") {
                    var p = parseSharePointDate(val);
                    if (p && !isNaN(p.getTime())) return p;
                }
                if (!val) return null;
                var d0 = new Date(val);
                return (d0 && !isNaN(d0.getTime())) ? d0 : null;
            }
            function strKey(item, f) {
                if (f === "Site") {
                    var s = item.Site ? (item.Site.Title || item.Site) : "";
                    return String(s || "");
                }
                var v = item[f];
                if (v == null) return "";
                return String(v);
            }

            var out = data.slice();
            out.sort(function (a, b) {
                if (field === "Created" || field === "Modified") {
                    var ta = parseItemInstant(a[field]);
                    var tb = parseItemInstant(b[field]);
                    var na = ta ? ta.getTime() : null;
                    var nb = tb ? tb.getTime() : null;
                    if (na == null && nb == null) return 0;
                    if (na == null) return 1;
                    if (nb == null) return -1;
                    return desc ? (nb - na) : (na - nb);
                }
                var sa = strKey(a, field);
                var sb = strKey(b, field);
                var cmp = sa.localeCompare(sb, undefined, { sensitivity: "base", numeric: true });
                return desc ? -cmp : cmp;
            });
            return out;
        }
        try { window.applyExcelSort = applyExcelSort; } catch (eS) { }

        // ===== Filtros avançados (empresa, categoria, etc.) =====
        function collectAdvancedFilters() {
            return {
                company: (_doc().getElementById('relCompany') || {}).value || "",
                category: (_doc().getElementById('relCategory') || {}).value || "",
                fabricante: (_doc().getElementById('relFabricante') || {}).value || "",
                modelo: (_doc().getElementById('relModelo') || {}).value || "",
                site: (_doc().getElementById('relSite') || {}).value || "",
                hostname: (_doc().getElementById('relHostname') || {}).value || "",
                itasset: (_doc().getElementById('relITAsset') || {}).value || "",
                author: (_doc().getElementById('relAuthor') || {}).value || "",
                onlyStock: !!((_doc().getElementById('relOnlyStock') || {}).checked)
            };
        }

        function applyAdvancedFilters(data, adv) {
            var arr = data.slice();

            // Estoque primeiro: se marcado, ignora qualquer status digitado
            if (adv.onlyStock) {
                arr = arr.filter(function (x) { return STOCK_STATUSES.indexOf(x.Status) > -1; });
            }

            if (adv.company) arr = arr.filter(function (x) { return contains(x.Company, adv.company); });
            if (adv.category) arr = arr.filter(function (x) { return contains(x.Category, adv.category); });
            if (adv.fabricante) arr = arr.filter(function (x) { return contains(x.Fabricante, adv.fabricante); });
            if (adv.modelo) arr = arr.filter(function (x) { return contains(x.Modelo, adv.modelo); });
            if (adv.site) arr = arr.filter(function (x) {
                var s = x.Site ? (x.Site.Title || x.Site) : "";
                return contains(s, adv.site);
            });
            if (adv.hostname) arr = arr.filter(function (x) { return contains(x.Hostname, adv.hostname); });
            if (adv.itasset) arr = arr.filter(function (x) { return contains(x.ITAssetBunge, adv.itasset); });
            if (adv.author) arr = arr.filter(function (x) {
                var a = x.Author ? (x.Author.Title || x.Author.Name || x.Author) : "";
                return contains(a, adv.author);
            });

            return arr;
        }

        // Preenche Modified a partir de allItemsGlobal quando o objeto da lista filtrada não traz o campo
        function enrichModifiedFromGlobal(src) {
            if (!src || !src.Id) return src;
            if (parseSharePointDate(src.Modified)) return src;
            var g = window.allItemsGlobal;
            if (!Array.isArray(g)) return src;
            for (var i = 0; i < g.length; i++) {
                var x = g[i];
                if (x && String(x.Id) === String(src.Id) && parseSharePointDate(x.Modified)) {
                    var o = {};
                    for (var k in src) {
                        if (Object.prototype.hasOwnProperty.call(src, k)) o[k] = src[k];
                    }
                    o.Modified = x.Modified;
                    return o;
                }
            }
            return src;
        }
        try { window.enrichModifiedFromGlobal = enrichModifiedFromGlobal; } catch (e) { }

        // ===== Montagem das linhas para o Excel (trata lookups) =====
        function buildExportRows(data, columns) {
            var rows = [];
            for (var i = 0; i < data.length; i++) {
                var src = (typeof window.enrichModifiedFromGlobal === "function")
                    ? window.enrichModifiedFromGlobal(data[i]) : data[i];
                var row = {};

                for (var j = 0; j < columns.length; j++) {
                    var key = columns[j];
                    var header = HEADER_LABELS[key] || key;
                    if (typeof window.t === "function") {
                        try {
                            if (key === "Modified" || key === "Created") {
                                var hk = key === "Modified" ? "colModified" : "colCreated";
                                var tv = window.t(hk);
                                if (tv && tv !== hk) header = tv;
                            } else if (key === "Author") {
                                var ta = window.t("colResponsible");
                                if (ta && ta !== "colResponsible") header = ta;
                            } else if (key === "Editor") {
                                var te = window.t("colEditor");
                                if (te && te !== "colEditor") header = te;
                            }
                        } catch (e2) { }
                    }
                    var val = '';

                    if (key === 'Site' || key === 'Site.Title') {
                        // Site é Lookup -> pegar Title
                        if (src.Site != null) {
                            if (typeof src.Site === 'object') val = (src.Site.Title != null ? src.Site.Title : '');
                            else val = src.Site; // caso venha como string
                        }
                    } else if (key === 'Country') {
                        val = getCountryForItem(src);

                    } else if (key === 'Author' || key === 'Author.Title') {
                        // Author é Lookup/Pessoa -> pegar Title/Name
                        if (src.Author != null) {
                            if (typeof src.Author === 'object') val = (src.Author.Title || src.Author.Name || '');
                            else val = src.Author;
                        }
                    } else if (key === 'Editor' || key === 'Editor.Title') {
                        // Editor é Lookup/Pessoa -> pegar Title/Name
                        if (src.Editor != null) {
                            if (typeof src.Editor === 'object') val = (src.Editor.Title || src.Editor.Name || '');
                            else val = src.Editor;
                        }

                    } else if (key === 'Created') {
                        val = formatExportDateTimeBr(src.Created);
                    } else if (key === 'Modified') {
                        val = formatExportDateTimeBr(src.Modified);

                    } else {
                        if (Object.prototype.hasOwnProperty.call(src, key) && src[key] != null) val = src[key];
                    }



                    row[header] = (val == null) ? '' : val;
                }
                rows.push(row);
            }
            return rows;
        }

        // ===== Exportação via SheetJS =====
        function exportToExcel(data, columns, fileName) {
            if (!data || !data.length) {
                alert('Não há dados para exportar.');
                return;
            }
            var rows = buildExportRows(data, columns);
            var ws = XLSX.utils.json_to_sheet(rows, { skipHeader: false });
            var wb = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(wb, ws, "Relatório");

            // Ajuste de largura simples por coluna
            var headers = [];
            for (var k in rows[0]) { if (Object.prototype.hasOwnProperty.call(rows[0], k)) headers.push(k); }
            var wscols = [];
            for (var i = 0; i < headers.length; i++) {
                var h = headers[i];
                var max = ('' + h).length;
                for (var r = 0; r < rows.length; r++) {
                    var cell = rows[r][h] == null ? '' : ('' + rows[r][h]);
                    if (cell.length > max) max = cell.length;
                }
                wscols.push({ wch: Math.min(Math.max(10, max + 2), 60) }); // 10..60
            }
            ws['!cols'] = wscols;

            XLSX.writeFile(wb, (fileName && fileName.length ? fileName : 'relatorio.xlsx'), { bookType: 'xlsx', type: 'binary' });
        }

        // ===== Popular datalists quando o modal abrir =====
        (function wireModalPopulateDatalists() {
            var modal = _doc().getElementById('modalRelatorioExcel');
            if (!modal || !window.bootstrap) return;

            modal.addEventListener('shown.bs.modal', function () {
                try {
                    try { if (typeof window.translateExcelReportModal === 'function') window.translateExcelReportModal(); } catch (e3) { }
                    // UX: ao abrir, por padrão marque todas colunas (e mantenha Country oculto no UI)
                    // - "Country" fica oculto mas será exportado (via collectSelectedColumns) quando "Site" estiver selecionado.
                    try {
                        var colsContainer = _doc().getElementById('colsContainer');
                        if (colsContainer) {
                            colsContainer.querySelectorAll('.rel-col').forEach(function (el) {
                                if (el && el.type === 'checkbox') el.checked = true;
                            });
                        }
                        var cc = _doc().getElementById('colCountry');
                        if (cc) {
                            var cell = cc.closest('#colsContainer .col-6') || cc.closest('#colsContainer .col-md-4') || cc.closest('#colsContainer div');
                            if (cell) cell.classList.add('d-none');
                        }
                        // garante que o checkbox existe e está marcado mesmo estando oculto
                        if (cc) cc.checked = true;
                    } catch (e2) { }

                    var base = getExportBase();

                    fillDatalist('relCompanyList', collectUnique(base, function (x) { return x.Company; }));
                    fillDatalist('relCategoryList', collectUnique(base, function (x) { return x.Category; }));
                    fillDatalist('relFabricanteList', collectUnique(base, function (x) { return x.Fabricante; }));
                    fillDatalist('relModeloList', collectUnique(base, function (x) { return x.Modelo; }));
                    fillDatalist('relSiteList', collectUnique(base, function (x) { return x.Site ? (x.Site.Title || x.Site) : ""; }));
                    fillDatalist('relAuthorList', collectUnique(base, function (x) { return x.Author ? (x.Author.Title || x.Author.Name || x.Author) : ""; }));
                } catch (e) {
                    console.warn("populate datalists:", e);
                }
            });

            function collectUnique(arr, getter) {
                var set = new Set();
                (arr || []).forEach(function (it) {
                    var v = getter(it);
                    if (v) set.add(String(v));
                });
                return Array.from(set).sort(function (a, b) { return norm(a).localeCompare(norm(b)); });
            }
            function fillDatalist(id, list) {
                var dl = _doc().getElementById(id);
                if (!dl) return;
                dl.innerHTML = (list || []).map(function (v) { return '<option value="' + String(v).replace(/"/g, '&quot;') + '">'; }).join('');
            }
        })();

        // ===== UI: Habilita/desabilita campos de filtro quando marcar "toda base" =====
