        // ===== Ação do botão Exportar =====
        (function wireBtnExcel() {
            var btn = _doc().getElementById('btnGerarExcel');
            if (!btn) return;

            btn.addEventListener('click', function () {
                try {
                    var base = getExportBase();
                    var periodModified = _doc().getElementById("relPeriodByModified") && _doc().getElementById("relPeriodByModified").checked;
                    var sortByField = (_doc().getElementById("relSortBy") || {}).value || "";
                    if (periodModified || sortByField === "Modified") base = enrichExportRowsForDateFilter(base);

                    // Só aplica filtros rápidos/avançados se NÃO for "toda base"
                    var chk = _doc().getElementById('relAllBase');
                    var usarFiltros = !(chk && chk.checked);

                    var dados = base;
                    if (usarFiltros) {
                        dados = applyQuickFilters(dados);
                        dados = applyAdvancedFilters(dados, collectAdvancedFilters());
                    }
                    dados = applyExcelSort(dados);

                    // Colunas
                    var cols = collectSelectedColumns();
                    if (!cols.length) {
                        alert('Selecione ao menos uma coluna.');
                        return;
                    }

                    // Nome do arquivo
                    var fnInput = _doc().getElementById('relFileName');
                    var fname = fnInput && fnInput.value ? fnInput.value : 'relatorio.xlsx';
                    if (fname.toLowerCase().indexOf('.xlsx') === -1) fname += '.xlsx';

                    exportToExcel(dados, cols, fname);
                } catch (e) {
                    console.error('Exportação Excel:', e);
                    alert('Falha ao gerar o Excel. Veja o console para detalhes.');
                }
            });
        })();

        // ===== Rodapé do modal Excel: Relatório de Estoque + Modificados no dia (mesmo padrão de #btnGerarExcel) =====
        (function wireBtnRelatorioExcelFooter() {
            var btnEstoque = _doc().getElementById('btnRelatorioEstoque');
            if (btnEstoque) {
                btnEstoque.addEventListener('click', function () {
                    try {
                        var base = getExportBase();
                        var sortByStock = (_doc().getElementById("relSortBy") || {}).value || "";
                        if (sortByStock === "Modified") base = enrichExportRowsForDateFilter(base);

                        // Força filtro de estoque independentemente de "toda base"
                        var dados = base.filter(function (x) { return STOCK_STATUSES.indexOf(x.Status) > -1; });

                        // Aplica também filtros avançados opcionais (exceto status, pois já forçamos estoque)
                        var adv = collectAdvancedFilters();
                        adv.onlyStock = true; // garante estoque
                        dados = applyAdvancedFilters(dados, adv);
                        dados = applyExcelSort(dados);

                        var cols = collectSelectedColumns();
                        if (!cols.length) {
                            alert('Selecione ao menos uma coluna.');
                            return;
                        }

                        exportToExcel(dados, cols, 'relatorio_estoque.xlsx');
                    } catch (e) {
                        console.error('Relatório de Estoque:', e);
                        alert('Falha ao gerar o Relatório de Estoque.');
                    }
                });
            }

            var btnModDia = _doc().getElementById('btnRelatorioModificadosDia');
            if (btnModDia) {
                btnModDia.addEventListener('click', function () {
                    try {
                        function parseMod(val) {
                            if (typeof window.parseSharePointDate === "function") return window.parseSharePointDate(val);
                            if (!val) return null;
                            var d = new Date(val);
                            return isNaN(d.getTime()) ? null : d;
                        }
                        function msg(key, fallback) {
                            return (typeof window.t === "function" ? window.t(key) : fallback);
                        }

                        var iniVal = (_doc().getElementById("relIni") || {}).value || "";
                        var fimVal = (_doc().getElementById("relFim") || {}).value || "";
                        if (!String(iniVal).trim() && !String(fimVal).trim()) {
                            alert(msg("excelModifiedNeedPeriod", "Informe Período (De) e/ou Período (Até) para o relatório Modificados."));
                            return;
                        }

                        var dtIni = iniVal ? parseDateOnly(iniVal) : null;
                        var dtFim = fimVal ? new Date(parseDateOnly(fimVal).getTime() + 86399999) : null;

                        var base = enrichExportRowsForDateFilter(getExportBase() || []);

                        // Sempre por Modificado em (sem usar Created no intervalo nem como fallback de inclusão)
                        var dados = base.filter(function (x) {
                            if (!x) return false;
                            var d = parseMod(x.Modified);
                            if (!d || isNaN(d.getTime())) return false;
                            if (dtIni && d < dtIni) return false;
                            if (dtFim && d > dtFim) return false;
                            return true;
                        });

                        dados = applyAdvancedFilters(dados, collectAdvancedFilters());
                        dados = applyExcelSort(dados);

                        var cols = collectSelectedColumns();
                        if (!cols.length) {
                            alert(msg("excelSelectOneColumn", "Selecione ao menos uma coluna."));
                            return;
                        }
                        if (!dados.length) {
                            alert(msg("toastModifiedReportEmpty", "Nenhum item com Modificado em no período e filtros atuais."));
                            return;
                        }

                        exportToExcel(dados, cols, 'relatorio_modificados.xlsx');
                    } catch (e) {
                        console.error('Relatório Modificados:', e);
                        alert((typeof window.t === "function" ? window.t("toastModifiedReportError") : 'Falha ao gerar o relatório Modificados.'));
                    }
                });
            }
        })();



        // Foto do usuário In Use
        function getUserPhotoUrl(email, size) {
            size = size || "S"; // S, M, L
            return "https://bungeltd.sharepoint.com/_layouts/15/userphoto.aspx?size=" + size +
                "&accountname=" + encodeURIComponent(email || "");
        }
        function computeInitials(name) {
            name = (name || "").trim();
            if (!name) return "";
            var p = name.split(/\s+/);
            return ((p[0] && p[0][0]) || "").toUpperCase() + ((p[p.length - 1] && p[p.length - 1][0]) || "").toUpperCase();
        }
        function firstPersonField(p) {
            if (!p) return null;
            return (p.results && p.results.length) ? p.results[0] : p;
        }

        // ===== Anexos: helpers =====
        function escHtml(s) {
            return String(s || '').replace(/[&<>"']/g, c => (
                { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]
            ));
        }

        // Converte ServerRelativeUrl (ex: "/sites/fieldservices/...") em URL absoluta
        function absUrlFromServerRelative(u) {
            if (!u) return "#";
            if (/^https?:\/\//i.test(u)) return u;           // já é absoluta
            const rel = u.startsWith("/") ? u : "/" + u;
            return location.origin + rel;                     // evita duplicar /sites/...
        }

        async function loadAttachmentsList(itemId) {
            const ul = _doc().getElementById("attachList");
            if (!ul) return;

            if (!itemId) {
                ul.innerHTML = '<li class="list-group-item text-muted">Salve o item para anexar arquivos.</li>';
                return;
            }

            ul.innerHTML = '<li class="list-group-item text-muted">Carregando...</li>';

            try {
                const url = `${apiUrl}(${itemId})/AttachmentFiles?$select=FileName,ServerRelativeUrl,Length,TimeCreated`;
                const resp = await fetch(url, { headers: { "Accept": "application/json;odata=verbose" } });
                if (!resp.ok) throw new Error(await resp.text());
                const data = await resp.json();
                const files = (data && data.d && data.d.results) ? data.d.results : [];

                if (!files.length) {
                    ul.innerHTML = '<li class="list-group-item text-muted">Nenhum anexo</li>';
                    return;
                }

                ul.innerHTML = "";
                files.forEach(f => {
                    const li = _doc().createElement("li");
                    li.className = "list-group-item d-flex justify-content-between align-items-center";

                    const left = _doc().createElement("div");
                    left.className = "d-flex flex-column";

                    const a = _doc().createElement("a");
                    a.href = absUrlFromServerRelative(f.ServerRelativeUrl);
                    a.target = "_blank";
                    a.rel = "noopener";
                    a.textContent = f.FileName;

                    // meta (opcional): tamanho e data
                    const meta = _doc().createElement("small");
                    const sizeStr = (typeof f.Length === "number") ? ` • ${(f.Length / 1024).toFixed(1)} KB` : "";
                    const dateStr = f.TimeCreated ? ` • ${new Date(f.TimeCreated).toLocaleString()}` : "";
                    meta.className = "text-muted";
                    meta.textContent = `${sizeStr}${dateStr}`;

                    left.appendChild(a);
                    if (sizeStr || dateStr) left.appendChild(meta);

                    li.appendChild(left);
                    ul.appendChild(li);
                });
            } catch (e) {
                console.error("loadAttachmentsList:", e);
                ul.innerHTML = '<li class="list-group-item text-danger">Falha ao carregar anexos</li>';
            }
        }

        // Mostrar anexo no overlay (iframe acima do modal de detalhes)
        function showAttachmentInOverlay(serverRelativeUrl, fileName) {
            var overlay = _doc().getElementById("attachmentPreviewOverlay");
            var iframe = _doc().getElementById("attachmentPreviewIframe");
            var titleEl = _doc().getElementById("attachmentPreviewTitle");
            if (!overlay || !iframe) return;
            var url = absUrlFromServerRelative(serverRelativeUrl);
            iframe.src = url;
            if (titleEl) titleEl.textContent = fileName || "Anexo";
            overlay.classList.remove("d-none");
        }

        function hideAttachmentOverlay() {
            var overlay = _doc().getElementById("attachmentPreviewOverlay");
            var iframe = _doc().getElementById("attachmentPreviewIframe");
            if (overlay) overlay.classList.add("d-none");
            if (iframe) iframe.src = "about:blank";
        }

        (function bindAttachmentOverlayClose() {
            _doc().addEventListener("click", function (ev) {
                if (ev.target && ev.target.id === "attachmentPreviewClose") {
                    ev.preventDefault();
                    hideAttachmentOverlay();
                }
            });
        })();

        async function loadAttachmentsForRecordModal(itemId) {
            var container = _doc().getElementById("recordModalAttachSection");
            if (!container) return;

            var _t = (typeof window.t === "function") ? window.t : function (k) { return k; };

            try {
                var url = (typeof apiUrl === "undefined" ? "" : apiUrl) + "(" + itemId + ")/AttachmentFiles?$select=FileName,ServerRelativeUrl,Length,TimeCreated";
                var resp = await fetch(url, { headers: { "Accept": "application/json;odata=verbose" } });
                if (!resp.ok) throw new Error(await resp.text());
                var data = await resp.json();
                var files = (data && data.d && data.d.results) ? data.d.results : [];
                files.sort(function (a, b) {
                    var ta = a.TimeCreated ? new Date(a.TimeCreated).getTime() : 0;
                    var tb = b.TimeCreated ? new Date(b.TimeCreated).getTime() : 0;
                    return tb - ta;
                });
            } catch (e) {
                console.error("loadAttachmentsForRecordModal:", e);
                container.innerHTML = '<span class="text-danger">Falha ao carregar anexos</span>';
                return;
            }

            if (!files.length) {
                container.innerHTML = '<span class="text-muted">' + (_t("noAttachments") || "Nenhum anexo") + '</span>';
                return;
            }

            var newest = files[0];
            var older = files.slice(1);
            var html = '';

            html += '<div class="mb-2">';
            html += '<span class="d-inline-block me-2">' + escHtml(newest.FileName) + '</span>';
            html += '<button type="button" class="btn btn-sm btn-outline-primary" data-attach-view data-url="' + escHtml(newest.ServerRelativeUrl || "") + '" data-name="' + escHtml(newest.FileName || "") + '">Visualizar</button>';
            html += '</div>';

            if (older.length) {
                html += '<div><button type="button" class="btn btn-sm btn-link p-0" id="btnShowOlderAttachments" data-older=\'' + JSON.stringify(older.map(function (f) { return { FileName: f.FileName, ServerRelativeUrl: f.ServerRelativeUrl }; })) + '\'>Ver ' + older.length + ' anexo(s) anterior(es)</button></div>';
            }

            container.innerHTML = html;

            var viewBtn = container.querySelector("[data-attach-view]");
            if (viewBtn) {
                viewBtn.addEventListener("click", function () {
                    showAttachmentInOverlay(viewBtn.getAttribute("data-url"), viewBtn.getAttribute("data-name"));
                });
            }

            var btnOlder = _doc().getElementById("btnShowOlderAttachments");
            if (btnOlder && older.length) {
                btnOlder.addEventListener("click", function () {
                    var listEl = _doc().getElementById("olderAttachmentsList");
                    var modalEl = _doc().getElementById("modalOlderAttachments");
                    if (!listEl || !modalEl) return;
                    try {
                        var list = JSON.parse(btnOlder.getAttribute("data-older") || "[]");
                        listEl.innerHTML = "";
                        list.forEach(function (f) {
                            var li = _doc().createElement("li");
                            li.className = "list-group-item list-group-item-action";
                            li.textContent = f.FileName;
                            li.setAttribute("data-url", f.ServerRelativeUrl || "");
                            li.setAttribute("data-name", f.FileName || "");
                            li.style.cursor = "pointer";
                            li.addEventListener("click", function () {
                                showAttachmentInOverlay(f.ServerRelativeUrl, f.FileName);
                                try {
                                    var bsModal = bootstrap.Modal.getInstance(modalEl);
                                    if (bsModal) bsModal.hide();
                                } catch (e) { }
                            });
                            listEl.appendChild(li);
                        });
                        new bootstrap.Modal(modalEl).show();
                    } catch (err) { console.error(err); }
                });
            }
        }

        async function uploadSelectedAttachments(itemId) {
            const input = _doc().getElementById("attachInput");
            if (!input || !input.files || !input.files.length) {
                showToast("Selecione um ou mais arquivos.", "warning");
                return;
            }
            if (!itemId) {
                showToast("Salve o item antes de anexar arquivos.", "warning");
                return;
            }

            const digest = await getRequestDigest();
            let ok = 0, fail = 0;

            for (const file of input.files) {
                try {
                    // SP exige duplicar apóstrofos dentro das aspas simples
                    const safeFileName = file.name.replace(/'/g, "''");
                    // usa encodeURIComponent para nomes com espaços/caracteres especiais
                    const endpoint = `${apiUrl}(${itemId})/AttachmentFiles/add(FileName='${encodeURIComponent(safeFileName)}')`;

                    const resp = await fetch(endpoint, {
                        method: "POST",
                        headers: {
                            "Accept": "application/json;odata=verbose",
                            "Content-Type": "application/octet-stream",
                            "X-RequestDigest": digest
                        },
                        body: await file.arrayBuffer()
                    });
                    if (!resp.ok) throw new Error(await resp.text());
                    ok++;
                } catch (err) {
                    console.error("uploadSelectedAttachments:", err);
                    fail++;
                }
            }

            if (ok) showToast(`${ok} arquivo(s) enviado(s) com sucesso.`, "success");
            if (fail) showToast(`${fail} arquivo(s) falharam ao enviar.`, "danger");

            input.value = "";
            await loadAttachmentsList(itemId);
        }

        // Inicializa área de anexos conforme existir/for edição
        function setupAttachmentsUI(itemId) {
            const grp = _doc().getElementById("attachmentsGroup");
            const info = _doc().getElementById("attachmentsInfoNew");
            const btn = _doc().getElementById("btnUploadAttach");
            const list = _doc().getElementById("attachList");

            if (!grp || !info) return;

            if (itemId) {
                info.classList.add("d-none");
                grp.classList.remove("d-none");
                if (list) list.innerHTML = "";
                loadAttachmentsList(itemId);

                if (btn && !btn._bound) {
                    btn.addEventListener("click", () => {
                        const id = parseInt(_doc().getElementById("hiddenItemId").value, 10);
                        uploadSelectedAttachments(id);
                    });
                    btn._bound = true;
                }
            } else {
                grp.classList.add("d-none");
                info.classList.remove("d-none");
                if (list) list.innerHTML = "";
            }
        }

        // Novo - Sincronizador

        /* ==========================================================
         DELTA SYNC — Busca só o que mudou e trata deleções
         MASTER = window.allItemsGlobal (nunca currentItemsList)
         UI final = afterSyncRefresh(window.allItemsGlobal)
         ========================================================== */

        (function () {
            var INCR_SELECT =
                "Id,Title,Company,Category,Fabricante,Modelo,ITAssetBunge,Prateleira,Status,Hostname,Comments,Created,Modified," +
                "Author/Title,Site/Id,Site/Title,NotaFiscal,DataNota,NrRemessa,DataRemessa,OCPO," +
                "AssignedTo/Id,AssignedTo/Title,AssignedTo/EMail";
            var INCR_EXPAND = "Author,Site,AssignedTo";
            var LAST_SYNC_KEY = "delta_last_sync_iso";

            if (!Array.isArray(window.allItemsGlobal)) window.allItemsGlobal = [];
            var indexMap = null;

            function rebuildIndex() {
                indexMap = {};
                var list = window.allItemsGlobal || [];
                for (var i = 0; i < list.length; i++) {
                    var it = list[i];
                    if (it && typeof it.Id !== "undefined") indexMap[String(it.Id)] = i;
                }
            }
            rebuildIndex();

            function safeToast(msg, type) {
                try { if (typeof showToast === "function") showToast(msg, type || "info"); } catch (e) { }
            }

            function getLastSyncIso() {
                try { return localStorage.getItem(LAST_SYNC_KEY) || null; } catch (e) { return null; }
            }
            function setLastSyncIso(iso) {
                if (!iso) return;
                try { localStorage.setItem(LAST_SYNC_KEY, iso); } catch (e) { }
            }

            var listBaseUrl = (typeof apiUrl === "string") ? apiUrl.replace(/\/items[\s\S]*$/i, "") : "";
            function getHeartbeat() {
                var url = listBaseUrl + "?$select=LastItemModifiedDate,ItemCount";
                return fetch(url, { headers: { "Accept": "application/json;odata=verbose" } })
                    .then(function (r) { if (!r.ok) throw new Error("HB " + r.status); return r.json(); })
                    .then(function (data) {
                        var d = data && data.d;
                        return {
                            lastItemModifiedDate: (d && d.LastItemModifiedDate) || null,
                            itemCount: (d && d.ItemCount) || 0
                        };
                    });
            }

            function fetchPaged(startUrl) {
                var acc = [];
                function step(nextUrl) {
                    return fetch(nextUrl, { headers: { "Accept": "application/json;odata=verbose" } })
                        .then(function (r) { if (!r.ok) throw new Error("HTTP " + r.status); return r.json(); })
                        .then(function (data) {
                            var d = data && data.d;
                            var results = (d && d.results) ? d.results : [];
                            acc = acc.concat(results);
                            var nx = d && d.__next;
                            if (nx) return step(nx);
                            return acc;
                        });
                }
                return step(startUrl);
            }

            function fetchDeltaSince(lastIso) {
                var url = apiUrl
                    + "?$select=" + encodeURIComponent(INCR_SELECT)
                    + "&$expand=" + encodeURIComponent(INCR_EXPAND)
                    + "&$orderby=Modified asc"
                    + "&$filter=" + encodeURIComponent("Modified gt datetime'" + lastIso + "'")
                    + "&$top=5000";
                return fetchPaged(url);
            }

            function fetchAllIds() {
                var url = apiUrl + "?$select=Id&$orderby=Id asc&$top=5000";
                return fetchPaged(url).then(function (items) {
                    var set = {};
                    for (var i = 0; i < items.length; i++) {
                        var it = items[i];
                        if (it && typeof it.Id !== "undefined") set[String(it.Id)] = true;
                    }
                    return set;
                });
            }

            function mergeById(delta) {
                if (!delta || !delta.length) return { inserted: 0, updated: 0 };
                if (!indexMap) rebuildIndex();

                var ins = 0, upd = 0;
                for (var i = 0; i < delta.length; i++) {
                    var it = delta[i];
                    try { it = normalizeItemSystemFields(it); } catch (eIt) { }
                    var id = it && it.Id;
                    if (id == null) continue;

                    var key = String(id);
                    if (indexMap.hasOwnProperty(key)) {
                        window.allItemsGlobal[indexMap[key]] = it;
                        upd++;
                    } else {
                        indexMap[key] = window.allItemsGlobal.length;
                        window.allItemsGlobal.push(it);
                        ins++;
                    }
                }
                return { inserted: ins, updated: upd };
            }

            function removeIdsNotIn(existingIdsDict) {
                if (!existingIdsDict) return 0;
                var removed = 0;

                var oldList = window.allItemsGlobal || [];
                var newList = [];
                for (var i = 0; i < oldList.length; i++) {
                    var it = oldList[i];
                    var keep = it && typeof it.Id !== "undefined" && existingIdsDict[String(it.Id)];
                    if (keep) newList.push(it); else removed++;
                }

                if (removed > 0) {
                    window.allItemsGlobal = newList;
                    rebuildIndex();
                }
                return removed;
            }

            function uniqueLocalCount() {
                var seen = {};
                var list = window.allItemsGlobal || [];
                var c = 0;
                for (var i = 0; i < list.length; i++) {
                    var it = list[i];
                    var id = it && (it.Id != null ? it.Id : it.ID);
                    if (id == null) continue;

                    var k = String(id);
                    if (!seen[k]) { seen[k] = true; c++; }
                }
                return c;
            }

            function doIncrementalSync(trigger, uiHooks) {
                uiHooks = uiHooks || {};
                var onStart = uiHooks.onStart || function () { };
                var onStop = uiHooks.onStop || function () { };
                var setStatus = uiHooks.setStatus || function () { };
                function _tr(key, vars) {
                    if (typeof window.t === "function") return window.t(key, vars);
                    return key;
                }

                onStart();
                setStatus(_tr("syncVerifyingChanges", { trigger: trigger || "delta" }));

                var hadList = Array.isArray(window.allItemsGlobal) && window.allItemsGlobal.length > 0;
                var lastIso = getLastSyncIso();

                try { rebuildIndex(); } catch (e) { }

                return getHeartbeat().then(function (hb) {

                    // guard lastIso
                    try {
                        if (lastIso && hb && hb.lastItemModifiedDate && String(lastIso) > String(hb.lastItemModifiedDate)) {
                            setStatus(_tr("syncLastIsoInvalid"));
                            try { localStorage.removeItem(LAST_SYNC_KEY); } catch (e) { }
                            lastIso = "";
                        }
                    } catch (e) { }

                    // FULL inicial
                    if (!hadList || !lastIso) {
                        setStatus(!hadList ? _tr("syncFirstLoad") : _tr("syncFirstFull"));

                        return Promise.resolve()
                            .then(function () {
                                if (typeof fetchAllItems !== "function") throw new Error("fetchAllItems() não encontrado");
                                return fetchAllItems();
                            })
                            .then(async function (items) {
                                // ✅ SET MASTER protegido
                                scSetMasterItems(items || [], "deltaSync/FULL");

                                // ordena master
                                try {
                                    (window.allItemsGlobal || []).sort(function (a, b) {
                                        var da = a && a.Created ? Date.parse(a.Created) : 0;
                                        var db = b && b.Created ? Date.parse(b.Created) : 0;
                                        return (db || 0) - (da || 0);
                                    });
                                } catch (e) { }

                                try { rebuildIndex(); } catch (e) { }

                                // UI final 1x
                                if (typeof afterSyncRefresh === "function") afterSyncRefresh(window.allItemsGlobal);

                                if (hb && hb.lastItemModifiedDate) setLastSyncIso(hb.lastItemModifiedDate);

                                try { if (typeof scPersistCache === "function") await scPersistCache(); } catch (e) { }

                                setStatus(!hadList ? _tr("syncUpdatedInitial") : _tr("syncUpdatedFullInitial"));
                                safeToast(!hadList ? _tr("syncDataLoaded") : _tr("syncFullInitialOk"), "success");
                            })
                            .catch(function (err) {
                                setStatus(_tr("syncFullFail"));
                                safeToast(_tr("syncFailFullDetail", { msg: (err && err.message ? err.message : String(err)) }), "danger");
                            })
                            .finally(onStop);
                    }

                    // DELTA
                    setStatus(_tr("syncDownloadingSince", { iso: lastIso }));

                    return fetchDeltaSince(lastIso)
                        .then(function (delta) {
                            delta = delta || [];

                            var maxModified = lastIso;
                            for (var i = 0; i < delta.length; i++) {
                                var m = delta[i] && delta[i].Modified;
                                if (m && String(m) > String(maxModified)) maxModified = String(m);
                            }

                            var stats = mergeById(delta);

                            var localCount = uniqueLocalCount();
                            var promised = Promise.resolve(0);

                            if (hb && typeof hb.itemCount === "number" && hb.itemCount < localCount) {
                                setStatus(_tr("syncDeletionsDetected"));
                                promised = fetchAllIds().then(function (idsDict) {
                                    return removeIdsNotIn(idsDict);
                                });
                            }

                            return promised.then(async function (removed) {
                                // ordena master
                                try {
                                    (window.allItemsGlobal || []).sort(function (a, b) {
                                        var da = a && a.Created ? Date.parse(a.Created) : 0;
                                        var db = b && b.Created ? Date.parse(b.Created) : 0;
                                        return (db || 0) - (da || 0);
                                    });
                                } catch (e) { }

                                try { rebuildIndex(); } catch (e) { }

                                // UI final 1x
                                if (typeof afterSyncRefresh === "function") afterSyncRefresh(window.allItemsGlobal);

                                try { if (typeof scPersistCache === "function") await scPersistCache(); } catch (e) { }

                                if (delta.length > 0 && maxModified) setLastSyncIso(maxModified);
                                else if (hb && hb.lastItemModifiedDate) setLastSyncIso(hb.lastItemModifiedDate);

                                var msg = [];
                                if (stats.inserted) msg.push(_tr("syncStatInserted", { n: stats.inserted }));
                                if (stats.updated) msg.push(_tr("syncStatUpdated", { n: stats.updated }));
                                if (removed) msg.push(_tr("syncStatRemoved", { n: removed }));

                                var summary = msg.join(", ");
                                setStatus(msg.length ? _tr("syncDeltaStatus", { summary: summary }) : _tr("syncNoChanges"));
                                if (msg.length) safeToast(_tr("syncToastSummary", { summary: summary }), "success");
                            });
                        })
                        .catch(function (err) {
                            setStatus(_tr("syncDeltaFail"));
                            safeToast(_tr("syncFailDeltaDetail", { msg: (err && err.message ? err.message : String(err)) }), "danger");
                        })
                        .finally(onStop);

                }).catch(function (err) {
                    setStatus(_tr("syncHeartbeatFail"));
                    safeToast(_tr("syncFailHbDetail", { msg: (err && err.message ? err.message : String(err)) }), "danger");
                    onStop();
                });
            }

            window._deltaSync = { run: doIncrementalSync };
        })();

        (function () {
            // ===== Helpers de UI (definidos só se não existirem) =====
            function _q(id) { return _doc().getElementById(id); }

            if (typeof window.setStatus !== "function") {
                window.setStatus = function (t) {
                    var s = _doc().getElementById("syncStatus");
                    if (!s) return;
                    var txt = (t || "").toString();
                    s.textContent = txt;
                    s.title = txt; // hover mostra o texto completo
                };
            }
            if (typeof window.startSpin !== "function") {

                window.startSpin = function () {
                    var ic = _doc().getElementById("syncIcon");
                    var bt = _doc().getElementById("btnSyncNow");
                    if (ic) ic.classList.add("spin");      // só adiciona a classe spin
                    if (bt) bt.disabled = true;
                };

            }
            if (typeof window.stopSpin !== "function") {

                window.stopSpin = function () {
                    var ic = _doc().getElementById("syncIcon");
                    var bt = _doc().getElementById("btnSyncNow");
                    if (ic) ic.classList.remove("spin");   // só remove a classe spin
                    if (bt) bt.disabled = false;
                };

            }

            // Spinner CSS (leve)
            try {
                var st = _doc().createElement("style");

                st.textContent =
                    ".spin{display:inline-block;transform-origin:50% 50%;animation:spin .9s linear infinite}" +
                    "@keyframes spin{to{transform:rotate(360deg)}}";

                _doc().head.appendChild(st);
            } catch (e) { }

            // ===== Fallback: full sync usando sua função existente =====
            function fullSyncFallback(trigger) {
                if (typeof fetchAllItems !== "function") {
                    console.warn("fetchAllItems() não encontrado.");
                    alert(typeof window.t === "function" ? window.t("fetchAllNotFound") : "fetchAllItems() não encontrado.");
                    return;
                }
                startSpin();
                setStatus(typeof window.t === "function" ? window.t("syncUpdating", { trigger: trigger || "manual" }) : ("Atualizando (" + (trigger || "manual") + ")…"));

                var p;
                try { p = fetchAllItems(); } catch (e) { console.error(e); stopSpin(); return; }

                p.then(function (items) {
                    try {
                        if (typeof updateLatestItems === "function") {
                            updateLatestItems(items);
                        } else if (typeof renderLatestItems === "function") {
                            if (typeof window.currentItemsList !== "undefined") window.currentItemsList = items;
                            renderLatestItems();
                        }
                    } catch (e) { }
                    setStatus(typeof window.t === "function" ? window.t("syncUpdatedNow") : "Atualizado agora");
                    try { if (typeof showToast === "function") showToast((typeof window.t === "function" ? window.t("syncDataSyncedToast") : "Dados sincronizados."), "success"); } catch (e) { }
                }, function (err) {
                    console.error(err);
                    setStatus(typeof window.t === "function" ? window.t("syncFail") : "Falha ao sincronizar");
                    try { if (typeof showToast === "function") showToast((typeof window.t === "function" ? window.t("syncFailShortDetail", { msg: (err && err.message ? err.message : String(err)) }) : ("Falha na sincronização: " + (err && err.message ? err.message : err))), "danger"); } catch (e) { }
                }).then(function () { stopSpin(); });
            }

            // ===== Forçar sync: delta se disponível, senão full =====
            // ✅ Lock global para impedir sync duplicado (manual+auto, double click etc.)
            window.__scSyncPromise = window.__scSyncPromise || null;

            window.forceSync = function (trigger) {
                try {
                    // Se já tem sync rodando, reaproveita (não dispara outro)
                    if (window.__scSyncPromise) return window.__scSyncPromise;

                    if (window._deltaSync && typeof _deltaSync.run === "function") {
                        window.__scSyncPromise = _deltaSync.run(trigger || "manual", {
                            onStart: startSpin,
                            onStop: stopSpin,
                            setStatus: setStatus
                        }).finally(function () {
                            window.__scSyncPromise = null;
                        });

                        return window.__scSyncPromise;
                    }

                    // fallback full
                    fullSyncFallback(trigger || "manual");
                } catch (e) {
                    console.error("forceSync erro:", e);
                    setStatus(typeof window.t === "function" ? window.t("syncError") : "Erro ao sincronizar");
                    stopSpin();
                    window.__scSyncPromise = null;
                }
            };

            // ===== Wire defensivo (se o onclick não pegar por algum motivo) =====
            (function wireBtn() {
                var btn = _q("btnSyncNow");
                if (btn) {
                    if (!btn._wired) {
                        btn._wired = true;
                        btn.addEventListener("click", function () { forceSync("manual"); });
                    }
                } else {
                    // tenta de novo por alguns ciclos, caso o HTML carregue depois
                    setTimeout(wireBtn, 300);
                }
            })();

            // ===== Auto: se quiser já testar na carga, descomente =====
            // forceSync("startup");
        })();


        (function () {
            var KEY = "autoSyncSeconds"; // mesmo usado pelo seu auto-sync
            var btn = _doc().getElementById("btnAutoSync");
            var menu = _doc().getElementById("syncControls");

            function formatAutoLabel(secs) {
                if (typeof window.scFormatAutoLabel === "function") return window.scFormatAutoLabel(secs);
                secs = Number(secs) || 0;
                if (secs <= 0) return "Auto OFF";
                if (secs % 60 === 0) {
                    var m = secs / 60;
                    return "Auto " + (m === 1 ? "1 min" : (m + " min"));
                }
                return "Auto " + secs + " s";
            }

            function highlightActive(secs) {
                if (!menu) return;
                var items = menu.querySelectorAll("[data-sync-every]");
                for (var i = 0; i < items.length; i++) {
                    var val = parseInt(items[i].getAttribute("data-sync-every"), 10);
                    if (isNaN(val)) val = 0;
                    if (val === (Number(secs) || 0)) items[i].classList.add("active");
                    else items[i].classList.remove("active");
                }
            }

            function setButtonLabel(secs) {
                if (btn) btn.innerText = formatAutoLabel(secs);
                highlightActive(secs);
            }

            function getSaved() {
                try {
                    var v = parseInt(localStorage.getItem(KEY), 10);
                    if (isNaN(v)) return 0;
                    return v;
                } catch (e) { return 0; }
            }

            // Inicializa rótulo com o valor salvo
            setButtonLabel(getSaved());

            // Quando escolher uma opção, atualiza rótulo imediatamente
            if (menu) {
                menu.addEventListener("click", function (ev) {
                    var a = ev.target && ev.target.closest ? ev.target.closest("[data-sync-every]") : null;
                    if (!a) return; // ignora itens sem data-sync-every, ex.: "Tela cheia"
                    var secs = parseInt(a.getAttribute("data-sync-every"), 10);
                    if (isNaN(secs)) secs = 0;
                    // reflete no botão
                    setButtonLabel(secs);
                    // também salva (o seu applyAutoSync já salva, mas garantimos aqui)
                    try { localStorage.setItem(KEY, String(secs)); } catch (e) { }
                });
            }
        })();

/* ---- next block ---- */

(function () {
            var KEY = "autoSyncSeconds";          // mesma chave usada pela UI
            var DEFAULT_SECS = 0; // OFF por padrão
            var autoTimer = null;

            function _q(id) { return _doc().getElementById(id); }
            function _safeToast(m, t) { try { if (typeof showToast === "function") showToast(m, t || "info"); } catch (e) { } }
            function _setStatus(txt) { try { if (typeof setStatus === "function") setStatus(txt); } catch (e) { } }

            function formatAutoLabel(secs) {
                if (typeof window.scFormatAutoLabel === "function") return window.scFormatAutoLabel(secs);
                secs = Number(secs) || 0;
                if (secs <= 0) return "Auto OFF";
                if (secs % 60 === 0) { var m = secs / 60; return "Auto " + (m === 1 ? "1 min" : (m + " min")); }
                return "Auto " + secs + " s";
            }
            function setAutoButtonLabel(secs) {
                var btn = _q("btnAutoSync");
                if (btn) btn.innerText = formatAutoLabel(secs);
                // marca opção ativa no menu
                var menu = _q("syncControls");
                if (menu) {
                    var items = menu.querySelectorAll("[data-sync-every]");
                    for (var i = 0; i < items.length; i++) {
                        var v = parseInt(items[i].getAttribute("data-sync-every"), 10); if (isNaN(v)) v = 0;
                        if (v === (Number(secs) || 0)) items[i].classList.add("active"); else items[i].classList.remove("active");
                    }
                }
            }

            // ==== dispara a sincronização (delta -> full fallback) ====
            function tickSync() {
                try {
                    if (typeof forceSync === "function") { forceSync("auto"); return; }
                    if (window._deltaSync && typeof _deltaSync.run === "function") {
                        _deltaSync.run("auto", {
                            onStart: (window.startSpin || function () { }),
                            onStop: (window.stopSpin || function () { }),
                            setStatus: (window.setStatus || function () { })
                        });
                        return;
                    }
                    // fallback full
                    if (typeof fetchAllItems === "function") {
                        (window.startSpin || function () { })();
                        _setStatus(typeof window.t === "function" ? window.t("syncUpdatingAuto") : "Atualizando (auto)...");
                        fetchAllItems().then(function (items) {
                            if (typeof updateLatestItems === "function") updateLatestItems(items);
                            else if (typeof renderLatestItems === "function") {
                                if (typeof window.currentItemsList !== "undefined") window.currentItemsList = items;
                                renderLatestItems();
                            }
                            _setStatus(typeof window.t === "function" ? window.t("syncUpdatedNow") : "Atualizado agora");
                        }).catch(function (e) {
                            console.error(e); _setStatus(typeof window.t === "function" ? window.t("syncFail") : "Falha ao sincronizar");
                        }).then(function () { (window.stopSpin || function () { })(); });
                    }
                } catch (e) { console.error("tickSync:", e); }
            }

            // ==== cria/renova o intervalo ====
            // ALTERE esta função (acrescenta opts.skipImmediate)
            function setAutoSyncSeconds(secs, announce, opts) {
                opts = opts || {};
                secs = Number(secs) || 0;
                try { localStorage.setItem(KEY, String(secs)); } catch (e) { }
                setAutoButtonLabel(secs);
                if (autoTimer) { clearInterval(autoTimer); autoTimer = null; }

                if (secs > 0) {
                    var intv = secs % 60 === 0 ? (String(secs / 60) + " min") : (String(secs) + " s");
                    _setStatus((typeof window.t === "function" ? window.t("syncAutoEveryStatus", { interval: intv }) : ("Auto-sync a cada " + intv)));
                    if (announce) _safeToast((typeof window.t === "function" ? window.t("autoSyncOnToast", { label: formatAutoLabel(secs) }) : ("Auto-sync ligado: " + formatAutoLabel(secs))), "info");
                    // >>> não roda a primeira sincronização quando skipImmediate=true
                    if (!opts.skipImmediate) tickSync();
                    autoTimer = setInterval(function () { /* if (document.hidden) return; */ tickSync(); }, secs * 1000);
                } else {
                    _setStatus((typeof window.t === "function" ? window.t("syncAutoOffStatus") : "Auto-sync desligado"));
                    if (announce) _safeToast((typeof window.t === "function" ? window.t("autoSyncOffToast") : "Auto-sync desligado"), "warning");
                }
            }

            // ==== liga o clique do menu para acionar o motor ====
            var controls = _q("syncControls");
            if (controls) {
                controls.addEventListener("click", function (ev) {
                    var a = ev.target && ev.target.closest ? ev.target.closest("[data-sync-every]") : null;
                    if (!a) return;
                    var secs = parseInt(a.getAttribute("data-sync-every"), 10);
                    if (isNaN(secs)) secs = 0;

                    // ✅ Não sincroniza agora. Só agenda para daqui 'secs'
                    setAutoSyncSeconds(secs, true, { skipImmediate: true });
                });
            }


            // BOOT: aplique sem sincronizar agora
            var saved = parseInt((function () { try { return localStorage.getItem(KEY); } catch (e) { return null; } })(), 10);
            if (isNaN(saved)) saved = DEFAULT_SECS;
            // Chave para ligar e desligar o auto sync inicial
            setAutoSyncSeconds(saved, false, { skipImmediate: true });  // <<--- chave do ajuste

            // expõe para uso externo, se precisar mudar via código
            window.setAutoSyncSeconds = setAutoSyncSeconds;
        })();

