// Ordena por Created (desc)
        function _sortByCreatedDesc(arr) {
            try {
                arr.sort(function (a, b) {
                    var da = a && a.Created ? new Date(a.Created) : 0;
                    var db = b && b.Created ? new Date(b.Created) : 0;
                    return db - da;
                });
            } catch (e) { }
            return arr;
        }

        // Dedupe robusto por Id/ID (evita inflar cards)
        function _dedupeById(arr) {
            var seen = {}, out = [], i, n = arr.length;
            for (i = 0; i < n; i++) {
                var it = arr[i]; if (!it) continue;
                var k = (it.Id != null) ? ("id:" + it.Id) : (it.ID != null ? ("ID:" + it.ID) : null);
                if (k && seen[k]) continue;
                if (k) seen[k] = 1;
                out.push(it);
            }
            return out;
        }

        // Helpers ---------------------------------------------
        function norm(v) {
            return (v ?? "")
                .toString()
                .normalize("NFD").replace(/[\u0300-\u036f]/g, "") // sem acentos
                .toLowerCase()
                .trim();
        }

        // Converte qualquer valor do item em texto pesquisável
        function toText(x) {
            if (x == null) return "";
            if (Array.isArray(x)) return x.map(toText).join(" ");
            if (typeof x === "object") {
                // pessoas / lookups comuns
                if (x.Title || x.Name || x.EMail || x.Email) {
                    return [x.Title, x.Name, x.EMail || x.Email].filter(Boolean).join(" ");
                }
                // objeto genérico: concatena valores primitivos úteis
                return Object.values(x).map(toText).join(" ");
            }
            return String(x);
        }

        // Filtro global ---------------------------------------
        function applyAllFilters(arr) {
            try {
                const qEl = _doc().getElementById("globalSearchInput");
                const qRaw = qEl ? qEl.value : "";
                const q = norm(qRaw);
                if (!q) return arr.slice();

                const tokens = q.split(/\s+/).filter(Boolean); // AND de todas as palavras

                return (arr || []).filter(it => {
                    if (!it) return false;

                    // Monte um "blob" com todas as colunas relevantes + qualquer campo simples
                    const parts = [
                        it.Title, it.Company, it.Category,
                        it.Fabricante || it.Vendor,
                        it.Modelo || it.Model,
                        it.ITAssetBunge,
                        it.Hostname,
                        it.Prateleira,
                        it.Status,
                        it.Comments,
                        it.Created ? new Date(it.Created).toLocaleString() : "",
                        // Lookups/Pessoas:
                        it.Site,
                        it.AssignedTo,          // << inclui pessoa (nome + email)
                        it.Author,
                        it.Editor
                    ];

                    // também varre chaves primitivas extras que porventura existam no item
                    for (const [k, v] of Object.entries(it)) {
                        if (v == null) continue;
                        const t = typeof v;
                        if (t === "string" || t === "number" || t === "boolean") {
                            parts.push(v);
                        }
                    }

                    const blob = norm(parts.map(toText).join(" | "));
                    return tokens.every(t => blob.includes(t));
                });
            } catch (e) {
                console.warn("applyAllFilters error:", e);
                return arr.slice();
            }
        }

        // Chame SEMPRE após qualquer sync (manual/auto)
        function afterSyncRefresh(items) {
            // Página atual (pega currentPage solto ou window.currentPage)
            let prevPage = 1;
            try { if (typeof currentPage === "number" && currentPage > 0) prevPage = currentPage; } catch (e) { }
            if (typeof window.currentPage === "number" && window.currentPage > 0) prevPage = window.currentPage;

            // Scroll da página
            const scrollEl = _doc().scrollingElement || _doc().documentElement;
            const prevWinScrollTop = (typeof window.scrollY === "number"
                ? window.scrollY
                : (scrollEl ? scrollEl.scrollTop : 0)) || 0;

            // Scroll interno da tabela (se existir)
            const tableWrap = _doc().querySelector("#resultsSection .table-responsive");
            const prevTableScrollTop = (tableWrap && tableWrap.scrollHeight > tableWrap.clientHeight)
                ? tableWrap.scrollTop
                : null;

            // Sanitiza entrada
            items = Array.isArray(items) ? items.slice() : [];

            // Tombstones + dedupe + sort (mantém seu pipeline)
            if (typeof Deleted_filterArray === "function") items = Deleted_filterArray(items);
            if (typeof _dedupeById === "function") items = _dedupeById(items);
            if (typeof _sortByCreatedDesc === "function") items = _sortByCreatedDesc(items);

            // ✅ MASTER real (blindado)
            const master = scSetMasterItems(items, "afterSyncRefresh");

            // ✅ CARDS: MASTER + ESCOPO (sem filtros/busca)
            try { if (typeof refreshCardsNow === "function") refreshCardsNow(); } catch (e) { }

            // ✅ BASE DA TABELA/ BUSCA = MASTER + ESCOPO
            let scopedBase = scGetScopedBaseFromMaster(master);

            // ✅ VIEW final da tabela = (ESCOPO) + (filtros do painel) + (busca)
            let view = (typeof scBuildViewFromActiveFilters === "function")
                ? scBuildViewFromActiveFilters(scopedBase)
                : scopedBase.slice();

            // Tabela usa VIEW (ok)
            window.currentItemsList = view.slice();
            window.filteredItems = view.slice();
            try { currentItemsList = window.currentItemsList; } catch (e) { }           

            // Mantém página (clamp)
            const perPage = window.itemsPerPage || window.ITEMS_PER_PAGE || 10;
            const total = window.currentItemsList.length;
            const maxPage = Math.max(1, Math.ceil(total / perPage));
            const pageToKeep = Math.min(prevPage, maxPage);

            window.currentPage = pageToKeep;
            try { currentPage = pageToKeep; } catch (e) { }

            // Render tabela
            try { if (typeof renderLatestItems === "function") renderLatestItems(); }
            catch (e) { console.warn("renderLatestItems:", e); }

            // Restaura scroll
            requestAnimationFrame(() => {
                requestAnimationFrame(() => {
                    try {
                        const wrapNow = _doc().querySelector("#resultsSection .table-responsive");
                        if (wrapNow && prevTableScrollTop !== null && wrapNow.scrollHeight > wrapNow.clientHeight) {
                            wrapNow.scrollTop = prevTableScrollTop;
                        }
                    } catch (e) { }

                    try {
                        const se = _doc().scrollingElement || _doc().documentElement;
                        if (se) se.scrollTop = prevWinScrollTop;
                        window.scrollTo({ top: prevWinScrollTop, behavior: "auto" });
                    } catch (e) { }
                });
            });

            // Reconciliação (se existir)
            if (typeof reconcileDeletionsAfterSync === "function") {
                reconcileDeletionsAfterSync(function (dict) {
                    try {
                        if (typeof Deleted_reconcileWithServerIdDict === "function") {
                            Deleted_reconcileWithServerIdDict(dict || {});
                        }
                    } catch (e) { }
                });
            }

            // Hooks
            try { window.lastSyncTS = Date.now(); } catch (e) { }
            try { window.enforceAnalisesUI && window.enforceAnalisesUI(); } catch (e) { }
        }

