// ===== Tombstones de exclusão (ignorar IDs por um tempo) =====
        var DEL_KEY = "deletedIds.v1";
        var DEL_TTL_MS = 10 * 60 * 1000; // 10 min
        var _delCache = null;

        function _delLoad() {
            if (_delCache) return _delCache;
            try { _delCache = JSON.parse(localStorage.getItem(DEL_KEY) || "{}") || {}; }
            catch (e) { _delCache = {}; }
            return _delCache;
        }
        function _delSave() {
            try { localStorage.setItem(DEL_KEY, JSON.stringify(_delCache || {})); } catch (e) { }
        }
        function Deleted_add(id) {
            if (id == null) return;
            _delLoad(); _delCache[String(id)] = Date.now(); _delSave();
        }
        function Deleted_has(id) {
            _delLoad();
            var ts = _delCache[String(id)];
            if (!ts) return false;
            if (Date.now() - ts > DEL_TTL_MS) { delete _delCache[String(id)]; _delSave(); return false; }
            return true;
        }
        function Deleted_filterArray(arr) {
            _delLoad();
            var out = [], i, n = (arr || []).length, changed = false;
            for (i = 0; i < n; i++) {
                var it = arr[i];
                var id = it && (it.Id != null ? it.Id : it.ID);
                if (id != null && Deleted_has(id)) { changed = true; continue; }
                out.push(it);
            }
            return changed ? out : arr;
        }
        // (opcional) remove tombstones já confirmados pelo servidor (id não existe mais)
        function Deleted_reconcileWithServerIdDict(idDict) {
            _delLoad();
            var changed = false, k;
            for (k in _delCache) {
                if (!_delCache.hasOwnProperty(k)) continue;
                if (!idDict[k]) { delete _delCache[k]; changed = true; }
            }
            if (changed) _delSave();
        }

        // New 2

        function refreshFromMaster() {
            var master = Array.isArray(window.allItemsGlobal) ? window.allItemsGlobal : [];
            afterSyncRefresh(master); // sua função já renderiza grade + cards
        }


