        /** ===== Bootstrap sem DOMContentLoaded ===== */
        (function permissionBootstrap() {
            let started = false;

            async function start() {
                if (started) return; started = true;
                try {
                    const email = window.__currentUserEmail || await getCurrentUserEmail();
                    window.__currentUserEmail = email;

                    applyPermissionControls(email);

                    // Observa DOM para conteúdo dinâmico (tabelas re-renderizadas, etc.)
                    if (window.__permObserver) window.__permObserver.disconnect();
                    window.__permObserver = new MutationObserver(() => applyPermissionControls(email));
                    const target = _doc().documentElement || _doc().body;
                    if (target) window.__permObserver.observe(target, { childList: true, subtree: true });
                } catch (e) { console.warn("permissionBootstrap:", e); }
            }

            // Inicia assim que algum [data-perm] existir
            if (_doc().querySelector("[data-perm]")) {
                start();
            } else {
                const waitPerm = new MutationObserver((_, obs) => {
                    if (_doc().querySelector("[data-perm]")) { obs.disconnect(); start(); }
                });
                waitPerm.observe(_doc().documentElement || document, { childList: true, subtree: true });

                // fallback: se nada aparecer por algum motivo, tenta iniciar em breve
                setTimeout(start, 800);
            }

            // Exponha para chamar após seus renders (ex.: depois de montar a tabela)
            window.refreshPermissions = async function () {
                const email = window.__currentUserEmail || await getCurrentUserEmail();
                window.__currentUserEmail = email;
                applyPermissionControls(email);
            };
        })();

