        function renderSitesChecklist() {
            var wrap = _doc().getElementById("scopeSitesList");
            if (!wrap) return;

            var scope = window.scDashScope || { mode: "sites", siteIds: [] };
            var chosen = {};
            (scope.siteIds || []).forEach(function (id) { chosen[String(id)] = 1; });

            var filterCountry = (_doc().getElementById("scopeSitesCountryFilter") || {}).value || "";
            var q = ((_doc().getElementById("scopeSitesSearch") || {}).value || "").trim().toLowerCase();

            var sites = Object.values(window.allSites || {}).slice(); // {id,title,siteCountry} [1](https://bungeltd-my.sharepoint.com/personal/guilherme_filvoch_bunge_com/Documents/Arquivos%20de%20Microsoft%20Copilot%20Chat/Estoque%20-%20Copia.html)
            sites = sites.filter(function (s) {
                if (!s || !s.id || !s.title) return false;
                if (filterCountry && String(s.siteCountry || "").trim() !== filterCountry) return false;
                if (q && String(s.title).toLowerCase().indexOf(q) === -1) return false;
                return true;
            }).sort(function (a, b) { return String(a.title).localeCompare(String(b.title)); });

            wrap.innerHTML = sites.map(function (s) {
                var checked = chosen[String(s.id)] ? "checked" : "";
                var sub = s.siteCountry ? ('<small class="text-muted ms-2">' + escapeHtml(s.siteCountry) + '</small>') : "";
                return (
                    '<div class="form-check">' +
                    '<input class="form-check-input scope-site-chk" type="checkbox" data-id="' + s.id + '" id="scSite_' + s.id + '" ' + checked + '>' +
                    '<label class="form-check-label" for="scSite_' + s.id + '">' + escapeHtml(s.title) + '</label>' +
                    sub +
                    '</div>'
                );
            }).join("");

            // bind checkbox changes
            Array.from(wrap.querySelectorAll(".scope-site-chk")).forEach(function (chk) {
                if (chk.__bound) return;
                chk.addEventListener("change", function () {
                    var id = chk.getAttribute("data-id");
                    var arr = Array.isArray(scope.siteIds) ? scope.siteIds.slice() : [];
                    arr = arr.map(String);
                    if (chk.checked) {
                        if (arr.indexOf(String(id)) === -1) arr.push(String(id));
                    } else {
                        arr = arr.filter(function (x) { return x !== String(id); });
                    }
                    scope.siteIds = arr;
                    window.scDashScope = scope;
                });
                chk.__bound = true;
            });
        }

