        // ===================================================
        // Custom Dropdown (Bootstrap list-group) — PORTAL MODE
        // - Evita aumentar scrollHeight do modal-dialog-scrollable
        // - Abre sempre ao clicar (mesmo com valor)
        // - Teclado: ↑↓ Enter Esc
        // ===================================================
        function createCustomDropdown(inputId, menuId, getItemsFn, onPickFn, opts) {
            const input = _doc().getElementById(inputId);
            const menu = _doc().getElementById(menuId);
            if (!input || !menu) return null;

            opts = opts || {};
            const iconHtml = opts.iconHtml || '<span class="bi bi-geo-alt" style="opacity:.65"></span>';
            const usePortal = (opts.portal !== false); // ✅ default = true

            let items = [];      // [{value, label}]
            let filtered = [];
            let open = false;
            let activeIdx = -1;

            // Portal: guardar parent original
            const originalParent = menu.parentElement;
            const originalNext = menu.nextSibling;

            function n(s) { return String(s || "").trim().toLowerCase(); }

            function setActive(idx) {
                activeIdx = idx;
                const nodes = Array.from(menu.querySelectorAll(".list-group-item"));
                nodes.forEach(x => x.classList.remove("active"));
                if (nodes[idx]) {
                    nodes[idx].classList.add("active");
                    nodes[idx].scrollIntoView({ block: "nearest" });
                }
            }

            function render(list) {
                menu.innerHTML = "";
                if (!list.length) {
                    const empty = _doc().createElement("div");
                    empty.className = "list-group-item small text-muted";
                    empty.textContent = "Nenhum resultado";
                    menu.appendChild(empty);
                    return;
                }

                list.forEach((it, idx) => {
                    const row = _doc().createElement("div");
                    row.className = "list-group-item";
                    row.dataset.idx = String(idx);
                    row.innerHTML = `${iconHtml}<span>${it.label}</span>`;

                    // mousedown evita blur antes de selecionar
                    row.addEventListener("mousedown", (ev) => {
                        ev.preventDefault();
                        pick(idx);
                    });

                    menu.appendChild(row);
                });

                setActive(0);
            }

            function positionPortal() {
                if (!usePortal) return;

                // Move para body (portal)
                if (!menu.classList.contains("sc-dd-portal")) menu.classList.add("sc-dd-portal");
                if (menu.parentElement !== _doc().body) _doc().body.appendChild(menu);

                const r = input.getBoundingClientRect();
                const gap = 6;

                // Largura alinhada ao input
                menu.style.width = r.width + "px";
                menu.style.left = r.left + "px";

                // Decide abrir para baixo ou para cima
                const spaceBelow = window.innerHeight - r.bottom;
                const wantDown = spaceBelow >= 240; // threshold (ajuste se quiser)

                if (wantDown) {
                    menu.style.top = (r.bottom + gap) + "px";
                    menu.style.transform = "none";
                } else {
                    // abre para cima
                    menu.style.top = (r.top - gap) + "px";
                    menu.style.transform = "translateY(-100%)";
                }
            }

            function restoreFromPortal() {
                if (!usePortal) return;

                // volta para o lugar original (opcional, mas deixa DOM “limpo”)
                try {
                    menu.style.left = "";
                    menu.style.top = "";
                    menu.style.width = "";
                    menu.style.transform = "";
                    menu.classList.remove("sc-dd-portal");
                    if (originalParent) {
                        if (originalNext) originalParent.insertBefore(menu, originalNext);
                        else originalParent.appendChild(menu);
                    }
                } catch (e) { }
            }

            function show(showAll) {
                items = (typeof getItemsFn === "function") ? (getItemsFn() || []) : [];
                const q = n(input.value);

                filtered = showAll
                    ? items.slice()
                    : items.filter(it => n(it.label).includes(q) || n(it.value).includes(q));

                render(filtered);

                // ✅ portal posiciona depois de render (já tem altura)
                if (usePortal) {
                    positionPortal();
                    // Reposiciona após paint (garante coordenadas certas)
                    requestAnimationFrame(positionPortal);
                    window.addEventListener("resize", positionPortal, { passive: true });
                    window.addEventListener("scroll", positionPortal, { passive: true, capture: true });
                }

                menu.classList.remove("d-none");
                open = true;
            }

            function hide() {
                menu.classList.add("d-none");
                open = false;
                activeIdx = -1;

                if (usePortal) {
                    window.removeEventListener("resize", positionPortal, { capture: false });
                    window.removeEventListener("scroll", positionPortal, { capture: true });
                    restoreFromPortal();
                }
            }

            function pick(idx) {
                const it = filtered[idx];
                if (!it) return;

                // label no input
                input.value = it.label;

                hide();

                if (typeof onPickFn === "function") onPickFn(it);

                // dispara change (para reaproveitar fluxo)
                try { input.dispatchEvent(new Event("change", { bubbles: true })); } catch (e) { }
            }

            // Clique/foco abre SEMPRE, mesmo preenchido
            input.addEventListener("focus", () => show(true));
            input.addEventListener("click", () => show(true));

            // Digitou? filtra
            input.addEventListener("input", () => show(false));

            // Teclado
            input.addEventListener("keydown", (e) => {
                if (!open && (e.key === "ArrowDown" || e.key === "ArrowUp")) {
                    e.preventDefault();
                    show(true);
                    return;
                }
                if (!open) return;

                if (e.key === "Escape") { e.preventDefault(); hide(); return; }
                if (e.key === "ArrowDown") { e.preventDefault(); setActive(Math.min(activeIdx + 1, Math.max(0, filtered.length - 1))); return; }
                if (e.key === "ArrowUp") { e.preventDefault(); setActive(Math.max(activeIdx - 1, 0)); return; }
                if (e.key === "Enter") { e.preventDefault(); if (activeIdx >= 0) pick(activeIdx); return; }
            });

            // Clicar fora fecha (menu pode estar no body, então funciona igual)
            _doc().addEventListener("mousedown", (e) => {
                if (!open) return;
                if (e.target === input || menu.contains(e.target)) return;
                hide();
            });

            // Blur fecha com delay (permite mousedown no item)
            input.addEventListener("blur", () => setTimeout(hide, 140));

            return { show, hide };
        }


        /**************************************************************
     * Escopo dos Cards (País / Sites / Toda base) - FIX v2
     * - Padrão: Toda base
     * - Não depende do value dos radios (usa o ID)
     * - Select mostra País com letra bonita
     **************************************************************/
        function scGetScopedBaseFromMaster(masterArr) {
            var base = Array.isArray(masterArr) ? masterArr.slice() : [];

            try {
                // Preferência: se você tem applyDashScope (escopo: all/country/sites)
                if (typeof applyDashScope === "function") {
                    base = applyDashScope(base) || [];
                } else if (typeof filterItemsByScope === "function") {
                    // Seu getDashboardBaseItems usa isso — então funciona também
                    base = filterItemsByScope(base) || [];
                }
            } catch (e) { /* noop */ }

            return base;
        }

        const SC_SCOPE_KEY = "scDashScopeV1";
        window.scDashScope = window.scDashScope || null;

        function _esc(s) {
            return String(s || "").replace(/[&<>'"]/g, c => ({
                "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;"
            }[c]));
        }

        function normCountry(v) {
            v = String(v || "").trim().toLowerCase();
            if (!v) return "";
            v = v.normalize("NFD").replace(/[\u0300-\u036f]/g, "");
            if (v === "brasil") return "brazil";
            if (v === "paraguai") return "paraguay";
            if (v === "uruguai") return "uruguay";
            return v;
        }

        function displayCountryFromCanonical(k) {
            k = normCountry(k);
            return ({
                "brazil": "Brazil",
                "argentina": "Argentina",
                "paraguay": "Paraguay",
                "uruguay": "Uruguay",
                "chile": "Chile"
            }[k] || (k ? (k.charAt(0).toUpperCase() + k.slice(1)) : "—"));
        }

        // ===== Country i18n (exibição) =====
        function getCurrentLang() {
            // usa o seletor do topo, se existir
            const sel = _doc().getElementById("scLangSelectBar");
            const v = sel ? String(sel.value || "").toLowerCase() : "";

            // quando for "auto" ou vazio, tenta pegar do seu i18n (se existir)
            if (!v || v === "auto") {
                // se você já guarda em alguma global, use aqui (ajuste se seu app tiver outro nome)
                if (window.__scLang) return String(window.__scLang).toLowerCase();
                // fallback: navegador
                return (navigator.language || "pt").slice(0, 2).toLowerCase();
            }
            return v;
        }

        // Labels por idioma (adicione mais países se precisar)
        const COUNTRY_LABELS = {
            pt: { brazil: "Brasil", argentina: "Argentina", paraguay: "Paraguai", uruguay: "Uruguai", chile: "Chile" },
            en: { brazil: "Brazil", argentina: "Argentina", paraguay: "Paraguay", uruguay: "Uruguay", chile: "Chile" },
            es: { brazil: "Brasil", argentina: "Argentina", paraguay: "Paraguay", uruguay: "Uruguay", chile: "Chile" }
        };

        // Recebe "brazil"/"Brazil"/"Brasil" e devolve label traduzida
        function countryLabel(countryKeyOrName) {
            const key = normCountry(countryKeyOrName); // você já tem normCountry no escopo
            if (!key) return "";

            const lang = getCurrentLang();
            const dict = COUNTRY_LABELS[lang] || COUNTRY_LABELS.pt;

            // se não estiver no mapa, faz fallback "Title Case"
            return dict[key] || (key.charAt(0).toUpperCase() + key.slice(1));
        }

        function loadScope() {
            try {
                const raw = localStorage.getItem(SC_SCOPE_KEY);
                if (raw) return JSON.parse(raw);
            } catch (e) { }
            // ✅ padrão: toda base
            return { mode: "all", country: "", siteIds: [] };
        }

        /** Site (título SharePoint) exigido para exibir a aba Suprimentos — escopo = somente este site. */
        var SC_SUPPLIES_REQUIRED_SITE_TITLE = "Luís Eduardo Magalhães - LEM";

        function scNormSiteTitleKey(s) {
            return String(s || "").trim().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
        }

        function scDashScopeAllowsSupplies() {
            try {
                var scope = window.scDashScope || (typeof loadScope === "function" ? loadScope() : null);
                if (!scope) return false;
                if (scope.mode !== "sites") return false;
                var ids = Array.isArray(scope.siteIds) ? scope.siteIds.filter(function (x) { return x != null && String(x).trim() !== ""; }) : [];
                if (ids.length !== 1) return false;
                var map = window.allSites || {};
                var id = ids[0];
                var s = map[String(id)] || map[Number(id)];
                if (!s) return false;
                var title = String(s.Title != null ? s.Title : s.title || "").trim();
                return scNormSiteTitleKey(title) === scNormSiteTitleKey(SC_SUPPLIES_REQUIRED_SITE_TITLE);
            } catch (e) {
                return false;
            }
        }

        function scUpdateSuppliesTabVisibility() {
            var btn = _doc().getElementById("btnTabSuprimentos");
            if (!btn) return;
            var ok = typeof scDashScopeAllowsSupplies === "function" && scDashScopeAllowsSupplies();
            btn.classList.toggle("d-none", !ok);
            btn.setAttribute("aria-hidden", ok ? "false" : "true");
            if (!ok) {
                var sec = _doc().getElementById("suppliesSection");
                var open = sec && !sec.classList.contains("d-none");
                if (open && window.scSupplies && typeof window.scSupplies.close === "function") {
                    try { window.scSupplies.close(); } catch (e1) { }
                }
            }
        }

        function persistScope(scope) {
            try { localStorage.setItem(SC_SCOPE_KEY, JSON.stringify(scope)); } catch (e) { }
        }

        function getSiteIdFromItem(item) {
            if (item && typeof item.SiteId === "number") return item.SiteId;
            if (item && item.Site && typeof item.Site.Id === "number") return item.Site.Id;
            return null;
        }

        function filterItemsByScope(items) {
            items = Array.isArray(items) ? items : [];
            const scope = window.scDashScope || loadScope();

            if (!scope || scope.mode === "all") return items;

            // precisa allSites carregado
            if (!allSites || Object.keys(allSites).length === 0) return items;

            if (scope.mode === "country") {
                const wanted = normCountry(scope.country);
                if (!wanted) return items;

                return items.filter(it => {
                    const sid = getSiteIdFromItem(it);
                    const s = sid && allSites[sid] ? allSites[sid] : null;
                    const cc = s ? normCountry(s.siteCountry || s.SiteCountry || "") : "";
                    return cc === wanted;
                });
            }

            if (scope.mode === "sites") {
                const ids = Array.isArray(scope.siteIds) ? scope.siteIds.map(String) : [];
                if (!ids.length) return [];
                const set = {};
                ids.forEach(x => set[x] = 1);

                return items.filter(it => {
                    const sid = getSiteIdFromItem(it);
                    return sid != null && set[String(sid)] === 1;
                });
            }

            return items;
        }

        function getDashboardBaseItems() {
            const base = Array.isArray(window.allItemsGlobal) ? window.allItemsGlobal.slice() : [];
            return filterItemsByScope(base);
        }

        function updateScopeCardUI() {
            const scope = window.scDashScope || loadScope();
            const labelEl = _doc().getElementById("scopeLabel");
            const hintEl = _doc().getElementById("scopeHint");
            const topHint = _doc().getElementById("scTabsHint");
            function _st(key, vars, fallback) {
                if (typeof window.t === "function") return window.t(key, vars || {});
                return fallback;
            }

            if (labelEl) {
                if (scope.mode === "all") labelEl.textContent = _st("scopeAllBase", {}, "Toda base");
                else if (scope.mode === "country") {
                    const cnm = (typeof countryLabel === "function" ? countryLabel(scope.country) : displayCountryFromCanonical(scope.country));
                    labelEl.textContent = _st("scopeCountry", { name: cnm }, "País: " + cnm);
                }
                else labelEl.textContent = _st("scopeSitesCount", { n: ((scope.siteIds || []).length || 0) }, "Sites: " + ((scope.siteIds || []).length || 0));
            }

            if (hintEl) {
                if (scope.mode === "all") hintEl.textContent = _st("scopeHintNoFilter", {}, "Sem filtro");
                else if (scope.mode === "country") hintEl.textContent = _st("scopeHintCardsCountry", {}, "Cards filtrados por país");
                else hintEl.textContent = _st("scopeHintCardsSites", {}, "Cards filtrados por sites");
            }

            if (topHint) {
                if (scope.mode === "all") topHint.textContent = _st("scopeTopAll", {}, "Escopo: Toda base");
                else if (scope.mode === "country") {
                    const cnm2 = (typeof countryLabel === "function" ? countryLabel(scope.country) : displayCountryFromCanonical(scope.country));
                    topHint.textContent = _st("scopeTopCountry", { name: cnm2 }, "Escopo: " + cnm2);
                }
                else topHint.textContent = _st("scopeTopSites", { n: ((scope.siteIds || []).length || 0) }, "Escopo: " + ((scope.siteIds || []).length || 0) + " site(s)");
            }
            try { if (typeof scUpdateSuppliesTabVisibility === "function") scUpdateSuppliesTabVisibility(); } catch (eSupVis) { }
        }

        function refreshCardsWithScope() {
            const scoped = getDashboardBaseItems();
            updateDashboard(scoped);
            updateScopeCardUI();
        }

        /*********************
         * MODAL - Bind e UI
         *********************/
        function bindScopeModalOnce() {
            const modalEl = _doc().getElementById("scopeModal");
            if (!modalEl || modalEl.__bound) return;

            // radios -> NÃO depende de value
            const bindRadio = (id, mode) => {
                const el = _doc().getElementById(id);
                if (!el) return;
                el.addEventListener("change", function () {
                    if (!el.checked) return;
                    const scope = window.scDashScope || loadScope();
                    scope.mode = mode;
                    window.scDashScope = scope;
                    syncScopeModalUIFromState();
                });
            };
            bindRadio("scopeAll", "all");
            bindRadio("scopeCountry", "country");
            bindRadio("scopeSites", "sites");

            const selCountry = _doc().getElementById("scopeCountrySelect");
            if (selCountry) {
                selCountry.addEventListener("change", function () {
                    const scope = window.scDashScope || loadScope();
                    scope.country = normCountry(selCountry.value || "");
                    window.scDashScope = scope;
                });
            }

            const selFilter = _doc().getElementById("scopeSitesCountryFilter");
            if (selFilter) selFilter.addEventListener("change", renderSitesChecklist);

            const search = _doc().getElementById("scopeSitesSearch");
            if (search) search.addEventListener("input", renderSitesChecklist);

            modalEl.__bound = true;
        }

        function buildCountriesSelects() {
            // monta lista de países canônicos a partir de allSites
            const set = {};
            Object.values(allSites || {}).forEach(s => {
                const nk = normCountry(s.siteCountry || s.SiteCountry || "");
                if (nk) set[nk] = 1;
            });

            const keys = Object.keys(set).sort(); // ["argentina","brazil",...]

            // cache global para os dropdowns custom
            window.__scopeCountries = keys.map(k => ({
                value: k,
                label: (typeof countryLabel === "function" ? countryLabel(k) : displayCountryFromCanonical(k))
            }));
        }

        function syncScopeModalUIFromState() {
            const scope = window.scDashScope || loadScope();

            const rAll = _doc().getElementById("scopeAll");
            const rC = _doc().getElementById("scopeCountry");
            const rS = _doc().getElementById("scopeSites");

            if (rAll) rAll.checked = scope.mode === "all";
            if (rC) rC.checked = scope.mode === "country";
            if (rS) rS.checked = scope.mode === "sites";

            const wc = _doc().getElementById("scopeCountryWrap");
            const ws = _doc().getElementById("scopeSitesWrap");
            if (wc) wc.classList.toggle("d-none", scope.mode !== "country");
            if (ws) ws.classList.toggle("d-none", scope.mode !== "sites");

            const selCountry = _doc().getElementById("scopeCountrySelect");
            if (selCountry && scope.mode === "country") {
                selCountry.value = displayCountryFromCanonical(normCountry(scope.country || ""));
            }


            renderSitesChecklist();
        }

        function renderSitesChecklist() {
            const wrap = _doc().getElementById("scopeSitesList");
            if (!wrap) return;

            const scope = window.scDashScope || loadScope();
            const chosen = {};
            (scope.siteIds || []).forEach(id => chosen[String(id)] = 1);

            const filterC = normCountry((_doc().getElementById("scopeSitesCountryFilter") || {}).value || "");
            const q = ((_doc().getElementById("scopeSitesSearch") || {}).value || "").trim().toLowerCase();

            const sites = Object.values(allSites || {})
                .filter(s => s && s.id && s.title)
                .filter(s => !filterC || normCountry(s.siteCountry || s.SiteCountry || "") === filterC)
                .filter(s => !q || String(s.title).toLowerCase().includes(q))
                .sort((a, b) => String(a.title).localeCompare(String(b.title)));

            wrap.innerHTML = sites.map(s => {
                const checked = chosen[String(s.id)] ? "checked" : "";
                const c = (typeof countryLabel === "function"
                    ? countryLabel(normCountry(s.siteCountry || s.SiteCountry || ""))
                    : displayCountryFromCanonical(normCountry(s.siteCountry || s.SiteCountry || "")));
                return `
      <div class="form-check">
        <input class="form-check-input scope-site-chk" type="checkbox" data-id="${_esc(s.id)}"
               id="scSite_${_esc(s.id)}" ${checked}>
        <label class="form-check-label" for="scSite_${_esc(s.id)}">${_esc(s.title)}</label>
        <small class="text-muted ms-2">${_esc(c)}</small>
      </div>`;
            }).join("");

            Array.from(wrap.querySelectorAll(".scope-site-chk")).forEach(chk => {
                if (chk.__bound) return;
                chk.addEventListener("change", function () {
                    const id = String(chk.getAttribute("data-id"));
                    const sc = window.scDashScope || loadScope();
                    let arr = Array.isArray(sc.siteIds) ? sc.siteIds.map(String) : [];

                    if (chk.checked) { if (!arr.includes(id)) arr.push(id); }
                    else arr = arr.filter(x => x !== id);

                    sc.siteIds = arr;
                    window.scDashScope = sc;
                });
                chk.__bound = true;
            });
        }

        function openScopeModal() {
            bindScopeModalOnce();

            if (!allSites || Object.keys(allSites).length === 0) {
                showToast?.((typeof window.t === "function" ? window.t("be2SitesLoading") : "Ainda carregando BSA Sites... tente novamente em instantes."), "warning");
                return;
            }

            window.scDashScope = loadScope();

            // monta cache de países
            buildCountriesSelects();

            // inicializa dropdowns custom (1x)
            initScopeCustomDropdowns();

            // aplica estado na UI (radios/wraps/valores)
            syncScopeModalUIFromState();

            bootstrap.Modal.getOrCreateInstance(_doc().getElementById("scopeModal")).show();
        }

        function applyDashScope(items) {
            const list = Array.isArray(items) ? items : [];
            const scope = window.scDashScope || (typeof loadScope === "function" ? loadScope() : { mode: "all" });

            const mode = (scope && scope.mode) ? String(scope.mode).toLowerCase() : "all";

            // all => tudo
            if (mode === "all") return list;

            // country => filtra por país (usando a mesma normalização que você usa no saveScope)
            if (mode === "country") {
                const target = (typeof normCountry === "function") ? normCountry(scope.country || "") : String(scope.country || "");
                if (!target) return list;

                return list.filter(it => {
                    const c = (typeof getCountryForItem === "function") ? getCountryForItem(it) : "";
                    const cn = (typeof normCountry === "function") ? normCountry(c || "") : String(c || "");
                    return cn === target;
                });
            }

            // sites => filtra por IDs de site
            if (mode === "sites") {
                const ids = Array.isArray(scope.siteIds) ? scope.siteIds : [];
                if (!ids.length) return [];

                const set = new Set(ids.map(x => String(x)));

                return list.filter(it => {
                    const id =
                        (it && it.Site && (it.Site.Id ?? it.SiteID)) ??
                        it?.SiteId ??
                        it?.SiteID ??
                        it?.Site_x0020_Id ??
                        null;

                    return id != null && set.has(String(id));
                });
            }

            // fallback
            return list;
        }


        function saveScope() {
            const scope = window.scDashScope || loadScope();

            // qual radio está marcado
            const mode =
                _doc().getElementById("scopeAll")?.checked ? "all" :
                    _doc().getElementById("scopeSites")?.checked ? "sites" : "country";

            scope.mode = mode;

            if (mode === "all") {
                scope.country = "";
                scope.siteIds = [];
            }

            if (mode === "country") {
                scope.siteIds = [];
                const v = _doc().getElementById("scopeCountrySelect")?.value || "";
                scope.country = normCountry(v);
                if (!scope.country) {
                    showToast?.((typeof window.t === "function" ? window.t("scopePickCountry") : "Selecione um país."), "warning");
                    return;
                }
            }

            if (mode === "sites") {
                scope.country = "";
                scope.siteIds = Array.isArray(scope.siteIds) ? scope.siteIds : [];
                if (!scope.siteIds.length) {
                    showToast?.((typeof window.t === "function" ? window.t("scopePickOneSite") : "Selecione pelo menos 1 site."), "warning");
                    return;
                }
            }

            window.scDashScope = scope;
            persistScope(scope);

            refreshCardsWithScope();
            bootstrap.Modal.getInstance(_doc().getElementById("scopeModal"))?.hide();

            try { if (typeof triggerRecalc === 'function') triggerRecalc(); else _doc().getElementById('globalSearchInput')?.dispatchEvent(new Event('input')); } catch (e) { }
            try { scEnsureHeaderButtons(); } catch (e) { }

        }

        function resetScope() {
            // ✅ reset sempre volta para "Toda base"
            const scope = { mode: "all", country: "", siteIds: [] };
            window.scDashScope = scope;
            persistScope(scope);
            syncScopeModalUIFromState();
            refreshCardsWithScope();

            try { if (typeof triggerRecalc === 'function') triggerRecalc(); else _doc().getElementById('globalSearchInput')?.dispatchEvent(new Event('input')); } catch (e) { }
            try { scEnsureHeaderButtons(); } catch (e) { }

        }

        function hydrateSiteDatalistFromCache() {
            try {
                const dl = _doc().getElementById("site-list");
                if (!dl) return;

                // se já tem opções, não re-monta
                if (dl.options && dl.options.length > 0) return;

                const sitesObj = window.allSites || {};
                const sitesArr = Object.values(sitesObj);

                if (!sitesArr.length) return;

                dl.innerHTML = "";
                sitesArr.forEach(site => {
                    // seu objeto costuma ter title e id/code (às vezes id/Id)
                    const title = site.title || site.Title;
                    if (!title) return;

                    const opt = _doc().createElement("option");
                    opt.value = title;
                    // (opcional) manter metadados
                    opt.dataset.id = site.id || site.Id || "";
                    opt.dataset.code = site.code || site.Code || "";
                    dl.appendChild(opt);
                });
            } catch (e) {
                console.warn("hydrateSiteDatalistFromCache:", e);
            }
        }

        const SC_CHOICES_CACHE_KEY = "sc_choices_cache_v1";
        const SC_CHOICES_CACHE_TTL_MS = 1000 * 60 * 60 * 24 * 3; // 3 dias

        function choicesCacheLoad() {
            try {
                const raw = localStorage.getItem(SC_CHOICES_CACHE_KEY);
                if (!raw) return null;
                const obj = JSON.parse(raw);
                if (!obj || !obj.ts || (Date.now() - obj.ts) > SC_CHOICES_CACHE_TTL_MS) return null;
                return obj.data || null;
            } catch (_) { return null; }
        }

        function choicesCacheSave(data) {
            try {
                localStorage.setItem(SC_CHOICES_CACHE_KEY, JSON.stringify({ ts: Date.now(), data }));
            } catch (_) { }
        }

        // Preenche datalists a partir do cache local (instantâneo)
        function hydrateChoiceDatalistsFromCache() {
            const cached = choicesCacheLoad();
            if (!cached) return false;

            try {
                Object.keys(cached).forEach(fieldName => {
                    const dl = _doc().getElementById(fieldName.toLowerCase() + "-list");
                    if (!dl) return;

                    // se já tem opções, não re-monta
                    if (dl.options && dl.options.length > 0) return;

                    dl.innerHTML = "";
                    (cached[fieldName] || []).forEach(choice => {
                        const opt = _doc().createElement("option");
                        opt.dataset.canonical = choice;
                        opt.value = (typeof window.displayChoice === "function")
                            ? window.displayChoice(fieldName, choice)
                            : choice;
                        dl.appendChild(opt);
                    });
                });
                return true;
            } catch (e) {
                console.warn("hydrateChoiceDatalistsFromCache:", e);
                return false;
            }
        }

