// Preferência persistente
        (function () {
            const KEY = 'scCardsCollapsedV1';
            const BTN_ID = 'btnToggleCards';

            // expõe uma função global simples e direta
            window.scToggleCards = function scToggleCards() {
                const next = !isCollapsed();
                persist(next);
                applyUI(next);
                try {
                    showToast((typeof window.t === "function"
                        ? (next ? window.t("cardsCollapsedToast") : window.t("cardsExpandedToast"))
                        : (next ? "Cards recolhidos" : "Cards expandidos")), "success");
                } catch (_) { }
            };

            // Restaura imediatamente (caso o script suba depois do DOM, não tem problema)
            applyUI(isCollapsed());
            // Tenta re-sincronizar o botão, caso ele seja re-renderizado em algum momento
            setTimeout(() => applyUI(isCollapsed()), 0);

            // Helpers
            function isCollapsed() {
                try { return localStorage.getItem(KEY) === '1'; } catch (_) { return false; }
            }
            function persist(val) {
                try { localStorage.setItem(KEY, val ? '1' : '0'); } catch (_) { }
            }
            function applyUI(collapsed) {
                // Classe no <body> dispara o CSS
                _doc().body.classList.toggle('sc-cards-collapsed', !!collapsed);
                // Atualiza o botão se existir
                const btn = _doc().getElementById(BTN_ID);
                if (btn) {
                    btn.setAttribute('aria-pressed', collapsed ? 'true' : 'false');
                    btn.setAttribute('aria-label', collapsed
                        ? (typeof window.t === "function" ? window.t("cardsAriaExpand") : "Expandir cards")
                        : (typeof window.t === "function" ? window.t("cardsAriaCollapse") : "Recolher cards"));
                    const cardLbl2 = (typeof window.t === "function" ? window.t("cardsToolbarLabel") : "Cards");
                    btn.innerHTML = collapsed
                        ? '<i class="bi bi-layout-sidebar-inset-reverse me-1"></i> ' + cardLbl2
                        : '<i class="bi bi-layout-three-columns me-1"></i> ' + cardLbl2;
                }
            }

            // Opcional: atalho Alt+Shift+K
            window.addEventListener('keydown', (e) => {
                if (e.altKey && e.shiftKey && (e.key === 'K' || e.key === 'k')) {
                    e.preventDefault();
                    window.scToggleCards();
                }
            });
        })();

