(function () {
            const SEARCH_ID = 'globalSearchInput';

            // Intercepta ANTES do "Find" nativo do navegador
            window.addEventListener('keydown', function onKeyDown(e) {
                // Ctrl+F (Win/Linux) OU ⌘+F (macOS), sem Shift
                const isFindCombo =
                    (e.ctrlKey || e.metaKey) &&
                    !e.shiftKey &&
                    (e.code === 'KeyF' || String(e.key).toLowerCase() === 'f');

                if (!isFindCombo) return;

                const inp = _doc().getElementById(SEARCH_ID);
                if (!inp) return; // se por algum motivo não existir, deixa o nativo

                const ae = _doc().activeElement;
                const tag = (ae && ae.tagName || '').toLowerCase();
                const isEditable = tag === 'input' || tag === 'textarea' || (ae && ae.isContentEditable);

                // --- TOGGLE ---
                // Caso 1: já estou na busca -> volta ao "estado original" (tira foco)
                if (ae === inp) {
                    e.preventDefault();  // evita abrir o find nativo
                    e.stopPropagation();
                    inp.blur();
                    // (opcional) rola levemente pra cima pra “sair” visualmente do campo
                    try { window.scrollBy({ top: -10, behavior: 'instant' }); } catch (_) { }
                    return;
                }

                // Caso 2: estou digitando em outro campo -> deixa o find nativo funcionar normalmente
                if (isEditable) return;

                // Caso 3: estou fora de campos -> foca a busca
                e.preventDefault();
                e.stopPropagation();
                inp.focus({ preventScroll: false });
                try { inp.select(); } catch (_) { }
                try { inp.scrollIntoView({ behavior: 'smooth', block: 'center' }); } catch (_) { }

                // (opcional) primeira vez: mostra dica
                try {
                    if (!localStorage.getItem('scHintCtrlF')) {
                        localStorage.setItem('scHintCtrlF', '1');
                        // se você tiver showToast
                        try { showToast('Dica: pressione Ctrl+F novamente para voltar ao conteúdo. (ESC limpa a busca)', 'info'); } catch (_) { }
                    }
                } catch (_) { }
            }, { capture: true });
        })();

