/* =========================================================
    BULK EDIT V2 - DO ZERO (ATUALIZADO)
    - Scope: paste (Serial/ITAsset) + all (admin)
    - Preview real (Antes → Depois)
    - Site é Lookup: exibe Title e salva via SiteId
    - Toasts only (sem alert/confirm)
    =======================function bind() {================================== */
        (function () {

            // =========================================================
            // BULK EDIT V2 - CONFIG ABSOLUTA (SITE ONDE A LISTA EXISTE)
            // =========================================================
            const BE2_API = (function () {
                // Se você já tem essas vars globais no app, reaproveita
                const BASE_SITE = (window.BASE_SITE || "https://bungeltd.sharepoint.com/sites/fieldservices").replace(/\/+$/, "");
                const LIST_TITLE = window.LIST_TITLE || "Stock Control";

                return {
                    BASE_SITE,
                    LIST_TITLE,
                    CONTEXTINFO_URL: `${BASE_SITE}/_api/contextinfo`,
                    ENSUREUSER_URL: `${BASE_SITE}/_api/web/ensureuser`,
                    LIST_URL: `${BASE_SITE}/_api/web/lists/getbytitle('${encodeURIComponent(LIST_TITLE)}')`,
                    ITEM_URL: (id) => `${BASE_SITE}/_api/web/lists/getbytitle('${encodeURIComponent(LIST_TITLE)}')/items(${id})`,
                    // Se você precisar GETITEMS/RenderListDataAsStream depois:
                    LIST_ITEMS_URL: `${BASE_SITE}/_api/web/lists/getbytitle('${encodeURIComponent(LIST_TITLE)}')/items`,
                    GETITEMS_URL: `${BASE_SITE}/_api/web/lists/getbytitle('${encodeURIComponent(LIST_TITLE)}')/GetItems`,
                };
            })();
            const be2 = {
                state: {
                    scope: { mode: 'paste', keys: [], items: [] },
                    grid: { rows: [], dirty: new Map(), search: '' },
                    global: { patches: {} },
                    preview: null,
                    results: { ok: 0, fail: 0, errors: [] },
                    busy: false
                },
                cfg: {
                    // Ajuste aqui se precisar:
                    listTitle: 'Stock Control',

                    // Lookup de Site:
                    siteLookup: {
                        internalName: 'Site',      // se o internal name for "Site"
                        sitesListTitle: 'BSA Sites'// lista lookup (ajuste se outro)
                    },

                    // Mapeie nomes internos do SharePoint (se forem diferentes)
                    fieldMap: {
                        Status: 'Status',
                        Company: 'Company',
                        Category: 'Category',
                        Vendor: 'Fabricante',      // ajuste se seu internal name for Vendor
                        Model: 'Modelo',
                        Prateleira: 'Prateleira',
                        Hostname: 'Hostname',
                        Comments: 'Comments',
                        Responsible: 'Author',
                        AssignedTo: 'AssignedTo',  // Person/Group -> AssignedToId

                        // AR:
                        NotaFiscal: 'NotaFiscal',
                        DataNota: 'DataNota',
                        NrRemessa: 'NrRemessa',
                        DataRemessa: 'DataRemessa',
                        OCPO: 'OCPO'
                    },

                    chunkSize: 25,
                    retry: { tries: 4, baseDelayMs: 700 }
                },
                els: {},
                _bound: false
            };

            /* -------------------------
            Toast helper (no alerts)
            ------------------------- */
            function toast(msg, type = 'info') {
                if (typeof window.showToast === 'function') return window.showToast(msg, type);
                console.log(`[${type}] ${msg}`);
            }

            function setBusy(on) {
                be2.state.busy = !!on;
                const dis = !!on;

                ['be2BtnLoad', 'be2BtnPreview', 'be2BtnApply', 'be2BtnExportCSV', 'be2BtnPasteClear', 'be2BtnPasteExample']
                    .forEach(id => be2.els[id] && (be2.els[id].disabled = dis));

                be2.els.be2ProgressWrap?.classList.toggle('d-none', !on);
            }

            function setStatus(msg) {
                if (be2.els.be2StatusBar) be2.els.be2StatusBar.textContent = msg;
            }

            function setCounts() {
                const loaded = be2.state.scope.items.length;
                const changedItems = (be2.state.preview?.diffs?.length) || computeChangedItemsCount();

                be2.els.be2CountLoaded.textContent = (typeof window.t === "function" ? window.t("be2CountLoadedLabel", { n: loaded }) : ("Carregados: " + loaded));
                be2.els.be2CountChanged.textContent = (typeof window.t === "function" ? window.t("be2CountChangedLabel", { n: changedItems }) : ("Alterados: " + changedItems));

                be2.els.be2SumLoaded.textContent = String(loaded);
                be2.els.be2SumChanged.textContent = String(changedItems);

                const canPreview = loaded > 0 && computeChangedItemsCount() > 0;
                be2.els.be2BtnPreview.disabled = !canPreview;
                be2.els.be2BtnApply.disabled = !canPreview;
                be2.els.be2BtnExportCSV.disabled = loaded === 0;
            }

            function computeChangedItemsCount() {
                const hasGlobal = Object.keys(be2.state.global.patches || {}).length > 0;
                if (hasGlobal) return be2.state.scope.items.length;
                // grade: contar itens que têm ao menos 1 célula dirty
                const itemIds = new Set();
                for (const key of be2.state.grid.dirty.keys()) {
                    const [id] = key.split(':');
                    if (id) itemIds.add(id);
                }
                return itemIds.size;
            }

            function norm(s) { return (s ?? '').toString().trim(); }
            function normKey(s) { return norm(s).toLowerCase().replace(/\s+/g, ' ').trim(); }
            function isEmail(s) { return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(norm(s)); }

            function escapeHtmlAttr(s) {
                return String(s ?? '')
                    .replace(/&/g, '&amp;')
                    .replace(/"/g, '&quot;')
                    .replace(/</g, '&lt;')
                    .replace(/>/g, '&gt;');
            }

            /* -------------------------
            SharePoint helpers
            ------------------------- */
            // ===== Digest cache por BASE_SITE (anti-CSRF SharePoint) =====
            const be2DigestCache = {}; // key: BASE_SITE

            async function getDigest(forceRefresh = false) {
                const key = BE2_API.BASE_SITE;

                if (!be2DigestCache[key]) {
                    be2DigestCache[key] = { value: null, expiresAt: 0, fetching: null };
                }

                const slot = be2DigestCache[key];
                const now = Date.now();

                if (!forceRefresh && slot.value && now < slot.expiresAt) return slot.value;

                if (slot.fetching) return slot.fetching;

                slot.fetching = fetch(BE2_API.CONTEXTINFO_URL, {
                    method: "POST",
                    credentials: "same-origin",
                    headers: { Accept: "application/json;odata=nometadata" },
                })
                    .then(async (res) => {
                        if (!res.ok) {
                            const t = await res.text().catch(() => "");
                            throw new Error(`contextinfo falhou (${res.status}) ${t}`);
                        }
                        return res.json();
                    })
                    .then((j) => {
                        const digest = j?.FormDigestValue || j?.d?.GetContextWebInformation?.FormDigestValue;
                        const timeout =
                            j?.FormDigestTimeoutSeconds || j?.d?.GetContextWebInformation?.FormDigestTimeoutSeconds || 1800;

                        if (!digest) throw new Error("contextinfo sem FormDigestValue.");

                        slot.value = digest;
                        slot.expiresAt = Date.now() + Math.max(60, timeout - 60) * 1000; // margem 60s
                        slot.fetching = null;
                        return digest;
                    })
                    .catch((err) => {
                        slot.fetching = null;
                        throw err;
                    });

                return slot.fetching;
            }

            async function ensureUserByEmail(email) {
                // aceita email ou claims (sua função já faz fallback)
                const u = await ensureUserByKeyOrEmail(email);
                if (!u) return null;
                return u;
            }

            async function spMergeItem(itemId, patch) {
                async function doMerge(forceDigestRefresh = false) {
                    const digest = await getDigest(forceDigestRefresh);

                    const res = await fetch(BE2_API.ITEM_URL(itemId), {
                        method: "POST",
                        credentials: "same-origin",
                        headers: {
                            Accept: "application/json;odata=nometadata",
                            "Content-Type": "application/json;odata=nometadata",
                            "X-RequestDigest": digest,
                            "IF-MATCH": "*",
                            "X-HTTP-Method": "MERGE",
                        },
                        body: JSON.stringify(patch),
                    });

                    if (res.ok) return true;

                    const text = await res.text().catch(() => "");

                    const isSecurityValidation =
                        res.status === 403 &&
                        (/validaç[aã]o de seguranç[aã]o/i.test(text) || /-2130575251/i.test(text));

                    if (isSecurityValidation && !forceDigestRefresh) {
                        // força renovar digest do BASE_SITE e tenta de novo
                        be2DigestCache[BE2_API.BASE_SITE].value = null;
                        be2DigestCache[BE2_API.BASE_SITE].expiresAt = 0;
                        return doMerge(true);
                    }

                    throw new Error(`MERGE falhou (${res.status}) ${text}`);
                }

                return doMerge(false);
            }

            function getAllItemsCache() {
                // seu app costuma manter cache global (ex.: allItemsGlobal) 
                if (Array.isArray(window.allItemsGlobal) && window.allItemsGlobal.length) return window.allItemsGlobal;
                if (Array.isArray(window.allItems) && window.allItems.length) return window.allItems;
                return [];
            }

            /* -------------------------
            Lookup Site (Title -> Id) via lista de sites
            ------------------------- */
            let be2SiteMap = null;

            async function ensureSiteMap(forceReload) {
                window.__be2SiteMap = window.__be2SiteMap || null;
                if (window.__be2SiteMap && !forceReload) return window.__be2SiteMap;

                function hasAllSites() {
                    try { return window.allSites && Object.keys(window.allSites).length > 0; } catch (_) { return false; }
                }

                // 1) Se não tem allSites, tenta carregar
                if (forceReload || !hasAllSites()) {
                    // tenta hidratar do cache (rápido) e depois carregar normal
                    try { if (typeof hydrateSiteDatalistFromCache === "function") hydrateSiteDatalistFromCache(); } catch (_) { }
                    try { if (typeof loadSiteDatalist === "function") await loadSiteDatalist(); } catch (_) { }

                    if (!hasAllSites()) {
                        throw new Error("Falha ao carregar sites (BSA Sites).");
                    }
                }

                // 2) Monta map Title -> Id
                const map = {};
                try {
                    Object.values(window.allSites || {}).forEach(s => {
                        const title = (s && (s.title || s.Title)) ? String(s.title || s.Title).trim() : "";
                        const id = (s && (s.id || s.Id)) ? String(s.id || s.Id).trim() : "";
                        if (!title || !id) return;
                        map[title.toLowerCase()] = Number(id);
                    });
                } catch (e) {
                    console.error("ensureSiteMap(build):", e);
                }

                if (!Object.keys(map).length) {
                    throw new Error("Falha ao montar mapa de sites (BSA Sites).");
                }

                window.__be2SiteMap = map;
                return map;
            }

            async function resolveSiteId(siteTitle) {
                const t = String(siteTitle || "").trim();
                if (!t) return null;

                const map = await ensureSiteMap(false);
                return map[t.toLowerCase()] || null;
            }


            function lookupTitle(x) {
                if (!x) return '';
                if (typeof x === 'string') return x;
                return x.Title || x.LookupValue || x.Value || '';
            }

            /* -------------------------
            isAR hook (seu app já tem) 
            ------------------------- */
            function isARUser() {
                try {
                    if (typeof window.isAR === 'function') return !!window.isAR();
                } catch (e) { }

                // ✅ Fallback: usa a regra global (inclui forceCountry=argentina quando permitido)
                try {
                    if (typeof isArgentinaTeam === 'function') return !!isArgentinaTeam();
                } catch (e) { }

                return false;
            }

            /* -------------------------
            Parse paste (Serial/ITAsset)
            - aceita colar excel -> pega primeira célula por linha
            ------------------------- */
            function parsePasteToKeys(txt) {
                const raw = (txt || '').trim();
                if (!raw) return [];
                const lines = raw.split(/\r?\n/).map(l => l.trim()).filter(Boolean);

                const keys = [];
                for (const line of lines) {
                    const parts = line.split(/\t|;|,/).map(p => p.trim()).filter(Boolean);
                    const key = parts[0] || '';
                    if (key) keys.push(key);
                }

                const seen = new Set();
                return keys.filter(k => {
                    const nk = normKey(k);
                    if (!nk || seen.has(nk)) return false;
                    seen.add(nk);
                    return true;
                });
            }

            /* -------------------------
            Convert item -> row snapshot (corrige Site lookup object)
            ------------------------- */
            function extractAssignedEmail(it) {
                const a = it?.AssignedTo;
                if (!a) return it?.AssignedToEmail || '';
                if (typeof a === 'string') return a;
                return a?.EMail || a?.Email || a?.email || it?.AssignedToEmail || '';
            }

            function extractResponsibleEmail(it) {
                // ✅ tenta Author primeiro (Created By / coluna renomeada), senão fallback para Responsible
                const r = it?.Author || it?.Responsible;
                if (!r) return '';
                if (typeof r === 'string') return r;
                return r?.EMail || r?.Email || r?.email || '';
            }
            ``


            function toGridRow(it) {
                return {
                    Id: it?.Id,
                    Title: it?.Title ?? '',
                    ITAssetBunge: it?.ITAssetBunge ?? '',
                    Hostname: it?.Hostname ?? '',
                    Status: it?.Status ?? '',
                    Site: lookupTitle(it?.Site), // ✅ sem [object Object]
                    Company: it?.Company ?? '',
                    Category: it?.Category ?? '',
                    Vendor: it?.Fabricante ?? it?.Vendor ?? '',
                    Model: it?.Modelo ?? it?.Model ?? '',
                    Prateleira: it?.Prateleira ?? '',
                    Comments: it?.Comments ?? '',
                    Responsible: extractResponsibleEmail(it),
                    AssignedToEmail: extractAssignedEmail(it),
                    // AR:
                    NotaFiscal: it?.NotaFiscal ?? '',
                    DataNota: it?.DataNota ?? '',
                    NrRemessa: it?.NrRemessa ?? '',
                    DataRemessa: it?.DataRemessa ?? '',
                    OCPO: it?.OCPO ?? ''
                };
            }

            /* -------------------------
            Load scope
            ------------------------- */
            async function loadScope() {
                // ✅ Segurança: ninguém pode usar "all" (mesmo se alguém reintroduzir via DOM)
                let mode = _doc().querySelector('input[name="be2Scope"]:checked')?.value || 'paste';
                if (mode !== 'paste') {
                    mode = 'paste';
                    const rb = _doc().getElementById('be2ScopePaste');
                    if (rb) rb.checked = true;
                    toast((typeof window.t === "function" ? window.t("be2ScopeAllNotAllowed") : 'Escopo "Todos" não é permitido. Use apenas a lista colada.'), "warning");
                }

                be2.state.scope.mode = mode;

                let items = [];
                const cache = getAllItemsCache();
                if (!cache.length) {
                    toast((typeof window.t === "function" ? window.t("be2CacheNotReady") : "Cache de itens ainda não está disponível. Faça Sync/Carregamento do app primeiro."), "warning");
                    return;
                }

                // Apenas "paste"
                const keys = parsePasteToKeys(be2.els.be2PasteInput.value);
                if (!keys.length) {
                    toast((typeof window.t === "function" ? window.t("be2PasteAtLeastOne") : "Cole ao menos 1 Serial ou Asset Tag (IT Asset)."), "warning");
                    return;
                }

                const bySerial = new Map();
                const byIT = new Map();

                for (const it of cache) {
                    const serial = normKey(it?.Title);
                    const itasset = normKey(it?.ITAssetBunge);
                    if (serial) bySerial.set(serial, it);
                    if (itasset) byIT.set(itasset, it);
                }

                const notFound = [];
                for (const k of keys) {
                    const nk = normKey(k);
                    const hit = bySerial.get(nk) || byIT.get(nk);
                    if (hit) items.push(hit);
                    else notFound.push(k);
                }

                // dedupe por Id
                const seen = new Set();
                items = items.filter(it => {
                    const id = it?.Id;
                    if (!id || seen.has(id)) return false;
                    seen.add(id);
                    return true;
                });

                if (!items.length) {
                    toast((typeof window.t === "function" ? window.t("be2NoItemsForList") : "Nenhum item encontrado para a lista colada."), "danger");
                    return;
                }

                if (notFound.length) {
                    toast(`Não encontrados: ${notFound.length} (ver log).`, 'warning');
                    clearLog();
                    appendLog?.(`Não encontrados (${notFound.length}): ${notFound.join(', ')}`, 'warn');
                }

                // reset state
                be2.state.scope.items = items;
                be2.state.grid.rows = items.map(toGridRow);
                be2.state.grid.dirty.clear();
                be2.state.global.patches = {};
                be2.state.preview = null;
                be2.state.results = { ok: 0, fail: 0, errors: [] };

                clearLog();
                renderGrid();
                setCounts();
                setStatus((typeof window.t === "function" ? window.t("be2StatusItemsLoaded", { n: items.length }) : ("Itens carregados: " + items.length + ".")));
                toast(`Carregado(s): ${items.length} item(ns).`, 'success');

                // AR section visibility (somente AR)
                _doc().getElementById('be2ArWrap')?.classList.toggle('d-none', !isARUser());
            }
            /* -------------------------
            Global patches (Set/Clear)
            - Clear limpa o input visualmente
            ------------------------- */
            function setGlobalPatch(fieldKey, value) {
                if (!be2.state.scope.items.length) {
                    toast((typeof window.t === "function" ? window.t("be2LoadItemsFirst") : "Carregue itens primeiro."), "warning");
                    return;
                }
                be2.state.global.patches[fieldKey] = value;
                be2.state.preview = null;
                setCounts();
                toast(`Global: ${fieldKey} preparado.`, 'info');
                appendLog(`GLOBAL SET ${fieldKey} = "${value ?? ''}"`);
            }

            function clearGlobalPatch(fieldKey) {
                if (!be2.state.scope.items.length) {
                    toast((typeof window.t === "function" ? window.t("be2LoadItemsFirst") : "Carregue itens primeiro."), "warning");
                    return;
                }
                be2.state.global.patches[fieldKey] = { __clear: true };

                // ✅ limpa o campo também
                const inp = _doc().getElementById('be2G_' + fieldKey);
                if (inp) inp.value = '';

                be2.state.preview = null;
                setCounts();
                toast(`Global: ${fieldKey} será limpo.`, 'info');
                appendLog(`GLOBAL CLEAR ${fieldKey}`);
            }

            /* -------------------------
            Grid render (datalist funciona pois usamos list="")
            + headers fortes com ícones
            ------------------------- */
            function renderGrid() {
                const thead = be2.els.be2GridThead;
                const tbody = be2.els.be2GridTbody;
                if (!thead || !tbody) return;

                const showAR = isARUser();

                const cols = [
                    { k: 'Title', t: 'Serial', ro: true, ico: 'bi-upc-scan' },
                    { k: 'ITAssetBunge', t: 'ITAsset', ro: true, ico: 'bi-tag' },
                    { k: 'Hostname', t: 'Hostname', ico: 'bi-pc-display' },
                    { k: 'Status', t: 'Status', list: 'status-list', ico: 'bi-flag' },
                    { k: 'Site', t: 'Site', list: 'site-list', ico: 'bi-geo-alt' },
                    { k: 'Company', t: 'Company', list: 'company-list', ico: 'bi-building' },
                    { k: 'Category', t: 'Category', list: 'category-list', ico: 'bi-grid-3x3-gap' },
                    { k: 'Vendor', t: 'Vendor', list: 'vendor-list', ico: 'bi-truck' },
                    { k: 'Model', t: 'Model', ico: 'bi-cpu' },
                    { k: 'Prateleira', t: 'Prateleira', list: 'prateleira-list', ico: 'bi-inboxes' },
                    { k: 'AssignedToEmail', t: 'AssignedTo (email)', ico: 'bi-person-badge' },
                    { k: 'Responsible', t: 'Responsible', ico: 'bi-person-check' },
                    { k: 'Comments', t: 'Comments', ico: 'bi-chat-left-text' }
                ];

                if (showAR) {
                    cols.push(
                        { k: 'NotaFiscal', t: 'NotaFiscal', ico: 'bi-receipt' },
                        { k: 'DataNota', t: 'DataNota', type: 'date', ico: 'bi-calendar3' },
                        { k: 'NrRemessa', t: 'NrRemessa', ico: 'bi-truck-flatbed' },
                        { k: 'DataRemessa', t: 'DataRemessa', type: 'date', ico: 'bi-calendar3' },
                        { k: 'OCPO', t: 'OCPO', ico: 'bi-file-earmark-text' }
                    );
                }

                thead.innerHTML = `
      <tr>
        <th class="be2-th" style="width:70px;"><i class="bi bi-hash me-1"></i>ID</th>
        ${cols.map(c => `<th class="be2-th"><i class="bi ${c.ico || 'bi-dot'} me-1"></i>${c.t}</th>`).join('')}
      </tr>
    `;

                const q = normKey(be2.state.grid.search);
                const rows = be2.state.grid.rows.filter(r => {
                    if (!q) return true;
                    return normKey(Object.values(r).join(' ')).includes(q);
                });

                tbody.innerHTML = rows.map(r => {
                    const cells = cols.map(c => {
                        const v = r[c.k] ?? '';
                        const dirtyKey = `${r.Id}:${c.k}`;
                        const isDirty = be2.state.grid.dirty.has(dirtyKey);
                        const ro = !!c.ro;
                        const listAttr = c.list ? ` list="${c.list}"` : '';
                        const typeAttr = c.type ? ` type="${c.type}"` : ' type="text"';

                        return `
          <td>
            <input class="form-control form-control-sm be2-cell ${isDirty ? 'be2-dirty' : ''}"
              autocomplete="off" spellcheck="false"
              data-rowid="${r.Id}" data-col="${c.k}" ${typeAttr} ${listAttr}
              ${ro ? 'readonly' : ''}
              value="${escapeHtmlAttr(String(v))}">
          </td>
        `;
                    }).join('');

                    return `<tr data-rowid="${r.Id}">
        <td class="small text-muted">${r.Id}</td>
        ${cells}
      </tr>`;
                }).join('');

                tbody.querySelectorAll('input.be2-cell:not([readonly])').forEach(inp => {
                    inp.addEventListener('input', onGridInput, { passive: true });
                    inp.addEventListener('blur', onGridBlur);
                });
            }

            function onGridInput(e) {
                const el = e.target;
                const rowId = Number(el.getAttribute('data-rowid'));
                const col = el.getAttribute('data-col');
                const val = el.value;

                const row = be2.state.grid.rows.find(r => r.Id === rowId);
                if (!row) return;

                row[col] = val;

                const dirtyKey = `${rowId}:${col}`;
                be2.state.grid.dirty.set(dirtyKey, true);
                el.classList.add('be2-dirty');

                be2.state.preview = null;
                setCounts();
            }

            function onGridBlur(e) {
                const el = e.target;
                const col = el.getAttribute('data-col');
                const val = norm(el.value);

                if (col === 'AssignedToEmail' && val && !isEmail(val)) {
                    toast((typeof window.t === "function" ? window.t("be2AssignedToInvalidEmail") : "AssignedTo: e-mail inválido."), "warning");
                    el.classList.add('is-warning');
                    setTimeout(() => el.classList.remove('is-warning'), 1200);
                }
            }

            /* -------------------------
            Preview (diff) + modal
            ------------------------- */
            function applyGlobalOnRow(row, patches) {
                for (const [k, v] of Object.entries(patches)) {
                    if (v && v.__clear) row[k] = '';
                    else row[k] = (v ?? '');
                }
                return row;
            }

            function diffRow(before, after) {
                const keys = [
                    'Hostname', 'Status', 'Site', 'Company', 'Category', 'Vendor', 'Model', 'Prateleira',
                    'Comments', 'Responsible', 'AssignedToEmail',
                    'NotaFiscal', 'DataNota', 'NrRemessa', 'DataRemessa', 'OCPO'
                ];

                const out = [];
                for (const k of keys) {
                    const b = norm(before[k]);
                    const a = norm(after[k]);
                    if (b !== a) out.push({ field: k, from: b, to: a });
                }
                return out;
            }

            function buildPreview() {
                if (!be2.state.scope.items.length) {
                    toast((typeof window.t === "function" ? window.t("be2LoadItemsFirst") : "Carregue itens primeiro."), "warning");
                    return null;
                }

                const globalP = be2.state.global.patches || {};
                const hasGlobal = Object.keys(globalP).length > 0;

                const diffs = [];
                if (hasGlobal) {
                    for (const it of be2.state.scope.items) {
                        const before = toGridRow(it);
                        const after = applyGlobalOnRow({ ...before }, globalP);
                        const ch = diffRow(before, after);
                        if (ch.length) diffs.push({ Id: before.Id, Serial: before.Title, changes: ch });
                    }
                } else {
                    const baseById = new Map(be2.state.scope.items.map(it => [it.Id, toGridRow(it)]));
                    for (const r of be2.state.grid.rows) {
                        const before = baseById.get(r.Id);
                        if (!before) continue;
                        const ch = diffRow(before, r);
                        if (ch.length) diffs.push({ Id: r.Id, Serial: r.Title, changes: ch });
                    }
                }

                be2.state.preview = { diffs, hasGlobal };
                be2.els.be2SumChanged.textContent = String(diffs.length);
                setCounts();

                if (!diffs.length) {
                    toast((typeof window.t === "function" ? window.t("be2NoChanges") : "Nenhuma mudança detectada."), "warning");
                    return be2.state.preview;
                }

                toast(`Prévia pronta: ${diffs.length} item(ns) com mudanças.`, 'success');
                appendLog(`PREVIEW: ${diffs.length} itens com mudanças.`);
                return be2.state.preview;
            }

            function openPreviewModal(preview) {
                const flat = [];
                for (const d of preview.diffs) {
                    for (const c of d.changes) {
                        flat.push({ Id: d.Id, Serial: d.Serial, Field: c.field, From: c.from, To: c.to });
                    }
                }

                const tbody = _doc().getElementById('be2PrevTbody');
                const count = _doc().getElementById('be2PrevCount');
                const search = _doc().getElementById('be2PrevSearch');

                if (!tbody || !count || !search) {
                    toast((typeof window.t === "function" ? window.t("be2PreviewModalMissing") : "Modal de pré-visualização não encontrado no HTML."), "warning");
                    return;
                }

                count.textContent = `${flat.length} mudanças`;
                tbody.innerHTML = flat.map(x => `
      <tr>
        <td class="small text-muted">${x.Id}</td>
        <td><b>${escapeHtmlAttr(String(x.Serial || ''))}</b></td>
        <td><span class="badge text-bg-secondary">${escapeHtmlAttr(String(x.Field))}</span></td>
        <td class="text-muted">${escapeHtmlAttr(String(x.From))}</td>
        <td><b>${escapeHtmlAttr(String(x.To))}</b></td>
      </tr>
    `).join('');

                search.value = '';
                search.oninput = () => {
                    const q = (search.value || '').toLowerCase().trim();
                    tbody.querySelectorAll('tr').forEach(r => {
                        r.style.display = r.innerText.toLowerCase().includes(q) ? '' : 'none';
                    });
                };

                bootstrap.Modal.getOrCreateInstance(_doc().getElementById('be2PreviewModal')).show();
            }

            /* -------------------------
            Apply (MERGE chunk + retry)
            - Site lookup salva via SiteId
            - AssignedTo salva via AssignedToId
            ------------------------- */
            async function withRetry(fn) {
                const { tries, baseDelayMs } = be2.cfg.retry;
                let lastErr;
                for (let i = 0; i < tries; i++) {
                    try { return await fn(); }
                    catch (err) {
                        lastErr = err;
                        const wait = baseDelayMs * Math.pow(2, i);
                        await new Promise(r => setTimeout(r, wait));
                    }
                }
                throw lastErr;
            }

            async function buildSharePointPatch(afterRow, beforeRow) {
                const fm = be2.cfg.fieldMap;
                const patch = {};

                function normLocal(v) { return String(v ?? "").trim(); }

                function setIfChanged(fieldKey, spFieldName, choiceField) {
                    const bRaw = beforeRow[fieldKey];
                    const aRaw = afterRow[fieldKey];

                    const b = choiceField ? canonChoice(choiceField, bRaw) : normLocal(bRaw);
                    const a = choiceField ? canonChoice(choiceField, aRaw) : normLocal(aRaw);

                    if (b === a) return;
                    patch[spFieldName] = a ? a : null;
                }

                // helper local (não depende de canon())
                function canonChoice(field, value) {
                    const v = (value ?? '').toString().trim();
                    if (!v) return '';
                    try {
                        if (typeof window.canonicalChoice === 'function') {
                            return (window.canonicalChoice(field, v) ?? '').toString().trim();
                        }
                    } catch (_) { }
                    return v;
                }

                // Simple fields:
                setIfChanged('Hostname', fm.Hostname);             // (você remove depois no apply, se quiser)
                setIfChanged('Status', fm.Status, 'Status');
                setIfChanged('Company', fm.Company);
                setIfChanged('Category', fm.Category);
                setIfChanged('Vendor', fm.Vendor);
                setIfChanged('Model', fm.Model);
                setIfChanged('Prateleira', fm.Prateleira);
                setIfChanged('Comments', fm.Comments);

                // AR:
                setIfChanged('NotaFiscal', fm.NotaFiscal);
                setIfChanged('DataNota', fm.DataNota);
                setIfChanged('NrRemessa', fm.NrRemessa);
                setIfChanged('DataRemessa', fm.DataRemessa);
                setIfChanged('OCPO', fm.OCPO);

                // =========================
                // Site (lookup) -> SiteId
                // =========================
                const bSite = normLocal(beforeRow.Site);
                const aSite = normLocal(afterRow.Site);

                const lookupInternal = be2.cfg.siteLookup.internalName; // "Site"
                const lookupIdField = `${lookupInternal}Id`;            // "SiteId"

                if (bSite !== aSite) {
                    // ✅ garante mapa antes de resolver (evita "Falha ao carregar sites")
                    await ensureSiteMap(false);

                    if (!aSite) {
                        patch[lookupIdField] = null;
                    } else {
                        const siteId = await resolveSiteId(aSite);
                        if (!siteId) throw new Error(`Site inválido (não encontrado): ${aSite}`);
                        patch[lookupIdField] = siteId;
                    }
                }

                // =========================
                // AssignedTo (Person/Group) -> AssignedToId
                // =========================
                const bEmail = normLocal(beforeRow.AssignedToEmail);
                const aEmail = normLocal(afterRow.AssignedToEmail);

                if (bEmail !== aEmail) {
                    const internal = fm.AssignedTo; // "AssignedTo"
                    const idField = `${internal}Id`;

                    if (!aEmail) {
                        patch[idField] = null;
                    } else {
                        if (!isEmail(aEmail)) throw new Error('AssignedTo: e-mail inválido no patch.');
                        const u = await ensureUserByEmail(aEmail);
                        const userId = u && (u.Id || u.ID) ? Number(u.Id || u.ID) : null;
                        if (!userId) throw new Error(`AssignedTo: usuário não encontrado: ${aEmail}`);
                        patch[idField] = userId;
                    }
                }

                return patch;
            }

            // BulkEdit Helpers

            async function be2FixPatch(patch, beforeRow, afterRow) {
                const out = Object.assign({}, patch || {});

                // 1) Hostname nunca pode vir do usuário
                delete out.Hostname;
                delete out.hostname;
                delete out.HostName;

                // 2) Responsible (Person) via e-mail -> ResponsibleId
                // (aceita vários nomes pra cobrir seu builder)
                const respEmail =
                    (typeof out.ResponsibleEmail === "string" && out.ResponsibleEmail.trim()) ? out.ResponsibleEmail.trim() :
                        (typeof out.Responsible === "string" && out.Responsible.trim()) ? out.Responsible.trim() :
                            "";

                if (respEmail) {
                    const emailRx = /^[^\s@]+@[^\s@]+\.[^\s@]+$/i;
                    if (!emailRx.test(respEmail)) {
                        throw new Error(`Responsible inválido (precisa ser e-mail): "${respEmail}"`);
                    }
                    const id = await be2ResolveUserIdByEmail(respEmail);
                    if (!id) throw new Error(`Não foi possível resolver Responsible: "${respEmail}"`);

                    delete out.ResponsibleEmail;
                    delete out.Responsible;
                    out.ResponsibleId = id;
                }

                // 3) AUTO Hostname quando Site mudou (regra serial+site)
                // Detecta o "site final" (novo) e serial/category finais
                const newSite = (out.Site || out.SiteTitle || (afterRow && afterRow.Site) || "").toString().trim();
                const newCat = (out.Category || (afterRow && afterRow.Category) || (beforeRow && beforeRow.Category) || "").toString().trim();
                const serial = ((afterRow && (afterRow.Title || afterRow.Serial)) || (beforeRow && (beforeRow.Title || beforeRow.Serial)) || "").toString().trim();

                // Só gera se o usuário realmente alterou o site (ou se out tem SiteId/Site)
                const oldSite = (beforeRow && beforeRow.Site) ? String(beforeRow.Site).trim() : "";
                const siteChanged = (!!newSite && newSite.toLowerCase() !== oldSite.toLowerCase()) || ("Site" in out) || ("SiteId" in out);

                if (siteChanged) {
                    const hn = be2ComputeHostnameByRule(newCat, newSite, serial);
                    if (hn) {
                        out.Hostname = hn; // ✅ sistema define
                    }
                }

                return out;
            }

            function be2ComputeHostnameByRule(category, siteTitle, serial) {
                const cat = String(category || "").trim().toLowerCase();
                const site = String(siteTitle || "").trim();
                const sn = String(serial || "").trim();

                // mesma regra do seu updateHostname()
                if (cat !== "desktop" && cat !== "notebook") return "";

                if (!site || !sn) return "";

                // siteMapping precisa existir no escopo global
                try {
                    const siteData = (window.siteMapping || siteMapping || {})[site.toLowerCase()];
                    if (siteData && siteData.code) {
                        return String(siteData.code).trim() + "-" + sn;
                    }
                } catch (_) { }

                return "";
            }


            async function be2ResolveUserIdByEmail(email) {
                const em = String(email || "").trim();
                if (!em) return null;

                window.__be2UserIdCache = window.__be2UserIdCache || {};
                if (window.__be2UserIdCache[em]) return window.__be2UserIdCache[em];

                const u = await ensureUserByKeyOrEmail(em);
                const id = u && (u.Id || u.ID) ? Number(u.Id || u.ID) : null;

                if (id) window.__be2UserIdCache[em] = id;
                return id;
            }

            function be2EnsureConfirmApplyButton() {
                const modal = _doc().getElementById("be2PreviewModal");
                if (!modal) return;

                const footer = modal.querySelector(".modal-footer");
                if (!footer) return;

                // evita duplicar
                if (_doc().getElementById("be2BtnConfirmApply")) return;

                const btn = _doc().createElement("button");
                btn.type = "button";
                btn.id = "be2BtnConfirmApply";
                btn.className = "btn btn-success";
                btn.innerHTML = '<i class="bi bi-check2-circle me-1"></i>Confirmar aplicação';
                btn.title = "Aplicar as alterações no SharePoint";

                footer.appendChild(btn);

                btn.addEventListener("click", async function () {
                    try {
                        // ✅ chama SEMPRE a função global exportada
                        if (typeof window.be2ApplyChanges === "function") {
                            await window.be2ApplyChanges(true);
                            return;
                        }

                        // fallback (se por algum motivo não exportou)
                        if (typeof applyChanges === "function") {
                            await applyChanges(true);
                            return;
                        }

                        toast((typeof window.t === "function" ? window.t("be2ApplyFnMissing") : "Função de aplicação não encontrada (be2ApplyChanges)."), "danger");
                        console.error("be2ApplyChanges/applyChanges não encontrados.");
                    } catch (e) {
                        console.error("Confirmar aplicação:", e);
                        toast((typeof window.t === "function" ? window.t("be2ApplyFail") : "Falha ao aplicar alterações. Veja o console."), "danger");
                    }
                });
            }

            function be2LockHostname() {
                const input = _doc().getElementById("be2G_Hostname");
                if (input) {
                    input.value = "";
                    input.setAttribute("disabled", "disabled");
                    input.setAttribute("readonly", "readonly");
                    input.placeholder = (typeof window.t === "function" ? window.t("be2HostnameLockedPlaceholder") : "Bloqueado (Hostname é automático: Site + Serial)");
                    input.classList.add("opacity-75");
                }

                // botões Set/Clear do Hostname (se existirem no builder)
                _doc().querySelectorAll('[data-be2-set="Hostname"], [data-be2-clear="Hostname"]').forEach(btn => {
                    btn.setAttribute("disabled", "disabled");
                    btn.classList.add("disabled");
                    btn.title = (typeof window.t === "function" ? window.t("be2HostnameLockedTitle") : "Hostname é automático (Site + Serial). Não é permitido alterar manualmente.");
                });
            }


            async function be2GuardSitesBeforeApply() {
                const btnApply = _doc().getElementById("be2BtnApply");
                if (btnApply) btnApply.disabled = true;

                try {
                    await ensureSiteMap(false);
                    if (btnApply) btnApply.disabled = false;
                } catch (e) {
                    if (btnApply) btnApply.disabled = true;
                    toast((typeof window.t === "function" ? window.t("be2SitesLoading") : "Ainda carregando BSA Sites… tente novamente em instantes."), "warning");
                }
            }

            // Fim helpers BulkEdit

            async function applyChanges(confirmado) {
                // ✅ Exporta o wrapper imediatamente (para o botão Confirmar sempre achar)
                try { window.be2ApplyChanges = applyChanges; } catch (e) { }

                // garante hostname travado
                try { be2LockHostname(); } catch (_) { }

                const prev = be2.state.preview || buildPreview();
                if (!prev || !prev.diffs.length) {
                    toast((typeof window.t === "function" ? window.t("be2NothingToApply") : "Nada para aplicar."), "warning");
                    return;
                }

                // 1º clique em Aplicar => abre Preview
                if (confirmado !== true) {
                    try {
                        be2EnsureConfirmApplyButton();
                        openPreviewModal(prev);
                        toast((typeof window.t === "function" ? window.t("be2ReviewPreview") : "Revise a prévia e clique em 'Confirmar aplicação'."), "info");
                    } catch (e) {
                        console.error("applyChanges(wrapper):", e);
                        toast((typeof window.t === "function" ? window.t("be2OpenPreviewFail") : "Falha ao abrir a prévia."), "danger");
                    }
                    return;
                }

                // Confirmado => aplica
                if (typeof applyChangesCore !== "function") {
                    toast((typeof window.t === "function" ? window.t("be2ApplyCoreMissing") : "applyChangesCore() não encontrado. Verifique se a função existe."), "danger");
                    return;
                }

                await applyChangesCore();
            }

            async function applyChangesCore() {
                const prev = be2.state.preview || buildPreview();
                if (!prev || !prev.diffs.length) {
                    toast((typeof window.t === "function" ? window.t("be2NothingToApply") : "Nada para aplicar."), "warning");
                    return;
                }

                // =========================
                // ✅ Validação antes de aplicar
                // =========================
                const emailRx = /^[^\s@]+@[^\s@]+\.[^\s@]+$/i;

                function datalistHasValue(listId, value) {
                    const raw = String(value || '').trim();
                    if (!raw) return true; // vazio = ok
                    const dl = _doc().getElementById(listId);
                    if (!dl) return true; // sem datalist = não bloqueia
                    const opts = Array.from(dl.querySelectorAll('option')).map(o => String(o.value || '').trim()).filter(Boolean);
                    const low = raw.toLowerCase();
                    if (opts.some(o => o.toLowerCase() === low)) return true;
                    const map = { 'status-list': 'Status', 'category-list': 'Category', 'vendor-list': 'Vendor' };
                    const fieldName = map[listId];
                    if (fieldName && typeof canonicalChoice === 'function') {
                        try {
                            const rawCan = String(canonicalChoice(fieldName, raw) || raw).trim().toLowerCase();
                            for (const o of opts) {
                                const oCan = String(canonicalChoice(fieldName, o) || o).trim().toLowerCase();
                                if (oCan === rawCan) return true;
                            }
                        } catch (e) { }
                    }
                    return false;
                }

                function isValidIsoDate(v) {
                    let s = String(v || '').trim();
                    if (!s) return true;
                    if (s.includes('T')) s = s.slice(0, 10);
                    if (!/^\d{4}-\d{2}-\d{2}$/.test(s)) return false;
                    const d = new Date(s + 'T00:00:00');
                    return !isNaN(d.getTime());
                }

                const baseById = new Map(be2.state.scope.items.map(it => [it.Id, it]));
                const validationErrors = [];


                try {
                    await ensureSiteMap(false);
                } catch (e) {
                    setBusy(false);
                    toast(String(e?.message || e), "danger");
                    setStatus((typeof window.t === "function" ? window.t("be2StatusSitesNotReady") : "Falha: BSA Sites ainda não carregou."));
                    switchTab("results");
                    return;
                }


                for (const d of prev.diffs) {
                    const it = baseById.get(d.Id);
                    if (!it) continue;

                    const beforeRow = toGridRow(it);
                    const afterRow = prev.hasGlobal
                        ? applyGlobalOnRow({ ...beforeRow }, be2.state.global.patches)
                        : be2.state.grid.rows.find(r => r.Id === d.Id);

                    if (!afterRow) continue;

                    // Choices / datalists
                    if (!datalistHasValue('status-list', afterRow.Status)) {
                        validationErrors.push(`#${d.Id} (${d.Serial}) -> Status inválido: "${afterRow.Status}"`);
                    }
                    if (!datalistHasValue('company-list', afterRow.Company)) {
                        validationErrors.push(`#${d.Id} (${d.Serial}) -> Company inválida: "${afterRow.Company}"`);
                    }
                    if (!datalistHasValue('category-list', afterRow.Category)) {
                        validationErrors.push(`#${d.Id} (${d.Serial}) -> Category inválida: "${afterRow.Category}"`);
                    }
                    if (!datalistHasValue('vendor-list', afterRow.Vendor)) {
                        validationErrors.push(`#${d.Id} (${d.Serial}) -> Vendor inválido: "${afterRow.Vendor}"`);
                    }
                    if (!datalistHasValue('prateleira-list', afterRow.Prateleira)) {
                        validationErrors.push(`#${d.Id} (${d.Serial}) -> Prateleira inválida: "${afterRow.Prateleira}"`);
                    }
                    if (!datalistHasValue('site-list', afterRow.Site)) {
                        validationErrors.push(`#${d.Id} (${d.Serial}) -> Site inválido: "${afterRow.Site}"`);
                    }

                    // Emails
                    if (afterRow.AssignedToEmail && !emailRx.test(String(afterRow.AssignedToEmail).trim())) {
                        validationErrors.push(`#${d.Id} (${d.Serial}) -> AssignedToEmail inválido: "${afterRow.AssignedToEmail}"`);
                    }

                    // Datas AR
                    if (!isValidIsoDate(afterRow.DataNota)) {
                        validationErrors.push(`#${d.Id} (${d.Serial}) -> DataNota inválida: "${afterRow.DataNota}" (use YYYY-MM-DD)`);
                    }
                    if (!isValidIsoDate(afterRow.DataRemessa)) {
                        validationErrors.push(`#${d.Id} (${d.Serial}) -> DataRemessa inválida: "${afterRow.DataRemessa}" (use YYYY-MM-DD)`);
                    }
                }

                if (validationErrors.length) {
                    clearLog();
                    validationErrors.slice(0, 200).forEach(msg => appendLog(`VALIDATION -> ${msg}`, 'warn'));
                    toast(`Validação falhou (${validationErrors.length}). Corrija antes de aplicar.`, 'danger');
                    setStatus((typeof window.t === "function" ? window.t("be2StatusValidationFailed", { n: validationErrors.length }) : ("Validação falhou: " + validationErrors.length + " erro(s).")));
                    switchTab('results');
                    return;
                }

                // =========================
                // ✅ Aplicar
                // =========================
                setBusy(true);
                setStatus((typeof window.t === "function" ? window.t("be2StatusApplying") : "Aplicando alterações..."));
                clearLog();
                be2.state.results = { ok: 0, fail: 0, errors: [] };

                const baseById2 = new Map(be2.state.scope.items.map(it => [it.Id, it]));


                // ✅ Garante que BSA Sites está pronto ANTES de gerar patch (SiteId)
                try {
                    await ensureSiteMap(false);
                } catch (e) {
                    setBusy(false);
                    toast(String(e?.message || e), "danger");
                    setStatus((typeof window.t === "function" ? window.t("be2StatusSitesFail") : "Falha: não foi possível carregar BSA Sites."));
                    switchTab("results");
                    return;
                }


                const patches = [];
                for (const d of prev.diffs) {
                    const it = baseById2.get(d.Id);
                    if (!it) continue;

                    const beforeRow = toGridRow(it);
                    const afterRow = prev.hasGlobal
                        ? applyGlobalOnRow({ ...beforeRow }, be2.state.global.patches)
                        : be2.state.grid.rows.find(r => r.Id === d.Id);

                    // patch “cru” do seu builder
                    let patch = await buildSharePointPatch(afterRow, beforeRow);

                    // =========================
                    // 🔒 Nunca permitir Hostname manual
                    // =========================
                    delete patch.Hostname;
                    delete patch.hostname;
                    delete patch.HostName;


                    // =========================
                    // ✅ AssignedToEmail (se existir no patch) => AssignedToId
                    // (blindagem extra; mesmo se buildSharePointPatch já tratar, isso não atrapalha)
                    // =========================
                    if (patch.AssignedToEmail && typeof patch.AssignedToEmail === "string" && patch.AssignedToEmail.trim()) {
                        const em = patch.AssignedToEmail.trim();
                        const userId = await be2ResolveUserIdByEmail(em);
                        if (!userId) throw new Error(`AssignedTo não encontrado: ${em}`);
                        delete patch.AssignedToEmail;
                        patch.AssignedToId = userId;
                    }

                    // =========================
                    // ✅ Hostname automático (mesma regra do seu updateHostname)
                    // - gera quando precisa (Site/Serial/Categoria)
                    // - só envia se mudou (ou se precisa limpar)
                    // =========================
                    const finalCategory = String(afterRow?.Category || beforeRow?.Category || "").trim();
                    const finalSite = String(afterRow?.Site || beforeRow?.Site || "").trim();
                    const finalSerial = String(beforeRow?.Title || d.Serial || "").trim(); // Serial = Title na sua lista

                    const desiredHostname = be2ComputeHostnameByRule(finalCategory, finalSite, finalSerial);
                    const oldHostname = String(beforeRow?.Hostname || "").trim();

                    // Só patcha hostname se necessário:
                    // - se quiser preencher e mudou
                    // - ou se precisa limpar e antes tinha
                    if (desiredHostname && desiredHostname !== oldHostname) {
                        patch.Hostname = desiredHostname;
                    } else if (!desiredHostname && oldHostname) {
                        patch.Hostname = ""; // limpa quando categoria não é desktop/notebook ou sem mapping
                    }

                    patches.push({ id: d.Id, serial: d.Serial, patch });
                }

                let done = 0;
                const total = patches.length;
                be2.els.be2ProgressWrap.classList.remove('d-none');
                be2.els.be2ProgressBar.style.width = `0%`;

                for (let i = 0; i < patches.length; i += be2.cfg.chunkSize) {
                    const chunk = patches.slice(i, i + be2.cfg.chunkSize);

                    await Promise.all(chunk.map(async (p) => {
                        try {
                            await withRetry(() => spMergeItem(p.id, p.patch));
                            be2.state.results.ok++;
                            appendLog(`OK   #${p.id} (${p.serial})`);
                        } catch (err) {
                            be2.state.results.fail++;
                            be2.state.results.errors.push({ Id: p.id, Serial: p.serial, Error: String(err?.message || err) });
                            appendLog(`FAIL #${p.id} (${p.serial}) -> ${String(err?.message || err)}`);
                        } finally {
                            done++;
                            const pct = Math.round((done / total) * 100);
                            be2.els.be2ProgressBar.style.width = `${pct}%`;
                        }
                    }));
                }

                setBusy(false);

                be2.els.be2SumOk.textContent = String(be2.state.results.ok);
                be2.els.be2SumFail.textContent = String(be2.state.results.fail);

                if (be2.state.results.fail) {
                    be2.els.be2CountErrors.classList.remove('d-none');
                    be2.els.be2CountErrors.textContent = (typeof window.t === "function" ? window.t("be2CountErrorsLabel", { n: be2.state.results.fail }) : ("Erros: " + be2.state.results.fail));
                    be2.els.be2BtnDownloadErrors.disabled = false;
                    toast((typeof window.t === "function" ? window.t("be2DoneWithFailures", { n: be2.state.results.fail }) : ("Concluído com falhas: " + be2.state.results.fail + ".")), 'warning');
                    setStatus((typeof window.t === "function" ? window.t("be2StatusDone", { ok: be2.state.results.ok, fail: be2.state.results.fail }) : ("Concluído. OK: " + be2.state.results.ok + " | Falhas: " + be2.state.results.fail)));
                } else {
                    be2.els.be2CountErrors.classList.add('d-none');
                    toast((typeof window.t === "function" ? window.t("be2DoneOk") : "Concluído com sucesso!"), "success");
                    setStatus((typeof window.t === "function" ? window.t("be2StatusDone", { ok: be2.state.results.ok, fail: 0 }) : ("Concluído. OK: " + be2.state.results.ok + " | Falhas: 0")));
                }

                switchTab('results');

                // fecha o modal de preview (se estiver aberto)
                try {
                    const m = bootstrap.Modal.getInstance(_doc().getElementById("be2PreviewModal"));
                    m?.hide();
                } catch (_) { }
            }

            /* -------------------------
            CSV export (grade) + erros
            ------------------------- */
            function downloadText(text, filename, mime) {
                const blob = new Blob([text], { type: mime });
                const a = _doc().createElement('a');
                a.href = URL.createObjectURL(blob);
                a.download = filename;
                _doc().body.appendChild(a);
                a.click();
                setTimeout(() => { URL.revokeObjectURL(a.href); a.remove(); }, 0);
            }

            function exportGridCSV() {
                if (!be2.state.grid.rows.length) {
                    toast((typeof window.t === "function" ? window.t("be2NothingToExport") : "Nada para exportar."), "warning");
                    return;
                }
                const rows = be2.state.grid.rows;
                const cols = Object.keys(rows[0] || {});
                const csv = [
                    cols.join(';'),
                    ...rows.map(r => cols.map(c => `${String(r[c] ?? '').replace(/"/g, '""')}`).join(';'))
                ].join('\n');

                downloadText(csv, 'bulk-edit-v2-grid.csv', 'text/csv;charset=utf-8');
                toast((typeof window.t === "function" ? window.t("be2CsvExported") : "CSV exportado."), "success");
            }

            function downloadErrorsCSV() {
                const errs = be2.state.results.errors || [];
                if (!errs.length) {
                    toast((typeof window.t === "function" ? window.t("be2NoErrorsToDownload") : "Sem erros para baixar."), "info");
                    return;
                }
                const cols = ['Id', 'Serial', 'Error'];
                const csv = [
                    cols.join(';'),
                    ...errs.map(e => cols.map(c => `${String(e[c] ?? '').replace(/"/g, '""')}`).join(';'))
                ].join('\n');

                downloadText(csv, 'bulk-edit-v2-erros.csv', 'text/csv;charset=utf-8');
                toast((typeof window.t === "function" ? window.t("be2ErrorsCsvOk") : "CSV de erros gerado."), "success");
            }

            /* -------------------------
            Tabs
            ------------------------- */
            function switchTab(tab) {
                _doc().querySelectorAll('#be2Tabs .nav-link').forEach(b => {
                    b.classList.toggle('active', b.getAttribute('data-be2-tab') === tab);
                });

                be2.els.be2PaneGlobal.classList.toggle('d-none', tab !== 'global');
                be2.els.be2PaneGrid.classList.toggle('d-none', tab !== 'grid');
                be2.els.be2PaneResults.classList.toggle('d-none', tab !== 'results');
            }

            /* -------------------------
            Log
            ------------------------- */
            function appendLog(line) {
                const el = be2.els.be2Log;
                if (!el) return;
                const div = _doc().createElement('div');
                div.textContent = `[${new Date().toLocaleTimeString()}] ${line}`;
                el.appendChild(div);
                el.scrollTop = el.scrollHeight;
            }

            function clearLog() {
                if (be2.els.be2Log) be2.els.be2Log.innerHTML = '';
                if (be2.els.be2BtnDownloadErrors) be2.els.be2BtnDownloadErrors.disabled = true;

                if (be2.els.be2CountErrors) {
                    be2.els.be2CountErrors.classList.add('d-none');
                    be2.els.be2CountErrors.textContent = (typeof window.t === "function" ? window.t("be2CountErrorsLabel", { n: 0 }) : "Erros: 0");
                }
            }

            /* -------------------------
            Bind UI
            ------------------------- */
            function bind() {
                const ids = [
                    'be2PasteInput', 'be2BtnPasteClear', 'be2BtnPasteExample',
                    'be2BtnLoad', 'be2BtnPreview', 'be2BtnApply', 'be2BtnExportCSV',
                    'be2GridThead', 'be2GridTbody', 'be2GridSearch', 'be2GridClear',
                    'be2CountLoaded', 'be2CountChanged', 'be2CountErrors',
                    'be2ProgressWrap', 'be2ProgressBar', 'be2StatusBar',
                    'be2PaneGlobal', 'be2PaneGrid', 'be2PaneResults',
                    'be2Log', 'be2BtnDownloadErrors', 'be2BtnClearResults',
                    'be2SumLoaded', 'be2SumChanged', 'be2SumOk', 'be2SumFail',
                    'be2BtnHelp'
                ];
                ids.forEach(id => be2.els[id] = _doc().getElementById(id));

                // Ajuda/Regras -> abre o modal
                be2.els.be2BtnHelp?.addEventListener('click', () => {
                    const helpEl = _doc().getElementById('be2HelpModal');
                    if (!helpEl) {
                        toast((typeof window.t === "function" ? window.t("be2HelpModalMissing") : "Modal de ajuda (be2HelpModal) não encontrado no HTML."), "warning");
                        return;
                    }
                    bootstrap.Modal.getOrCreateInstance(helpEl).show();
                });

                // Scope change -> mantém compatível, mas o app deve usar somente "paste"
                _doc().querySelectorAll('input[name="be2Scope"]').forEach(r => {
                    r.addEventListener('change', () => {
                        const mode = _doc().querySelector('input[name="be2Scope"]:checked')?.value || 'paste';
                        _doc().getElementById('be2PasteBox')?.classList.toggle('d-none', mode !== 'paste');
                    });
                });

                // Clear/Example paste
                be2.els.be2BtnPasteClear?.addEventListener('click', () => {
                    be2.els.be2PasteInput.value = '';
                    toast((typeof window.t === "function" ? window.t("be2ListCleared") : "Lista limpa."), "info");
                });

                be2.els.be2BtnPasteExample?.addEventListener('click', () => {
                    be2.els.be2PasteInput.value = 'SN123456\n700000\nSN999999';
                    toast((typeof window.t === "function" ? window.t("be2ExampleFilled") : "Exemplo preenchido."), "info");
                });

                // Main actions
                be2.els.be2BtnLoad?.addEventListener('click', loadScope);

                be2.els.be2BtnPreview?.addEventListener('click', () => {
                    const p = buildPreview();
                    if (p && p.diffs?.length) openPreviewModal(p);
                    else toast((typeof window.t === "function" ? window.t("be2NoChangesPreview") : "Sem alterações para pré-visualizar."), "warning");
                });

                be2.els.be2BtnApply?.addEventListener('click', applyChanges);
                be2.els.be2BtnExportCSV?.addEventListener('click', exportGridCSV);
                be2.els.be2BtnDownloadErrors?.addEventListener('click', downloadErrorsCSV);

                be2.els.be2BtnClearResults?.addEventListener('click', () => {
                    be2.state.results = { ok: 0, fail: 0, errors: [] };
                    clearLog();
                    toast((typeof window.t === "function" ? window.t("be2LogCleared") : "Log limpo."), "info");
                });

                // Tabs click
                _doc().querySelectorAll('#be2Tabs .nav-link').forEach(btn => {
                    btn.addEventListener('click', () => switchTab(btn.getAttribute('data-be2-tab')));
                });

                // Grid filter
                be2.els.be2GridSearch?.addEventListener('input', (e) => {
                    be2.state.grid.search = e.target.value || '';
                    renderGrid();
                });

                be2.els.be2GridClear?.addEventListener('click', () => {
                    be2.state.grid.search = '';
                    be2.els.be2GridSearch.value = '';
                    renderGrid();
                });

                // Global set/clear
                _doc().querySelectorAll('[data-be2-set]').forEach(b => {
                    b.addEventListener('click', () => {
                        const field = b.getAttribute('data-be2-set');
                        const inputId = 'be2G_' + field;
                        const val = _doc().getElementById(inputId)?.value ?? '';
                        setGlobalPatch(field, val);
                    });
                });

                _doc().querySelectorAll('[data-be2-clear]').forEach(b => {
                    b.addEventListener('click', () => {
                        const field = b.getAttribute('data-be2-clear');
                        clearGlobalPatch(field);
                    });
                });

                setCounts();
                switchTab('global');
            }

            window.be2OnLanguageChanged = function () {
                try { be2LockHostname(); } catch (e) { }
                try {
                    if (be2.els && be2.els.be2CountLoaded) setCounts();
                } catch (e2) { }
            };

            /* -------------------------
            Public open
            ------------------------- */
            window.openBulkEditV2 = function () {
                try {
                    // seu app usa data-perm para controlar UI
                    if (typeof window.refreshPermissions === 'function') window.refreshPermissions();

                    const modalEl = _doc().getElementById('bulkEditV2Modal');
                    const m = bootstrap.Modal.getOrCreateInstance(modalEl);
                    m.show();

                    if (!be2._bound) {
                        bind();
                        be2._bound = true;
                    }

                    be2GuardSitesBeforeApply();
                    try { be2LockHostname(); } catch (e) { }
                    // ✅ Força paste como único escopo permitido
                    const rbPaste = _doc().getElementById('be2ScopePaste');
                    if (rbPaste) rbPaste.checked = true;
                    _doc().getElementById('be2PasteBox')?.classList.remove('d-none');

                    // ✅ AR (somente para AR)
                    _doc().getElementById('be2ArWrap')?.classList.toggle('d-none', !isARUser());

                    toast((typeof window.t === "function" ? window.t("be2BulkEditOpened") : "Bulk Edit V2 aberto."), "info");
                } catch (err) {
                    toast((typeof window.t === "function" ? window.t("be2OpenBulkEditFail", { msg: String(err?.message || err) }) : ("Erro ao abrir Bulk Edit V2: " + String(err?.message || err))), 'danger');
                }
            }

        })();

        /* =========================================================
        MASS ACTIONS DROPDOWN - BIND (SharePoint-proof)
        - Event delegation (não depende do DOM timing)
        - Toast only
        ========================================================= */
        (function () {
            function toast(msg, type = 'info') {
                if (typeof window.showToast === 'function') return window.showToast(msg, type);
                console.log(`[${type}] ${msg}`);
            }

            function safeOpenBulkV2() {
                if (typeof window.openBulkEditV2 === 'function') return window.openBulkEditV2();
                toast((typeof window.t === "function" ? window.t("be2BulkEditNotLoaded") : "Bulk Edit V2 ainda não carregou (função openBulkEditV2 não existe)."), "warning");
            }

            function safeOpenBulkRegister() {
                if (typeof window.openBulkModal === 'function') return window.openBulkModal(); // seu registro em massa 
                toast((typeof window.t === "function" ? window.t("be2BulkRegisterNotLoaded") : "Registro em massa ainda não carregou (função openBulkModal não existe)."), "warning");
            }

            // Delegação: pega clique mesmo se SharePoint recriar o DOM (sem onclick no HTML)
            _doc().addEventListener('click', function (ev) {
                const aV2 = ev.target.closest('#btnOpenBulkEditV2');
                if (aV2) {
                    ev.preventDefault();
                    safeOpenBulkV2();
                    return;
                }

                const aReg = ev.target.closest('#btnOpenBulkRegister');
                if (aReg) {
                    ev.preventDefault();
                    safeOpenBulkRegister();
                    return;
                }

                // data-action: substitui todos os onclick (CSP / iframe)
                const el = ev.target.closest('[data-action]');
                if (!el) return;
                const action = el.getAttribute('data-action');
                const value = el.getAttribute('data-value');
                const extra = el.getAttribute('data-extra');
                const method = el.getAttribute('data-method');
                const arg = el.getAttribute('data-arg');
                const inputId = el.getAttribute('data-input-id');
                ev.preventDefault();
                ev.stopPropagation();

                if (action === 'scSupplies' && method) {
                    try {
                        if (typeof window.scSupplies !== 'object' || !window.scSupplies[method]) return;
                        if (arg !== null && arg !== undefined) window.scSupplies[method](arg);
                        else window.scSupplies[method]();
                    } catch (e) { }
                    return;
                }

                var fn = window[action];
                if (typeof fn !== 'function') return;
                if (action === 'filterByCard' && value != null) { fn(value); return; }
                if (action === 'showAdminPanel' && value != null) { fn(value); return; }
                if (action === 'openBarcodeScanner' && (inputId || value)) { fn(inputId || value); return; }
                if (action === 'editPageFromAdmin') { fn(); if (typeof window.toggleLoadingOverlay === 'function') window.toggleLoadingOverlay(); return; }
                if (action === 'carouselPrev' || action === 'carouselNext') ev.stopPropagation();
                fn();
            });

            // Dica: opcional — garante que dropdown fecha após click
            _doc().addEventListener('click', function (ev) {
                const item = ev.target.closest('.dropdown-menu .dropdown-item');
                if (!item) return;
                const dd = ev.target.closest('.dropdown');
                if (!dd) return;
                const btn = dd.querySelector('[data-bs-toggle="dropdown"]');
                if (!btn) return;
                try { bootstrap.Dropdown.getOrCreateInstance(btn).hide(); } catch (e) { }
            });

        })();

