/* =========================================================
        BE2 PATCH v2 (Produção) — Auto-set robusto (input/change)
        ========================================================= */
        (function () {
            function be2NormDate(v) {
                if (v == null) return '';
                var s = String(v).trim();
                if (!s) return '';
                if (s.indexOf('T') >= 0) return s.slice(0, 10);
                return s.length >= 10 ? s.slice(0, 10) : s;
            }
            function be2NormStatus(v) {
                if (v == null) return '';
                var s = String(v).trim();
                if (!s) return '';
                try { if (typeof canonicalChoice === 'function') { return canonicalChoice('Status', s) || s; } } catch (e) { }
                return s;
            }

            function be2BindAutoSet() {
                var lastApplied = {}; // campo -> valor
                var pane = _doc().getElementById('be2PaneGlobal');
                if (!pane) return;
                if (pane.dataset.autosetBound === '2') return;
                pane.dataset.autosetBound = '2';
                function enabled() { var sw = _doc().getElementById('be2AutoSet'); return sw ? !!sw.checked : true; }
                var map = { be2G_Status: 'Status', be2G_Site: 'Site', be2G_Company: 'Company', be2G_Category: 'Category', be2G_Vendor: 'Vendor', be2G_Model: 'Model', be2G_Prateleira: 'Prateleira', be2G_Hostname: 'Hostname', be2G_Comments: 'Comments', be2G_AssignedToEmail: 'AssignedToEmail', be2G_Responsible: 'Responsible', be2G_NotaFiscal: 'NotaFiscal', be2G_DataNota: 'DataNota', be2G_NrRemessa: 'NrRemessa', be2G_DataRemessa: 'DataRemessa', be2G_OCPO: 'OCPO' };
                var t; function schedule(fn) { clearTimeout(t); t = setTimeout(fn, 600); }
                function handle(ev) {
                    var el = ev.target; if (!el || !el.id) return; var field = map[el.id]; if (!field) return; if (!enabled()) return;
                    if (field === 'DataNota' || field === 'DataRemessa') el.value = be2NormDate(el.value);
                    if (field === 'Status') el.value = be2NormStatus(el.value);
                    schedule(function () {
                        var v = (el.value || '').trim();
                        var key = field;

                        // Se não mudou desde a última aplicação, não faz nada (evita spam)
                        if ((lastApplied[key] || '') === v) return;

                        lastApplied[key] = v;

                        if (!v) {
                            var bc = pane.querySelector('button[data-be2-clear=\"' + field + '\"]');
                            if (bc) bc.click();
                            return;
                        }

                        var bs = pane.querySelector('button[data-be2-set=\"' + field + '\"]');
                        if (bs) bs.click();
                    });
                }
                pane.addEventListener('change', handle, true);

                pane.addEventListener('input', function (ev) {
                    // Bloqueia auto-set em digitação contínua de campos “texto livre”
                    const el = ev.target;
                    if (!el || !el.id) return;

                    // Campos onde NÃO queremos auto-set a cada tecla
                    const blockOnInput = new Set([
                        'be2G_Comments',
                        'be2G_Hostname',
                        'be2G_Model',
                        'be2G_NotaFiscal',
                        'be2G_NrRemessa',
                        'be2G_OCPO'
                    ]);

                    if (blockOnInput.has(el.id)) return; // ⛔ não chama handle no input
                    handle(ev); // ✅ para os demais, segue normal
                }, true);
            }
            function init() {
                var modal = _doc().getElementById('bulkEditV2Modal');
                if (!modal) return;
                modal.addEventListener('shown.bs.modal', function () { try { be2BindAutoSet(); } catch (e) { } });
                if (modal.classList.contains('show')) setTimeout(function () { try { be2BindAutoSet(); } catch (e) { } }, 60);
            }
            if (_doc().readyState === 'loading') _doc().addEventListener('DOMContentLoaded', init);
            else init();
        })();

        function scSetLatestHeaderTitle(text, bg, fg) {
            const header = _doc().getElementById("latestItemsHeader");
            if (!header) return;

            // garante que o layout do header existe
            let titleEl = _doc().getElementById("latestItemsTitle");
            if (!titleEl) {
                // se alguém já destruiu o header, reconstruímos via resetLatestItemsHeader (se existir)
                try { if (typeof resetLatestItemsHeader === "function") resetLatestItemsHeader(); } catch (e) { }
                titleEl = _doc().getElementById("latestItemsTitle") || header.querySelector("span");
            }
            if (!titleEl) return;

            titleEl.textContent = text || "";

            // cores opcionais
            header.style.backgroundColor = (bg != null ? bg : "");
            header.style.color = (fg != null ? fg : "");
        }

        function scEnsureHeaderButtons() {
            if (!_doc().getElementById("btnShowHide") || !_doc().getElementById("btnResetCols")) {
                try { resetLatestItemsHeader?.(); } catch (e) { }
            }
            try { if (typeof scUpdateSuppliesTabVisibility === "function") scUpdateSuppliesTabVisibility(); } catch (eSup) { }
        }

